    public int lengthOfLongestSubstring(String s) {
        int[] freq = new int[128];
        int left = 0, max = 0;
        for (int right = 0; right < s.length(); right++) {
            freq[s.charAt(right)]++;
            while (freq[s.charAt(right)] > 1)
