package com.cheehwatang.leetcode;

import java.util.ArrayList;
import java.util.List;

// Time Complexity  : O(n),
// where 'n' is the length of 'nums'.
// We traverse the 'nums' array twice, once to swap the numbers to the corresponding positions,
// and once to find numbers that are missing.
//
// Space Complexity : O(n),
// where 'n' is the length of 'nums'.
// The result list has length of 'n'.

public class FindAllNumbersDisappearedInAnArray {

    // Approach:
    // For each number in 'nums', we place the number back to the correct position in 'nums'.
    // For example, in nums = [_4_,3,2,7,8,2,3,1], the first element is 4, and the correct position is index 3 (i - 1).
    // So, we swap nums[0] with nums[3], making nums = [_7_,3,2,_4_,8,2,3,1].
    // We continue to swap until either the number is in the correct position, or the number is a duplicate.
    //
    // Once all the possible numbers are in their respective positions in 'nums',
    // we traverse 'nums' once more to check any numbers that are not in the correct position.
    // If the number is not in the correct position, the actual number in the position is missing.

    public List<Integer> findDisappearedNumbers(int[] nums) {
        // Traverse the 'nums' array,
        for (int i = 0; i < nums.length; i++) {
            // and continue to swap the numbers until either the number is in the correct position,
            // or the number is a duplicate.
            while (nums[i] != nums[nums[i] - 1]) {
                int temp = nums[nums[i] - 1];
                nums[nums[i] - 1] = nums[i];
                nums[i] = temp;
            }
        }

        List<Integer> result = new ArrayList<>();
        // Traverse 'nums' array once more to check if the number is in the correct position.
        // If it is not, add the number to the result list.
        for (int i = 0; i < nums.length; i++) {
            if (nums[i] != i + 1) result.add(i + 1);
        }
        return result;
    }
}

package com.cheehwatang.leetcode;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

// Time Complexity  : O(n),
// where 'n' is the length of 'nums'.
// We traverse the 'nums' array twice, once to add the numbers to the HashSet,
// and once to find numbers that are missing.
//
// Space Complexity : O(n),
// where 'n' is the length of 'nums'.
// The result list has length of 'n', and the HashSet has a maximum size of 'n'.

public class FindAllNumbersDisappearedInAnArray_HashTable {

    // Approach:
    // We use a HashSet to record the distinct numbers found in 'nums'.
    // First traverse 'nums' array to add the numbers to the HashSet.
    // Then, we check each number from 1 to 'n' to find the numbers that are missing and add to the result list.

    public List<Integer> findDisappearedNumbers(int[] nums) {
        Set<Integer> set = new HashSet<>();

        // Add the numbers to the HashSet.
        for (int number : nums) set.add(number);

        List<Integer> result = new ArrayList<>();
        // For each number from 1 to 'n', check if the number is in the HashSet.
        // If the number is not found, add to the result list.
        for (int i = 1; i <= nums.length; i++) {
            if (!set.contains(i)) result.add(i);
        }
        return result;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the number of digits in 'num'.
// Traverse 'num' from right to left using the division operator.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the input.

public class Maximum69Number_Math {

    // Approach:
    // For any number, changing the first digit 6 to 9 from left to right yields the maximum number.
    // This is also known as to be Greedy as we only need to find the first digit 6.
    //
    // Using math to traverse an integer from right to left, it is done using division '/' and remainder '%' operations.
    // Checking for the digit 6, and change the leftmost digit 6 to 9.
    // We use a variable 'previous' to record the previous number that we changed, and
    // a variable 'increment' to record the increment we used previously to change the digit 6 to digit 9.
    // Traversing from right to left, we add the increment each time we find a 6,
    // while subtracting the previous increment that we used to change the previously changed 9 back to 6.

    public int maximum69Number (int num) {
        int result = num;
        // 'previous' is set 0 to start as there are no previous number change.
        int previous = 0;
        // Since we are only changing 6 to 9, we only need to add
        // the increment of 3 (and its 10 powers such as 30, 300 or 3000), if the digit is 6.
        // As we start from right to left, the first increment is 3.
        int increment = 3;

        while (num > 0) {
            // Check if the current digit is 6.
            if (num % 10 == 6) {
                // Change the 6 to 9, with "result + increment".
                // Change the previously changed 6 (if any), back to 6 with "result - previous".
                result = result - previous + increment;
                // Update 'previous'.
                previous = increment;
            }
            // Increase the increment by factor of 10 while traversing 'num' to the left.
            increment *= 10;
            num /= 10;
        }
        return result;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the number of digits in 'num'.
// We convert 'num' to a string, convert the string to a char array, convert the char array back to string,
// and parse the string to the result integer, all has linear time complexity to the number of digits in 'num'.
//
// Space Complexity : O(n),
// where 'n' is the number of digits in 'num'.
// The conversion of 'num' to string, string to char array, char array back to string,
// all of which has a same size as the digits in 'num'.

public class Maximum69Number_String {

    // Approach:
    // For any number, changing the first digit 6 to 9 from left to right yields the maximum number.
    // This is also known as to be Greedy as we only need to find the first digit 6.
    // As such, we can convert the integer 'num' to a char array,
    // and traverse from left to right to change the first digit 6 that we encounter to digit 9.

    public int maximum69Number (int num) {
        // Convert the integer 'num' to String, then to char[] for easy conversion of char '6' to char '9'.
        char[] chars = String.valueOf(num).toCharArray();
        for (int i = 0; i < chars.length; i++) {
            // Once found and converted the 6 to 9, we can exit the loop and return the result.
            if (chars[i] == '6') {
                chars[i] = '9';
                break;
            }
        }
        // Convert the char[] back to String and back to integer.
        return Integer.parseInt(String.valueOf(chars));
    }
}

package com.cheehwatang.leetcode;

import java.util.*;

// Time Complexity  : O(m),
// where 'm' is the number of characters in 'paths'.
// For each string in 'paths', we perform String.split() method, which in total as a linear time complexity.
// Additionally, the string concatenation to form the file path approximate to linear time complexity as well.
//
// Space Complexity : O(n),
// where 'n' is the number of strings in 'paths' array.
// In the worst-case when no duplicate content is found and each string in 'paths' only contain a file,
// the space of the HashMap used is O(n).
// Additionally, the space used by each re-constructed file path grows linearly with the input length 'n'.

public class FindDuplicateFileInSystem_HashMap {

    // Approach:
    // Using a HashMap to store the list of paths with the same content,
    // with key = content, and value = the list of paths with that content.
    // With each string in 'paths' being a unique directory, we can split each string by whitespace.
    // The first of the array is the directory, while the remaining elements are the filename and content.
    // To get the content, we can extract based on the open bracket "(", as the content is in the format "()".
    // For each file, we format the path with the following format:
    // directory + "/" + filename
    // Once all the paths are mapped to its content in the HashMap, we only add the list of paths with multiple paths.

    public List<List<String>> findDuplicate(String[] paths) {
        // Set up the result list.
        List<List<String>> result = new ArrayList<>();

        // Return an empty list if there is no item in the paths.
        if (paths.length == 0) return result;

        // Use a HashMap to record the content (key) and the file path list (value).
        Map<String, List<String>> map = new HashMap<>();

        for (String path : paths) {
            // Split each path into the directory and contents.
            // Example:
            // String path = "root/a 1.txt(abcd) 2.txt(efgh)"
            // path.split("\\s+") = ["root/a", "1.txt(abcd)", "2.txt(efgh)"]
            // with split("\\s+") split string separated by whitespace characters " ".
            String[] strings = path.split("\\s+");

            // We know that path[0] is always the directory.
            // So, i = 1, and we check for the content.
            for (int i = 1; i < strings.length; i++) {
                // From "(" onwards, all letters are the contents (including the final ")"), to check for duplicates.
                int index = strings[i].indexOf("(");

                // Example:
                // String.substring(index) results in content = "(abcd)" or "(efgh)".
                String content = strings[i].substring(index);

                // Example:
                // "root/a" + "/" + "1.txt" = "root/a/1.txt"
                // "root/a" + "/" + "2.txt" = "root/a/2.txt"
                String filename = strings[0] + "/" + strings[i].substring(0, index);

                // If the list contains the content (e.g. "(abcd)" or "(efgh)"),
                // we add the 'filename' ("root/a/1.txt") to the list.
                List<String> filenames = map.getOrDefault(content, new ArrayList<>());
                filenames.add(filename);

                // Record the file path list as the key, into the 'map'.
                // Since if content is the same, meaning it is duplicate file in different directories.
                map.put(content, filenames);
            }
        }
        // Check all the key (content) if there are duplicates (size > 1).
        // If there are duplicates, add the list to the result.
        for (String key : map.keySet()) {
            if (map.get(key).size() > 1) {
                result.add(map.get(key));
            }
        }
        return result;
    }
}

package com.cheehwatang.leetcode;

import java.util.ArrayList;
import java.util.List;
import java.util.Stack;

/**
 i * Definition for singly-linked list.
 * public class ListNode {
 *     int val;
 *     ListNode next;
 *     ListNode() {}
 *     ListNode(int val) { this.val = val; }
 *     ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */
// Note: Remember to set up a ListNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the singly linked list.
// We traverse every node in the singly linked list when we first record the node values into the ArrayList.
// Then, we traverse the ArrayList of 'n' elements while performing monotonic stack.
//
// Space Complexity : O(n),
// where 'n' is the number of nodes in the singly linked list.
// The maximum size of the stack is all the nodes in the singly linked list.
// The size of the ArrayList and the result integer array is of size 'n'.

public class NextGreaterNodeInLinkedList {

    // Approach:
    // First, we traverse the singly linked list to record the node values into an ArrayList
    // for easy retrieval of values and to get the size of the linked list.
    // Since the result is in integer array, we need the size before we can make the empty result array.
    //
    // Then, we use a descending monotonic stack to record the next greater node value for each node.
    // For any decreasing sequence in a stack followed by a greater number (e.g. bottom->[4,3,2,1,5]<-top),
    // the element 5 is the greater number for all its previous elements.
    // Likewise, if we have numbers greater than 5 in the stack (e.g. bottom->[7,6,4,3,2,1,5]<-top),
    // then element 5 is the greater number for the elements up to the element that is greater than 5.
    // As such, when we are popping the elements 1, 2, 3 and 4 from the stack,
    // we record the next greater number for each of the elements popped to be 5,
    // resulting in the stack = bottom->[7,6,5]<-top.
    // We continue this descending monotonic stack algorithm for all the elements in the ArrayList,
    // recording the next greater element for each element popped.
    // The remaining numbers in the monotonic stack remains as the default 0 value in the result integer array.

    public int[] nextLargerNodes(ListNode head) {
        List<Integer> list = new ArrayList<>();
        // Record the node values of the singly linked list into an ArrayList.
        for (ListNode current = head; current != null; current = current.next) {
            list.add(current.val);
        }
        // With the ArrayList, we can easily form the result integer array using the size of the ArrayList.
        int[] result = new int[list.size()];

        // Strictly decreasing monotonic stack.
        // Do note that we are storing the index in the stack, but not the element value,
        // as we need the index to update the 'result' integer array with the greater number.
        Stack<Integer> stack = new Stack<>();

        for (int i = 0; i < list.size(); i++){
            // While the element is greater than the top of the stack, pop and record the greater element in the result.
            while (!stack.isEmpty() && list.get(stack.peek()) < list.get(i)) {
                // As stack.pop() function returns the index and remove it from the stack,
                // we can use it straight into the 'result' array, rather than an additional variable for the index.
                result[stack.pop()] = list.get(i);
            }
            // Push the index of the greater element into the stack and continue.
            stack.push(i);
        }
        // Once all the elements checked, return the result.
        // The elements without next greater element remains as the default 0 in the integer array.
        return result;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of string 's'.
// We traverse the string 's' to determine the max consecutive characters.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the input.

public class ConsecutiveCharacters {

    // Approach:
    // We traverse the string 's', counting by comparing the current character with the previous character,
    // increase the count if the same,
    // or reset the count to 1 if the characters are different.
    // For each character, we compare the max with the current count
    // to get the maximum length of consecutive characters.

    public int maxPower(String s) {
        int max = 1, count = 1;
        // Traverse the string 's', starting at index 1,
        // since the first character always yields count of 1.
        for (int i = 1; i < s.length(); i++) {
            // If the current character is the same as the previous character,
            // increase 'count' by 1, and update the 'max' value.
            if (s.charAt(i) == s.charAt(i - 1)) {
                count++;
                max = Math.max(max, count);
            }
            // If the characters are different, reset the 'count' to 1.
            else {
                count = 1;
            }
        }
        // Once we traverse the string, the 'max' is the number of characters in the longest consecutive characters.
        return max;
    }
}

package com.cheehwatang.leetcode;

import java.util.HashMap;
import java.util.Map;

// Time Complexity  : O(n),
// where 'n' is the length of 'nums'.
// As we traverse 'nums' once to compare if any numbers are within the 'indexDiff' and 'valueDiff' range.
//
// Space Complexity : O(k),
// where 'k' is the value of 'indexDiff'.
// As we are adding and removing the numbers from the HashMap, the maximum size of the HashMap is 'indexDiff'.

public class ContainsDuplicateIII_SlidingWindow_HashMap_BucketSort {

    // Approach:
    // We use Bucket Sort to group the numbers into their respective buckets,
    // with each bucket representing the range of 'valueDiff'.
    // As such, the Bucket Sort is important when implementing a Sliding Window technique.
    // The Sliding Window is to ensure that we are comparing numbers within the 'indexDiff' range from the current number.
    // The Bucket Sort is to help us check if there are any number within the Sliding Window that is within the 'valueDiff' range.
    // Note that each Bucket only represents half of the negative and half of the positive from 'valueDiff'.
    // Thus, we need to check the top half of (Bucket - 1) and bottom half of (Bucket + 1),
    // to ensure that we check the whole positive and negative range of 'valueDiff'.

    public boolean containsNearbyAlmostDuplicate(int[] nums, int indexDiff, int valueDiff) {

        // The constraints in the problem descriptions already satisfy the conditions below, but
        // let's just check the input to be sure.
        if (nums == null || nums.length <= 1 || indexDiff == 0 || valueDiff < 0)
            return false;

        // The HashMap stores the key = bucket and value = nums[index].
        Map<Integer, Integer> slidingWindow = new HashMap<>();

        // The new value diff is ('valueDiff' + 1) to ensure that the getBuckets() method don't get error when dividing 0,
        // and to get positive integer < ceiling.
        // However, all the future comparisons of Math.abs(nums[i] - nums[j]) < valueDiff + 1.
        int newValDiff = valueDiff + 1;

        for (int index = 0; index < nums.length; index++) {

            // Group each numbers into buckets.
            int buckets = getBuckets(nums[index], newValDiff);

            // If nums[index] is within the same bucket in the slidingWindow,
            // meaning it is within the 'valueDiff' and 'indexDiff' range.
            // Imagine:
            // number1 / valueDiff = 1.5, is at bucket 1,
            // number2 / valueDiff = 2.5, is at bucket 2, and
            // number3 / valueDiff = 0.5, at bucket 0.
            // For numbers in bucket 0 and 2, we need to check if the number is < 2.5, or > 0.5.
            if (slidingWindow.containsKey(buckets))
                return true;

            if (slidingWindow.containsKey(buckets - 1)
                    && Math.abs(nums[index] - slidingWindow.get(buckets - 1)) < newValDiff) {
                return true;
            }
            if (slidingWindow.containsKey(buckets + 1)
                    && Math.abs(nums[index] - slidingWindow.get(buckets + 1)) < newValDiff) {
                return true;
            }

            // Expand the sliding window until index == indexDiff.
            // Afterwards, we will slide the SlidingWindow to the right,
            // by remove the last number, and adding the latest number.
            if (index >= indexDiff) {
                slidingWindow.remove(getBuckets(nums[index - indexDiff], newValDiff));
            }
            slidingWindow.put(buckets, nums[index]);
        }

        // If successfully traverse the whole array, meaning we fail to find any numbers fulfilling the conditions.
        return false;
    }

    // Method to group numbers into buckets (as the multipliers of the valueDiff)
    private int getBuckets(int integer, int valueDiff) {
        // For negative integer, add 1, so that the multiple is > -1 and <= -0. However, we use -1 of the result to avoid
        // collision of -0 and 0. This ensures the positive 0 and negative 0 range is in separate buckets.
        // For positive integer, the value can be within >= 0 and < 1, since valueDiff is already + 1.
        return integer < 0 ? (integer + 1)/valueDiff - 1 : integer / valueDiff;
    }

}

package com.cheehwatang.leetcode;

import java.util.TreeSet;

// Time Complexity  : O(n logn),
// where 'n' is the length of 'nums'.
// As we traverse 'nums', we perform floor(), ceiling(), remove() and add() methods on the TreeSet for each time.
// The four methods used have a time complexity of O(logn).
// Thus, the final time complexity is O(n logn).
//
// Space Complexity : O(k),
// where 'k' is the value of 'indexDiff'.
// As we are adding and removing the numbers from the TreeSet, the maximum size of the TreeSet is 'indexDiff'.

public class ContainsDuplicateIII_SlidingWindow_TreeSet_OrderedSet {

    // Approach:
    // This problem requires us to check both directions of the 'valueDiff', +/-.
    // As such, an OrderedSet such as TreeSet is important when implementing a Sliding Window technique.
    // The Sliding Window is to ensure that we are comparing numbers within the 'indexDiff' range from the current number.
    // The TreeSet help us check if there are any number within the Sliding Window that is within the 'valueDiff' range.
    // Details of the implementation is explained below.

    public boolean containsNearbyAlmostDuplicate(int[] nums, int indexDiff, int valueDiff) {

        // The constraints in the problem descriptions already satisfy the conditions below, but
        // let's just check the input to be sure.
        if (nums == null || nums.length <= 1 || indexDiff == 0 || valueDiff < 0)
            return false;

        TreeSet<Integer> slidingWindow = new TreeSet<>();

        // Traverse the 'nums' to check each numbers using the SlidingWindow (TreeSet).
        for (int index = 0; index < nums.length; index++) {

            // TreeSet.floor() returns the largest number less than or equal to the given element in the set.
            // TreeSet.ceiling() returns the smallest number more than or equal to the given element in the set.
            // Both return null if no number is found.
            // Here, we find if any numbers, nums[index] - valueDiff >= number >= nums[index] + valueDiff.
            Integer floor = slidingWindow.floor(nums[index] + valueDiff);
            Integer ceiling = slidingWindow.ceiling(nums[index] - valueDiff);

            // If we found numbers in the SlidingWindow that is within the 'valueDiff' range from nums[index],
            // it means that we found the number pair that fulfills the 3 conditions.
            if ((floor != null && floor >= nums[index]) || (ceiling != null && ceiling <= nums[index]))
                return true;

            // Expand the sliding window until index == indexDiff.
            // Afterwards, we will slide the SlidingWindow to the right,
            // by remove the last number, and adding the latest number.
            if (index >= indexDiff)
                slidingWindow.remove(nums[index - indexDiff]);

            slidingWindow.add(nums[index]);
        }

        // If successfully traverse the whole array, meaning we fail to find any numbers fulfilling the conditions.
        return false;
    }
}

package com.cheehwatang.leetcode;

import java.util.Arrays;

// Time Complexity  : O(n^2),
// where 'n' is the length of 'nums'.
// The traversal of 'nums' to make the number-index Pairs has linear time complexity O(n).
// The sort() method has a time complexity of O(n logn).
// When traversing the sorted array to check for 'indexDiff', the worst-case is when 'valueDiff' is very large,
// resulting in quadratic time complexity, O(n^2).
// Considering all the time complexity, the most impactful is O(n^2).
//
// Space Complexity : O(n),
// where 'n' is the length of 'nums'.
// The traversal of 'nums' to make the number-index Pairs has linear space complexity O(n).

public class ContainsDuplicateIII_Sorting {

    // Approach:
    // First, we couple the 'number' and the 'index' as Pair, for each number in 'nums', by creating a new class Pair.
    // This way, we can sort the Pair based on the 'number'.
    // Once sorted, we can iterate through the numbers within the 'valueDiff' range for each 'number' (Pair),
    // and check if the index difference is within 'indexDiff'.
    // Return true when the numbers within 'valueDiff' and 'indexDiff' is found.

    public boolean containsNearbyAlmostDuplicate(int[] nums, int indexDiff, int valueDiff) {

        // The constraints in the problem descriptions already satisfy the conditions below, but
        // let's just check the input to be sure.
        if (nums == null || nums.length <= 1 || indexDiff == 0 || valueDiff < 0)
            return false;

        // Create a number-index pair for all the numbers in 'nums', and store into a Pair array.
        Pair[] pairs = new Pair[nums.length];
        for (int i = 0; i < nums.length; i++) {
            pairs[i] = new Pair(nums[i], i);
        }

        // With the compareTo() method in the Pair class defined, this will stable sort in ascending order of the numbers.
        Arrays.sort(pairs);

        // Traverse the sorted Pair array to check if the numbers are within the valueDiff and the indexDiff range.
        for (int i = 0; i < nums.length; i++) {
            for (int j = i + 1; j < nums.length && pairs[j].value - pairs[i].value <= valueDiff; j++) {
                if (Math.abs(pairs[i].index - pairs[j].index) <= indexDiff) {
                    return true;
                }
            }
        }

        // If successfully traverse the whole array, meaning we fail to find any numbers fulfilling the conditions.
        return false;
    }

    // Pair class to map both 'number' (value) and index together.
    // For sorting, we need to implement the Comparable interface, and define the compareTo method,
    // so that we sort the Pair based on the 'number' (value).
    class Pair implements Comparable<Pair> {

        // Storing the value and index.
        int value;
        int index;

        // Constructor.
        public Pair(int value, int position) {
            this.value = value;
            this.index = position;
        }

        // We want to later sort the array in the ascending order of value.
        @Override
        public int compareTo(Pair pair) {
            return this.value - pair.value;
        }
    }
}

package com.cheehwatang.leetcode;

import java.util.*;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n logn),
// where 'n' is the number of nodes in the tree.
// We traverse the binary tree using a Queue in breadth-first search, with time complexity of O(n).
// However, we then sort the node values before comparing to find the minimum difference.
// The sorting function in the Collections class has a time complexity of O(n logn).
//
// Space Complexity : O(m),
// where 'm' is the breadth of the binary tree.
// The size of the queue in the breadth-first search has a maximum size equivalent to the breadth of the tree.

public class MinimumDistanceBetweenBSTNodes_BFS {

    // Approach:
    // Traverse the binary tree with breadth-first search, while recording the value of each node in a List.
    // Sort the value of the nodes in the list.
    // Compare each pair of consecutive node values and get the minimum difference between the two nodes.

    public int minDiffInBST(TreeNode root) {

        List<Integer> list = new ArrayList<>();

        // Breadth-first search uses a queue in the node traversal.
        Queue<TreeNode> queue = new LinkedList<>();
        queue.offer(root);

        // Traverse all the nodes until the queue is empty.
        while (!queue.isEmpty()) {
            TreeNode current = queue.poll();
            list.add(current.val);
            // If the current node has left or right child, add to the queue.
            if (current.left != null) queue.offer(current.left);
            if (current.right != null) queue.offer(current.right);
        }

        // Sort the list of node values in ascending order.
        Collections.sort(list);
        int result = Integer.MAX_VALUE;
        // Get the difference in each consecutive pair and get the minimum difference.
        for (int i = 1; i < list.size(); i++)
            result = Math.min(result, list.get(i) - list.get(i - 1));

        // Return the minimum difference between any two nodes once all the nodes are traversed.
        return result;
    }
}

package com.cheehwatang.leetcode;

import java.util.Stack;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// We traverse the binary tree in-order, comparing each value with the previous value to get the minimum difference.
//
// Space Complexity : O(m),
// where 'm' is the depth of the binary tree.
// The size of the stack used in the in-order traversal has a maximum size equivalent to the depth of the tree.

public class MinimumDistanceBetweenBSTNodes_DFS_Iterative {

    // Approach:
    // Perform in-order traversal, comparing the value of the nodes to the previous node.
    // For in-order traversal, we use stack to record the nodes to be visited, visiting the nodes in the order of:
    // 1. Left node (until we hit null, while storing the nodes in the stack).
    // 2. Visit the root node, and get the difference with the previous node.
    // 3. Right node (if any, then restart step 1 and step 2).

    public int minDiffInBST(TreeNode root) {
        int result = Integer.MAX_VALUE, previous = -1;

        // Iterative depth-first search is performed using a stack to store the nodes.
        Stack<TreeNode> stack = new Stack<>();
        // We use a pointer to keep track of the current node.
        TreeNode current = root;

        // At any point, if the pointer is null and the stack is empty, we have fully traversed the tree.
        while (current != null || !stack.isEmpty()) {
            // For any node, completely traverse the left branch.
            while (current != null) {
                stack.push(current);
                current = current.left;
            }
            // Get the top node in the stack.
            current = stack.pop();

            // Get the value difference of the two nodes, and get the minimum difference.
            if (previous != -1) result = Math.min(result, current.val - previous);
            previous = current.val;

            // Visit the right node (if any).
            // Note that if the right node is null, the pointer is null, which will continue to pop the stack.
            // If ever the right node is not null, then we fully traverse its left branch.
            current = current.right;
        }
        // Return the minimum difference between any two nodes once all the nodes are traversed.
        return result;
    }
}

package com.cheehwatang.leetcode;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// We traverse the binary tree in-order, comparing each value with the previous value to get the minimum difference.
//
// Space Complexity : O(1),
// as the auxiliary space used for the variables are constant.

public class MinimumDistanceBetweenBSTNodes_DFS_Recursive {

    // Approach:
    // Using recursion to perform in-order traversal, comparing the value of the nodes to the previous node.
    // For in-order traversal, to nodes are visited in the following order:
    // 1. Left node.
    // 2. Root node to get the difference with the previous node.
    // 3. Right node.

    int result = Integer.MAX_VALUE, previous = -1;

    public int minDiffInBST(TreeNode root) {
        // Visit the left node.
        if (root.left != null) minDiffInBST(root.left);

        // Get the value difference of the two nodes, and get the minimum difference.
        if (previous != -1) result = Math.min(result, root.val - previous);
        previous = root.val;

        // Visit the right node.
        if (root.right != null) minDiffInBST(root.right);

        // Return the minimum difference between any two nodes once all the nodes are traversed.
        return result;
    }
}

package com.cheehwatang.leetcode;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

// Time Complexity  : O(n^2),
// where 'n' is the length of 'nums'.
// We traverse 'nums' to check each 'nums[i]', with each element we use 2 pointers,
// thus it is a nested loop, with O(n^2) time complexity.
// The Arrays.sort() function has a time complexity of O(n logn).
//
// Space Complexity : O(n^2),
// where 'n' is the length of 'nums'.
// The result can grow quadratically with the input 'nums'.
// For each element 'nums[i]', there is 'n' number of possible triplets that sum to 0.
// As such, the space complexity is O(n^2).

public class ThreeSum {

    // Approach:
    // For 3 sum, nums[i] + nums[j] + nums[k] = 0.
    // For each 'nums[i]' in 'nums', we can check if the sum with nums[j] and nums[k] for the other numbers
    // are equal to 0, using two pointers, 'left' and 'right' to traverse the remaining numbers.
    // In order to use two pointers in this manner, we have to first sort the array in ascending order.
    // This allows use to check if nums[i] + nums[j] + nums[k] is greater or less than 0.
    // If the sum is less than 0, then we shift the 'left' pointer to the right.
    // If the sum is greater than 0, then we shift the 'right' pointer to the left.
    // If we found the sum to the 0, then we shift both pointers, and add the numbers to the result.

    public List<List<Integer>> threeSum(int[] nums) {

        Arrays.sort(nums);
        List<List<Integer>> result = new ArrayList<>();

        // Check each 'nums[i]'.
        // We use "nums.length - 2" as the last triplet to check.
        for (int i = 0; i < nums.length - 2; i++) {
            // If nums[i] is identical with the previous number,
            // skip the number to shorten time and prevent duplicate triplets.
            if (i > 0 && nums[i] == nums[i - 1]) continue;

            // Two points, the 'left' and 'right'.
            // If the sum is > 0, then decrease the 'right', and increase 'left' if sum < 0.
            // We have found a triplet if the sum == 0.
            int left = i + 1;
            int right = nums.length - 1;
            while (left < right) {
                if (nums[left] + nums[right] + nums[i] > 0) right--;
                else if (nums[left] + nums[right] + nums[i] < 0) left++;
                else {
                    result.add(Arrays.asList(nums[left],nums[right],nums[i]));
                    right--;
                    left++;
                    // For both 'left' and 'right', skip if the subsequent integer is the same.
                    // This shortens the time and prevent duplicate triplets.
                    while (left < right && nums[right] == nums[right + 1]) right--;
                    while (left < right && nums[left] == nums[left - 1]) left++;
                }
            }
        }
        return result;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of 'arr'.
// We traverse 'arr' once to count the frequency of the elements.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the input 'arr',
// with the counting array with size of 101 regardless of the input 'arr'.

public class ThreeSumWithMultiplicity_Counting {

    // Approach:
    // Using a counting array, get the frequency of all the integers,
    // then check all the possible combinations to get the sum.
    // Note that, i < j < k and arr[i] + arr[j] + arr[k] == target,
    // do not require the index as the sum is not dependent on the index.

    public int threeSumMulti(int[] arr, int target) {

        // With the constraint of 0 <= arr[i] <= 100, count the frequency of all the integers/
        int[] counting = new int[101];
        for (int integer : arr) counting[integer]++;

        // Keep the count as long type, so as only need to perform the modulo once at the end.
        long count = 0;

        // Traverse the counting array in two for-loops to get the value for 'i' and 'j'.
        for (int i = 0; i <= 100; i++) {
            for (int j = i; j <= 100; j++) {
                // Get the k integer to check if it is in the counting array.
                int k = target - i - j;
                if (k < 0 || k > 100) continue;
                if (counting[k] > 0) {
                    // If the triplet is of the same integers (eg. [1,1,1], target = 3),
                    // then perform geometric sum for 3 elements.
                    if (i == k && j == k)
                        count += (long) counting[i] * (counting[i] - 1) * (counting[i] - 2) / 6;
                    // If i and j is identical, but different from k (eg. [1,1,2], target = 4),
                    // then perform geometric sum for i & j, then multiply with k.
                    else if (i == j)
                        count += (long) counting[i] * (counting[i] - 1) / 2 * counting[k];
                    // If both i and j is smaller than k, then get the multiples of all the frequency.
                    // This is to make sure no duplicates of results
                    // (eg, [1,2,3], target = 6), only [1,2,3] is counted, but not [2,1,3] or [3,2,1], etc.)
                    else if (i < k && j < k)
                        count += (long) counting[i] * counting[j] * counting[k];
                }
            }
        }
        return (int) (count % (1e9 + 7));
    }
}

