package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of 'nums'.
// We traverse 'nums' array twice, resulting in time complexity of O(n).
//
// Space Complexity : O(n),
// where 'n' is the length of 'nums'.
// The 'result' array has the same size as the input 'nums' array.

public class ProductOfArrayExceptSelf {

    // Approach:
    // To exclude the current number from the product, we can multiply the prefix product and the suffix product.
    // The prefix product is the product of all the integers to the left of the current number, and
    // the suffix product is the product of all the integers to the right of the current number.
    //
    // With that, we need to traverse the 'nums' array twice.
    // Once from left to right to determine the prefix product for each position in 'nums', and
    // once from right to left to determine the suffix product for each position in 'nums'.
    // Note that we have to start the prefix and suffix with 1, not 0, as we are performing multiplication.

    public int[] productExceptSelf(int[] nums) {
        int n = nums.length;
        int[] result = new int[n];

        // Option to use a variable 'prefix' to store, but here we use the result array for simplicity.
        result[0] = 1;
        // We start at index 1 as index 0 has no prefix.
        for (int i = 1; i < n; i++) {
            // Note here that we only multiply with nums[i - 1] for each result[i] to skip the i-th element.
            result[i] = result[i - 1] * nums[i - 1];
        }
        int suffix = 1;
        // We start at index 'n - 2' as index 'n - 1' has no suffix.
        for (int i = n - 2; i >= 0; i--) {
            // For suffix, we use nums[i + 1] instead, traversing from right to left.
            suffix *= nums[i + 1];
            result[i] *= suffix;
        }
        return result;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of String array 'words'.
// We traverse the String array once to count and check for the length of palindrome that can form.
//
// Space Complexity : O(1),
// as the counting matrix (26 * 26) is independent on the length of the input String array 'words'.

public class LongestPalindromeByConcatenatingTwoLetterWords_Counting {

    // Approach:
    // With the elements containing only two lowercase English characters, we can use a 2D counting array of size 26 * 26,
    // to store the frequency of the elements in 'words'.
    //
    // There are two fundamental cases to form a palindrome using the elements in 'words':
    // 1. Word with 2 different characters (eg. "ab", "cd")
    // 2. Word with the same characters (eg. "aa", "bb")
    //
    // Case 1:
    // We need to find the pair that matches each other in a palindrome. For example using words "ab" and "ba".
    // They can form a palindrome by either "abba" or "baab".
    // Even if we have other palindromes in between, it does not affect, such as "abXXXXba" or "baXXXXab".
    // With that, we need to store the occurrence of either "ab" or "ba", whichever came first.
    // Then the next word can be flipped and checked.
    // As the pair is "used" as soon as matched, this is a greedy approach.
    //
    // Case 2:
    // This can further split into 2 behaviors.
    // First is the same as Case 1, "aa" and "aa" forming "aaaa" palindrome.
    //
    // Second is for it to be in the center of the palindrome.
    // For example, words are "ab", "ba" and "zz", it can form "abzzba".
    // As such, we need to first check the case 1 behavior, forming examples like "aaaa", before checking the center.
    // As there will only be one center element (if exist), we check if any exist.

    public int longestPalindrome(String[] words) {
        // As there are only 2 lowercase English letters in each word, we can represent the word using a
        // 2D array, with the row representing the first letter, and column representing the second letter.
        int[][] counting = new int[26][26];
        int max = 0;
        for (String word : words) {
            // Convert the char to its relative integer by subtracting with 'a' (e.g. 'a' == 0, 'b' == 1, etc).
            int a = word.charAt(0) - 'a';
            int b = word.charAt(1) - 'a';
            // We can flip the letters by using counting[b][a], while counting[a][b] represents the original lettering.
            // If we found the pair corresponding to the flipped word, then we can increase the max by 4 and update
            // the frequency of the flipped word.
            // For Example: If "ab" is previously stored in counting[0][1], when the word "ba" came up later,
            //              the flipped word of "ba" which is "ab" in counting[0][1] is found.
            // This is also why it is a greedy algorithm, as we count pair in the final result as soon as it is found,
            // since the position of the pair in a palindrome is not important, as long as they are placed opposite of
            // each other.
            if (counting[b][a] > 0) {
                max += 4;
                counting[b][a]--;
            }
            // If no pair is found, store the occurrence of the word.
            else {
                counting[a][b]++;
            }
        }
        // For the odd word in the center of the palindrome (e.g. "aa", "bb", "cc", etc.),
        // Check for all 26 possible pairs, if any is found, increase the max by 2.
        // For Example: words = ["ab","ba","zz","yy"]
        //              With "ab" and "ba" form a pair, with max = 4,
        //              either "zz" or "yy" can fit in the center to expand the palindrome, forming "abzzba" or "abyyba".
        // Do note that the valid pairs formed previously is already counted, since a == b, counting[a][b] == counting[b][a].
        for (int i = 0; i < 26; i++) {
            if (counting[i][i] > 0) {
                max += 2;
                break;
            }
        }
        return max;
    }
}

package com.cheehwatang.leetcode;

import java.util.HashMap;
import java.util.Map;

// Time Complexity  : O(n),
// where 'n' is the length of String array 'words'.
// We traverse the String array once to count and check for the length of palindrome that can form.
//
// Space Complexity : O(n),
// where 'n' is the length of String array 'words'.
// The worst-case is when no pair is found that can form a palindrome,
// resulting in the HashMap to grow linearly with the input when all the strings are unique.

public class LongestPalindromeByConcatenatingTwoLetterWords_HashTable {

    // Approach:
    // Use a HashMap to keep track of the frequency of each element in 'words'.
    //
    // There are two fundamental cases to form a palindrome using the elements in 'words':
    // 1. Word with 2 different characters (eg. "ab", "cd")
    // 2. Word with the same characters (eg. "aa", "bb")
    //
    // Case 1:
    // We need to find the pair that matches each other in a palindrome. For example using words "ab" and "ba".
    // They can form a palindrome by either "abba" or "baab".
    // Even if we have other palindromes in between, it does not affect, such as "abXXXXba" or "baXXXXab".
    // With that, we need to store the occurrence of either "ab" or "ba", whichever came first.
    // Then the next word can be flipped and checked.
    // As the pair is "used" as soon as matched, this is a greedy approach.
    //
    // Case 2:
    // This can further split into 2 behaviors.
    // First is the same as Case 1, "aa" and "aa" forming "aaaa" palindrome.
    //
    // Second is for it to be in the center of the palindrome.
    // For example, words are "ab", "ba" and "zz", it can form "abzzba".
    // As such, we need to first check the case 1 behavior, forming examples like "aaaa", before checking the center.
    // As there will only be one center element (if exist), we check if any exist.

    public int longestPalindrome(String[] words) {
        Map<String, Integer> map = new HashMap<>();
        int max = 0;
        for (String word : words) {
            // Get the flipped word.
            String flipped = "" + word.charAt(1) + word.charAt(0);
            // If the flipped word is found, reduce the count of the flipped word.
            // Removing the key from the map when it is 0 is important later on when we need to check for the center word
            // that can form the palindrome.
            if (map.containsKey(flipped)) {
                max += 4;
                map.put(flipped, map.get(flipped) - 1);
                // As we are using map.containsKey(), we need to clean up the HashMap when the count is 0.
                if (map.get(flipped) == 0) map.remove(flipped);
            } else {
                map.put(word, map.getOrDefault(word, 0) + 1);
            }
        }
        // For the odd word in the center of the palindrome (e.g. "aa", "bb", "cc", etc.),
        // check for all 26 possible pairs, if any is found, increase the max by 2.
        // For Example: words = ["ab","ba","zz","yy"]
        //              With "ab" and "ba" form a pair, with max = 4,
        //              either "zz" or "yy" can fit in the center to expand the palindrome, forming "abzzba" or "abyyba".
        // Exit the for-loop once found, as we only can use one at the center.
        for (int i = 0; i < 26; i++) {
            char current = (char) ('a' + i);
            if (map.getOrDefault("" + current + current, 0) > 0) {
                max += 2;
                break;
            }
        }
        return max;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of the string 's2'.
// We traverse the string 's2' once with the sliding window technique
// to compare the substrings of length of 's1' to find permutation matching the string 's1'.
// If the string 's1' is longer than string 's2', we would return false, thus not checking.
// As such, the time complexity grows linearly with the length of string 's2'.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the size of the input string 's1' and string 's2'.

public class PermutationInString {

    // Approach:
    // We can use an integer array of size 26 to record the count of the letters in any substrings.
    // By increasing the count for one substring, and decreasing the count for the other substring,
    // we can check whether both substrings are permutation of each other, if the count are all zeroes.
    // For example:
    // s1 = 'abc', s2 = 'bca', count = [0, 0, 0] for letter, 'a', 'b' and 'c' respectively.
    // At index = 0, s1 = 'a', s2 = 'b', count = [1, -1, 0], as we increase for letter 'a', and decrease for letter 'b'.
    // At index = 1, s1 = 'b', s2 = 'c', count = [1, 0, -1], as we increase for letter 'b', and decrease for letter 'c'.
    // At index = 2, s1 = 'c', s2 = 'a', count = [0, 0, 0], as we increase for letter 'c', and decrease for letter 'a'.
    //
    // Using sliding window, we can use the above method to check if the count array is all zeroes,
    // as we move the sliding window forward.
    // Whenever we found the count array to be all zeroes, return true.
    // If we reach the end and still unable to get count array to be all zeroes, return false.

    public boolean checkInclusion(String s1, String s2) {
        int s1Length = s1.length(), s2Length = s2.length();

        // If the length of 's1' is longer than the length of 's2',
        // it is impossible for 's1' to be the permutation for the substrings of 's2'.
        if (s1Length > s2Length) return false;

        int[] alphabetCount = new int[26];
        // First, we check all the letters in 's1', increasing the count,
        // as well as the corresponding letters in 's2', decreasing the count of the alphabet.
        for (int i = 0; i < s1Length; i++) {
            alphabetCount[s1.charAt(i) - 'a']++;
            alphabetCount[s2.charAt(i) - 'a']--;
        }
        // If all the alphabet counts are zeroes, then we have found that 's1' is the permutation of 's2' substring.
        if (isAllZeroesInArray(alphabetCount)) return true;

        // With the sliding window technique, we move the window of length of 's1' forward,
        // each time increasing the count for the back, and decreasing the count for the front of the window.
        for (int i = s1Length; i < s2Length; i++) {
            alphabetCount[s2.charAt(i - s1Length) - 'a']++;
            alphabetCount[s2.charAt(i) - 'a']--;
            // If all the alphabet counts are zeroes, then we have found that 's1' is the permutation of 's2' substring.
            if (isAllZeroesInArray(alphabetCount)) return true;
        }
        // If we reach the end and still unable to get count array to be all zeroes, return false.
        return false;
    }

    // Helper method to check if the array contains only zeroes.
    private boolean isAllZeroesInArray(int[] array) {
        // For every integer,
        for (int integer : array)
            // return false if the integer is not zero.
            if (integer != 0) return false;

        // If all the integers in the array are zeroes, return true.
        return true;
    }
}

package com.cheehwatang.leetcode;

import java.util.Arrays;

// Time Complexity  : O(n^2),
// where 'n' is the length of 'nums'.
// We traverse 'nums' to check each 'nums[i]', with each element we use 2 pointers,
// thus it is a nested loop, with O(n^2) time complexity.
// The Arrays.sort() function has a time complexity of O(n logn).
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the input.

public class ThreeSumClosest {

    // Approach:
    // Use sorting and two pointers to search for all the triplets and check for the closest sum to 'target'.
    // For each 'nums[i]' in 'nums', we can check the sum with nums[j] and nums[k] using two pointers,
    // 'left' and 'right' to traverse the remaining numbers.
    // In order to use two pointers in this manner, we have to first sort the array in ascending order.
    // This allows use to check if nums[i] + nums[j] + nums[k] is greater or less than 0.
    // If the sum is less than 'target', then we shift the 'left' pointer to the right.
    // If the sum is greater than 'target', then we shift the 'right' pointer to the left.
    // If we found the sum to be equal to 'target', then we return 'target'.
    //
    // To find the closest number to 'target', we use a variable to keep track and update when found a closer number.

    public int threeSumClosest(int[] nums, int target) {
        // Sort the array, and use 2 variables to keep track of the minimum difference and the sum of the triplets.
        Arrays.sort(nums);

        int minDiff = Integer.MAX_VALUE;
        int threeSum = 0;
        for (int i = 0; i < nums.length - 2; i++) {
            // If nums[i] is identical with the previous number skip the number to shorten the time.
            if (i > 0 && nums[i] == nums[i - 1]) continue;

            // The following 'highSum' and 'lowSum' is additional check to shorten the time.
            // Otherwise, the rest of the code works on their own.
            //
            // The 'highSum' is to check if the largest possible sum for nums[i] is less than the target.
            // Since we have sorted the 'nums', we know all the remaining numbers will be smaller than the 'highSum'.
            // Thus, we can skip the remaining numbers if 'highSum' is lesser than target.
            int highSum = nums[i] + nums[nums.length - 1] + nums[nums.length - 2];
            if (highSum < target) {
                if (target - highSum < minDiff) {
                    threeSum = highSum;
                    minDiff = target - highSum;
                }
                continue;
            }
            // The 'lowSum' is to check if the smallest possible sum for nums[i] is greater than the target.
            // Since we have sorted the 'nums', we know all the remaining numbers will be greater than the 'lowSum'.
            // If the 'lowSum' is greater than the target,
            // the remaining numbers, including the subsequent i-th numbers will be greater than the 'lowSum'.
            // Thus, we are sure that 'lowSum' is the closest triplet to 'target', if found.
            int lowSum = nums[i] + nums[i + 1] + nums[i + 2];
            if (lowSum > target) {
                if (lowSum - target < minDiff) {
                    return lowSum;
                }
            }

            // After the initial checks, use two pointers, 'left' and 'right'.
            int left = i + 1;
            int right = nums.length - 1;
            while (left < right) {
                int sum = nums[left] + nums[right] + nums[i];
                int difference = Math.abs(sum - target);
                // If the triplet's 'minDiff' is lesser, then record it as the closest 'threeSum' for now.
                if (difference < minDiff) {
                    minDiff = difference;
                    threeSum = sum;
                }
                // Otherwise, decrease the 'right' if sum > target,
                if (sum > target) {
                    right--;
                    while (left < right && nums[right] == nums[right + 1]) right--;
                }
                // and increase 'left' if sum < target.
                else if (sum < target) {
                    left++;
                    while (left < right && nums[left] == nums[left - 1]) left++;
                }
                // If found sum == target, then it is the closest possible.
                else {
                    return sum;
                }
            }
        }
        return threeSum;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of the longest string.
// This happens when the greatest common divisor is a string of length 1.
//
// Space Complexity : O(n),
// where 'n' is the length of the longest string.
// The maximum height of the recursive call stack is 'n' when the greatest common divisor is a string of length 1.

public class GreatestCommonDivisorOfStrings {

    // Approach:
    // Using Euclid's Algorithm from math for the strings' Greatest Common Divisor (GCD).
    // Euclid's algorithm has 2 main theorem:
    // 1. Subtracting the smaller number from the larger number does not change the GCD.
    //    (e.g. 6 - 4 = 2, the GCD remains as 2).
    // 2. If the smaller number exactly divides the larger number, the smallest number is the GCD.
    //    (e.g. 8 % 4 = 0, so 4 is the GCD)
    // The implementation of Euclid's Algorithm for whole numbers is as below:
    /*
    int gcdByEuclidsAlgorithm(int n1, int n2) {
        if (n2 == 0) return n1;
        return gcdByEuclidsAlgorithm(n2, n1 % n2);
    }
    */

    public String gcdOfStrings(String str1, String str2) {
        // If all of str2 is 'divided' and none remains, then str1 is the GCD.
        // Similar to "if (n2 == 0) return n1;"
        if (str2.equals("")) {
            return str1;
        }

        int length1 = str1.length();
        int length2 = str2.length();
        // Check if the shorter string is the same as the substring of same length of the longer string.
        // If it is the same, then we perform recursion of the smaller string and the 'remainder'.
        // Similar to "return gcdByEuclidsAlgorithm(n2, n1 % n2);" above, but we need to take note on the string length.
        if (length1 > length2) {
            if (str1.substring(0, length2).equals(str2)) {
                return gcdOfStrings(str2, str1.substring(length2));
            }
        } else{
            if (str2.substring(0, length1).equals(str1)) {
                return gcdOfStrings(str1, str2.substring(length1));
            }
        }

        // If the substring is not the same as the shorter string, then there are no GCD.
        return "";
    }
}

package com.cheehwatang.leetcode;

import java.util.LinkedList;
import java.util.List;
import java.util.Stack;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder as your preorder traversal algorithms.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree, as we are traversing every single node.
//
// Space Complexity : O(n),
// where 'n' is the number of nodes in the tree,
// as we are recording the data of every node into the List.
// The stack only takes up the maximum space of tree height, which is smaller than 'n'.

public class BinaryTreePreorderTraversal_Iterative {

    // Approach:
    // For depth first search, we use stack to record the nodes to be visited, visiting the nodes in the order of:
    // 1. Visit the root node, and add the value to the list.
    // 2. Left node (until we hit null, while storing the nodes in the stack).
    // 3. Right node (if any, then restart step 1 and step 2).
    //
    // Note: Other than slight variation in the algorithm,
    //       both preorder and postorder traversal also use Stack when implemented iteratively.

    public List<Integer> preorderTraversal(TreeNode root) {
        List<Integer> integerList = new LinkedList<>();
        Stack<TreeNode> rightNodes = new Stack<>();

        while (root != null) {
            // First, we record the root.
            integerList.add(root.val);

            // If right node is available, push the right node into the Stack first.
            // We will pop it later we are done with the left nodes.
            if (root.right != null) {
                rightNodes.push(root.right);
            }

            // Continue to traverse to the left, while recording each subtree root nodes,
            // and pushing the subtree right nodes into the stack.
            // Once reaches a leaf node, pop the right nodes and continue.
            root = root.left;
            if (root == null && !rightNodes.isEmpty()) {
                root = rightNodes.pop();
            }
        }
        // Fully traversed the tree.
        return integerList;
    }
}

package com.cheehwatang.leetcode;

import java.util.LinkedList;
import java.util.List;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder as your preorder traversal algorithms.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree, as we are traversing every single node.
//
// Space Complexity : O(n),
// where 'n' is the number of nodes in the tree,
// as we are recording the value of every node into the List.
// The recursive call stack only takes up the maximum space of tree height, which is smaller than 'n'.

public class BinaryTreePreorderTraversal_Recursive {

    // Approach:
    // Using recursive function to traverse the tree, visiting the nodes in the order of:
    // 1. Visit the root node, and add the value to the list.
    // 2. Left node (with another recursive call).
    // 3. Right node (with another recursive call).

    // Wrapper method to set up and initialize the recursive function.
    public List<Integer> preorderTraversal(TreeNode root) {
        List<Integer> integerList = new LinkedList<>();
        integerList = preorderTraversal(root, integerList);
        return integerList;
    }

    // Recursive method.
    private List<Integer> preorderTraversal(TreeNode root, List<Integer> integerList) {
        // The base case, for when the root is null.
        if (root == null) return integerList;

        // For preorder traversal, we first visit the root and add the value of the root to the list.
        integerList.add(root.val);
        // Then, we visit the left node.
        preorderTraversal(root.left, integerList);
        // Lastly, we visit the right node.
        preorderTraversal(root.right, integerList);

        // Once done, we return the list.
        return integerList;
    }
}

