// Time Complexity  : O(sqrt(n)),
// where 'n' is 'candies'.
// For each person, the number of candies given increases by one.
// Thus, the total number distributed candies is "n * (n + 1) / 2", resulting in time complexity of O(sqrt(n)).
//
// Space Complexity : O(m),
// where 'm' is 'num_people'.
// The result array has the length of 'num_people'.

public class DistributeCandiesToPeople {

    // Approach:
    // Use two variables,
    // 1. 'person' to track the index of the person, and
    // 2. 'candy' to track the number of candies that should be given.
    // Then rotate the index while slowly reduce the total number of candies, while increasing the candy count.
    // Record the result in an int[].

    public int[] distributeCandies(int candies, int num_people) {
        // Integer array to record the distribution of candies.
        int[] result = new int[num_people];

        int person = 0;
        int candy = 1;

        // While we still have candies, add the candy count to the int[], and reduce the candies.
        // Each iteration increase the candy and people by 1.
        while (candies > 0) {
            // If candies is more than candy, return candy.
            // However, if the remaining candies is less than candy, distribute the remaining candies.
            result[person] += Math.min(candies, candy);
            candies -= candy++;
            // With the remainder operator %, the person will restart at index 0 once we reach the 'num_people'.
            person = (person + 1) % num_people;
        }
        return result;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(logn),
// as we are dividing 'n' by either 2, 3 or 5 until reaching 1,
// the time complexity scales with the log2 of 'n' in the worst case.
//
// Space Complexity : O(1),
// as no additional space is used.

public class UglyNumber {

    // Approach:
    // Continue to divide 'n' with either 2, 3 or 5 until unable to fully divide anymore.
    // If the result is 1, then 'n' is an ugly number.
    // If it is another prime number other than 2, 3 or 5, then it is not an ugly number.

    public boolean isUgly(int n) {
        // Edge case of 'n' == 0 and return true.
        if (n == 0) return true;

        // We continue to divide 'n' with number 2, 3, 4 and 5 until 'n' cannot be completely divided.
        for (int i = 5; i >= 2; i--) {
            while (n % i == 0) n /= i;
        }

        // As 'n' can be negative, we take the absolute value of the result.
        return Math.abs(n) == 1;
    }
}

package com.cheehwatang.leetcode;

import java.util.HashSet;
import java.util.List;
import java.util.Set;

// Time Complexity  : O(n * m),
// where 'n' is the length of the list 'arr', and 'm' is the number of characters in the list 'arr'.
// In the worst-case when all characters are unique, there is 'n' times of string concatenation,
// which each string concatenation having a linear time complexity, resulting in time complexity of O(n * m).
// Additionally, checking for duplicates and if the characters are unique introduces additional complexity.
//
// Space Complexity : O(n * m),
// where 'n' is the length of the list 'arr', and 'm' is the number of characters in the list 'arr'.
// In the recursive method, the maximum length of the recursive call stack is the number of elements in the list 'arr',
// O(n).
// In the worst-case when all characters are unique, the space used for the strings concatenation is O(n * m).

public class MaximumLengthOfAConcatenatedStringWithUniqueCharacters_Backtracking {

    // Approach:
    // Using recursive and backtracking to get the maximum length.
    // In each recursion, there are two states:
    // 1. Take or concatenate the current element.
    // 2. Not take the current element, remains the same.
    // Additionally, there is the scenario where the element contains duplicate characters.
    // If such element exist, then skip to the next element.

    // Wrapper and initialization method.
    public int maxLengthString(List<String> arr) {
        // Start the recursion from index 0, with an empty string.
        return maxLengthString(arr, 0, "").length();
    }

    // Recursive method.
    private String maxLengthString(List<String> arr, int index, String str) {
        // When the recursion reached the end of 'arr', return 'str', as the base case.
        if (index == arr.size()) return str;

        // The element at the current index.
        String current = arr.get(index);
        // If found duplicate, then skip to the next element (index + 1).
        if (containsDuplicate(current)) return maxLengthString(arr, index + 1, str);

        // Scenario 2, when we not take this element.
        String notTake = maxLengthString(arr, index + 1, str);

        // For Scenario 1, first check if any common characters found in 'str' and 'current'.
        String take = str;
        for (char character : current.toCharArray()) {
            if (take.indexOf(character) >= 0) {
                take = "";
                break;
            }
        }
        // If common characters not found, then we can take or concatenate 'current' with 'str'.
        if (take.equals(str)) {
            take = maxLengthString(arr, index + 1, str + current);
        }

        // Return the string that is longer.
        return take.length() >= notTake.length() ? take : notTake;
    }

    // Method to check if the element contains duplicate characters.
    private boolean containsDuplicate(String str) {
        Set<Character> set = new HashSet<>();
        for (int i = 0; i < str.length(); i++) {
            // If the character is already in the set, then this element contains duplicate.
            if (!set.add(str.charAt(i))) return true;
        }
        // If all characters successfully added into the HashSet, then no duplicates found.
        return false;
    }
}

package com.cheehwatang.leetcode;

import java.util.ArrayList;
import java.util.List;

// Time Complexity  : O(n^3 + m),
// where 'n' is the length of the list 'arr', and 'm' is the number of characters in the list 'arr'.
// We iterate through each character in the strings to find duplicates, with O(m) time complexity.
// In the worst-case when all characters are unique, we iterate through 'bitmaskList', O(n^2) size,
// for string in the list 'arr'.
//
// Space Complexity : O(n^2 + m),
// where 'n' is the length of the list 'arr', and 'm' is the number of characters in the list 'arr'.
// In the worst-case when all characters are unique, the space used in the 'bitmaskList' is O(n^2),
// since 'n' number of elements is added to the list for each element.
// Each string in the list 'n' is converted to char Array, resulting in time complexity of O(m).

public class MaximumLengthOfAConcatenatedStringWithUniqueCharacters_BitManipulation {

    // Approach:
    // Using bitmasking and bit manipulation to check for duplicates and 'concatenate' the unique characters.
    //
    // First, bitmasking is the process of storing data as bits (binary).
    // As a bit is represented by 0 or 1, it can be treated as true or false.
    // For string characters with radix of less than 31, in this case 26 lowercase English alphabets,
    // we can use bitmasking to store if any character exist (1) or not exist (0).
    // Using the left shift operation '<<', we can store 1 at a certain bit position in the number.
    // For example, 'a' is stored as 1 << 'a' - 'a' (1 << 0) as 1, 'b' as 10 binary, 'c' as 100 binary, etc.
    // Note:
    // Reason for 31 is only when using primitive type int (32-bit signed), while primitive type long is 63 (64-bit signed).
    //
    // In bit manipulation,
    // '&' bitwise AND operation can be used to check for duplicate.
    // For example: Using bitmasking mentioned above, "abc" == '111' in binary, "cde" == '11100' in binary.
    //              '00111' & '11100' == '00100'.
    //              So if '&' two bitmasked elements with result of > 0, then we have found duplicate.
    // '|' bitwise OR operation can be used to 'concatenate' the unique characters.
    // For example: "ab" == '11', "de" == '11000', '00011' | '11000' == '11011', indicating "abde".

    public int maxLength(List<String> arr) {
        // List of elements (concatenated or not) to be stored,
        // as we need to concatenate the new elements to all the strings with only unique characters found.
        List<Integer> bitmaskList = new ArrayList<>();
        // Remember the list is storing bitmasked String as int. An empty string is represented as '0'.
        bitmaskList.add(0);

        int max = 0;
        for (String str : arr) {
            int duplicate = 0;
            int currentBitmasked = 0;
            // Check if 'str' contains duplicate characters, as well as perform bitmasking into 'currentBitmasked'.
            // Optional to use str.get(index) to get the character, saving on the time and space complexity.
            // Below is written for better readability.
            for (char character : str.toCharArray()) {
                // '&' get > 0 if contains duplicate.
                duplicate |= currentBitmasked & (1 << (character - 'a'));
                // '|' and '<<' to bit mask.
                currentBitmasked |= 1 << (character - 'a');
            }
            // Skip the current element if there are duplicate characters.
            if (duplicate > 0) continue;

            // For all the strings with only unique characters found so far:
            for (int i = 0; i < bitmaskList.size(); i++) {
                // skip if the string shared same character, or
                if ((bitmaskList.get(i) & currentBitmasked) > 0) continue;

                // concatenate otherwise.
                bitmaskList.add(bitmaskList.get(i) | currentBitmasked);
                // For all strings, get the longest, using bitCount method to get all the 1s in the bit masked String.
                max = Math.max(max, Integer.bitCount(bitmaskList.get(i) | currentBitmasked));
            }
        }
        return max;
    }
}

package com.cheehwatang.leetcode;

import java.util.ArrayList;
import java.util.List;

// Time Complexity  : O(2^n),
// where 'n' is the length of the integer.
// The worst case scenario is when 'k' == 1, every increment in length 'n' doubles the number of integers to check.
//
// Space Complexity : O(2^n),
// where 'n' is the length of the integer.
// The worst case scenario is when 'k' == 1, every increment in length 'n' doubles the number of results.

public class NumbersWithSameConsecutiveDifferences_Backtracking {

    // Approach:
    // Using depth first search to append 0 - 9 to each number starting from 1 to 9 to form possible numbers,
    // until the numbers have 'n' digits. Note that starting from 1 to 9 as leading zero is not valid.
    // If the next digit is not valid, either less than 0, or more than 9, we backtrack to try another number.

    // Wrapper method to initiate the recursive method.
    public int[] numsSameConsecDiff(int n, int k) {
        List<Integer> result = new ArrayList<>();
        // Initiate the recursive method with the first digit from 1 to 9.
        for (int i = 1; i <= 9; i++)
            findNumber(n, k, i, 1, i, result);

        // Convert the queue to an int array.
        return result.stream().mapToInt(i -> i).toArray();
    }

    // Recursive method.
    private void findNumber(int n, int k, int number, int digit, int lastDigit, List<Integer> list) {

        // Breaking condition, when the number has 'n' length.
        if (digit == n) {
            list.add(number);
            return;
        }
        // Check if the lastDigit with positive and negative k difference is possible.
        // (i.e. 15 with k = 4, to append 1 to form 151 or 9 to form 159).
        // If positive k is possible, append lastDigit + k to the number, and call the method for the next digit.
        if (lastDigit + k <= 9)
            findNumber(n, k, number * 10 + (lastDigit + k), digit + 1, lastDigit + k, list);

        // If negative k is possible, append lastDigit - k to the number, and call the method for the next digit.
        // Additionally, skip this if k == 0 as it can result in duplicates.
        if (k > 0 && lastDigit - k >= 0)
            findNumber(n, k, number * 10 + (lastDigit - k), digit + 1, lastDigit - k, list);
    }
}

package com.cheehwatang.leetcode;

import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;
import java.util.Queue;

// Time Complexity  : O(2^n),
// where 'n' is the length of the integer.
// The worst case scenario is when 'k' == 1, every increment in length 'n' doubles the number of integers to check.
//
// Space Complexity : O(2^n),
// where 'n' is the length of the integer.
// The worst case scenario is when 'k' == 1, every increment in length 'n' doubles the number of results.

public class NumbersWithSameConsecutiveDifferences_BFS {

    // Approach:
    // Using breadth first search (BFS) to append 0 - 9 to each number starting from 1 to 9 to form possible numbers,
    // until the numbers have 'n' digits. Note that starting from 1 to 9 as leading zero is not valid.

    public int[] numsSameConsecDiff(int n, int k) {
        List<Integer> result = new ArrayList<>();

        // Starting from 1 to 9 as the first digit.
        for (int i = 1; i <= 9; i++) {
            Queue<Integer> queue = new LinkedList<>();
            queue.offer(i);
            // As the first element is at length of 1.
            int length = 1;
            // Continue to add append the digits until length of 'n'.
            while (++length <= n) {
                // Make sure to set store the queue size in a variable first.
                // This is to prevent the loop for terminating prematurely as we are polling elements from the queue.
                // Each length, append the digit to all the numbers that is in the queue.
                for (int j = 0, l = queue.size(); j < l; j++) {
                    int number = queue.poll();

                    // Get the last digit of the number,
                    // to check whether the 'k' difference is positive or negative.
                    // (i.e. 15 with k = 4, to append 1 to form 151 or 9 to form 159)
                    int lastDigit = number % 10;

                    // If positive k is possible, add to the queue.
                    if (lastDigit + k <= 9)
                        queue.offer(number * 10 + (lastDigit + k));

                    // If negative k is possible, add to the queue.
                    // Additionally, skip this if k == 0 as it can result in duplicates.
                    if (k > 0 && lastDigit - k >= 0)
                        queue.offer(number * 10 + (lastDigit - k));
                }
            }
            result.addAll(queue);
        }
        // Convert the queue to an int array.
        return result.stream().mapToInt(i -> i).toArray();
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the input 'n'.
// We traverse from 3 to 'n' to calculate the n-th tribonacci number.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the input.

public class NthTribonacciNumber_Iterative {

    // Approach:
    // We use the iterative method, using the variable 'first', 'second' and 'third' to keep track.

    public int tribonacci(int n) {
        if (n == 0 || n == 1) return n;
        if (n == 2) return 1;

        // As we need both 'n - 1', 'n - 2' and 'n - 3' to start, record 'first', 'second' and 'third', respectively.
        // For each iteration until n, sum all three numbers and replace the numbers.
        int first = 1;
        int second = 1;
        int third = 0;
        int result = 0;
        for (int i = 3; i <= n; i++) {
            result = first + second + third;
            third = second;
            second = first;
            first = result;
        }
        return result;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the input 'n'.
// The recursive call stack has a maximum height of 'n'.
//
// Space Complexity : O(n),
// where 'n' is the input 'n'.
// We use a memo of size 'n' to store the tribonacci numbers.
// Additionally, the recursive call stack has a maximum height of 'n'.

public class NthTribonacciNumber_Recursive {

    // Approach:
    // We use the recursive method, using the 'memo' keep track of the calculated number to lower the time complexity.

    public int tribonacci(int n) {

        // Use an integer array as 'memo' to record the results that was calculated.
        // This is so to not repeat the same calculation over the recursive calls.
        int[] memo = new int[n + 1];
        return tribonacci(n, memo);
    }

    private int tribonacci(int n, int[] memo) {
        if (n == 0 || n == 1) return n;
        if (n == 2) return 1;

        // Record the first three element in the Fibonacci sequence.
        memo[1] = 1;
        memo[2] = 1;

        // If the ways for n is not recorded in the 'memo' yet, then calculate and record the result into the memo.
        if (memo[n] == 0) {
            memo[n] = tribonacci(n - 1, memo) + tribonacci(n - 2, memo) + tribonacci(n - 3, memo);
        }
        return memo[n];
    }
}

