// Time Complexity  : O(n^2),
// where 'n' is the length of string 's'.
// We traverse the string 's' with nested for-loop.
//
// Space Complexity : O(n^2),
// where 'n' is the length of string 's'.
// We use a table to record if the particular 'start' and 'end' pointer substring is a palindrome.

public class LongestPalindromicSubstring_DynamicProgramming {

    // Approach:
    // Using dynamic programming to store the palindrome was found.
    // If the inner substring is a palindrome, and if 'start' and 'end' pointers have the same character,
    // we can be sure that the substring from 'start' to 'end' is a palindrome.
    // For Example:
    // s = "racecar"
    // Checking each character, we know 1 character itself is a palindrome, here we focus on "e" in the middle.
    // - "cec", we know "e" is a palindrome, and both "c" and "c" is the same, so this is a palindrome.
    // - "aceca", we know "cec" is a palindrome from previous check, and both "a" and "a" is the same.
    // - "racecar", we know "aceca" is a palindrome, and both "r" and "r" is the same,
    //
    // So we have found the longest palindrome, by building a table from length of 1 to s.length().

    public String longestPalindrome(String s) {
        int n = s.length();
        // The row represents the 'start' and column represents the 'end' pointer.
        boolean[][] table = new boolean[n][n];

        // Rather than storing the substring when a longer palindrome is found,
        // it is lower time-complexity and lower memory-complexity when storing just the pointers indicating the palindrome.
        // We only get the substring at the end when returning the result.
        int start = 0;
        int end = 0;
        for (int length = 0; length < n; length++) {
            for (int index = 0; index + length < n; index++) {
                // 'index' indicates the 'start' and 'index' + 'length' indicates the 'end'.
                // Check if charAt(start) == charAt(end), and whether the inner substring is a palindrome.
                table[index][index + length] = s.charAt(index) == s.charAt(index + length) &&
                        (length < 2 || table[index + 1][index + length - 1]);
                // If it is a palindrome, update the 'start' and 'end'.
                if (table[index][index + length] && length > end - start) {
                    start = index;
                    end = index + length;
                }
            }
        }
        // The substring method is from start (inclusive) to end (exclusive).
        // So we need "end + 1" to include the character at 'end'.
        return s.substring(start, end + 1);
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n^3),
// where 'n' is the length of string 's'.
// We traverse the string 's' with a nested for-loop to check every substrings if they are palindromes,
// with each checking for palindromes introducing an addition O(n) time complexity.
//
//
// Space Complexity : O(n),
// where 'n' is the length of string 's'.
// The maximum length of the result is length 'n'.

public class LongestPalindromicSubstring_TwoPointers1 {

    // Approach:
    // When it comes to substring, first came to mind is two pointers.
    // For palindrome, we can check for palindrome from outside in or from centre out.
    // For each character, we check for the longest possible palindrome from the start of 's' to that character (outside in).

    public String longestPalindrome(String s) {

        // Rather than storing the substring when a longer palindrome is found,
        // it is lower time-complexity and lower memory-complexity when storing just the pointers indicating the palindrome.
        // We only get the substring at the end when returning the result.
        int start = 0;
        int end = 0;
        int maxLength = 1;
        for (int right = 1; right < s.length(); right++) {
            int left = 0;
            // Continue to check for palindrome only if the pointers is greater than 'maxLength'.
            while (left < right && right - left + 1 > maxLength) {
                if (isPalindrome(s, left, right)) {
                    maxLength = right - left + 1;
                    start = left;
                    end = right;
                }
                left++;
            }
        }
        // The substring method is from start (inclusive) to end (exclusive).
        // So we need "end + 1" to include the character at 'end'.
        return s.substring(start, end + 1);
    }

    // Method to check for palindrome in the substring between 'start' and 'end'.
    private boolean isPalindrome(String str, int start, int end) {
        while (start < end) {
            if (str.charAt(start++) != str.charAt(end--)) return false;
        }
        return true;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n^2),
// where 'n' is the length of string 's'.
// We traverse the string 's', with each index checking the longest possible palindrome
// with the index as the center of the palindrome.
//
// Space Complexity : O(n),
// where 'n' is the length of string 's'.
// The maximum length of the result is length 'n'.

public class LongestPalindromicSubstring_TwoPointers2 {

    // Approach:
    // When it comes to substring, first came to mind is two pointers.
    // For palindrome, we can check for palindrome from outside in or from centre out.
    // For each character, we check for the longest possible palindrome when expanding from the centre.

    public String longestPalindrome(String s) {

        // Rather than storing the substring when a longer palindrome is found,
        // it is lower time-complexity and lower memory-complexity when storing just the pointers indicating the palindrome.
        // We only get the substring at the end when returning the result.
        int start = 0;
        int end = 0;

        for (int i = 0; i < s.length(); i++) {
            // Check for the longer palindrome, for both odd and even length of palindrome.
            int length = Math.max(expandAroundCentre(s, i, i), expandAroundCentre(s, i, i + 1));

            // If a longer palindrome is found, record the start and end index.
            if (length > end - start + 1) {
                start = i - (length - 1) / 2;
                end = i + length / 2;
            }
        }
        // The substring method is from start (inclusive) to end (exclusive).
        // So we need "end + 1" to include the character at 'end'.
        return s.substring(start, end + 1);
    }

    // Method for checking palindrome when expanding from the centre.
    private int expandAroundCentre(String s, int left, int right) {
        while (left >= 0 && right < s.length() && s.charAt(left) == s.charAt(right)) {
            left--;
            right++;
        }
        // As the while loop when the pointers are at the non-palindromic position (-1 for left, +1 for right),
        // we subtract 2.
        // However, as the length is end - start + 1, the length equation below is supposedly
        // right - left - 2 + 1.
        return right - left - 1;
    }
}

