import java.util.HashMap;
import java.util.Map;

// Time Complexity  : O(n),
// where 'n' is the length of 'nums'.
// We traverse 'nums' to record the difference of integer from the 'target',
// with the worst case being iterating through 'nums'.
//
// Space Complexity : O(n),
// where 'n' is the length of 'nums'.
// The maximum size of the HashMap scales linearly with the length of 'nums'.

public class TwoSum_HashTable {

    // Approach:
    // Since we know there is only one correct combination to get 'target', we can use HashMap to keep track of
    // the integer and the index.
    //
    // We need to account for 2 scenarios:
    // 1. Solution involves 2 unique integer value (Example 1).
    // 2. Solution involves same integer value but different elements (Example 2).
    //
    // Using a HashMap, Scenario 1 is straightforward as the solution involves 2 unique integers.
    // For Scenario 2, we only need to keep track of the first occurrence of the integer.
    // When the second occurrence is checked to achieve 'target', we can record the index for both elements.

    public int[] twoSum(int[] nums, int target) {

        int[] result = new int[2];

        // HashMap with key storing the Integer from 'nums', while value storing the index number.
        Map<Integer, Integer> map = new HashMap<>();

        // Traverse the 'nums'.
        for (int i = 0; i < nums.length; i++) {
            // Check if the HashMap contains the 'difference'.
            // If we found the 'difference' in the HashMap, then we have found our unique solution.
            int difference = target - nums[i];
            if (map.containsKey(difference)) {
                result[0] = i;
                result[1] = map.get(difference);
                break;
            }
            // Else, we record the Integer and index to check later.
            map.put(nums[i], i);
        }
        return result;
    }
}

package com.cheehwatang.leetcode;

import java.util.LinkedList;
import java.util.Queue;

// Time Complexity  : O(n),
// where 'n' is the maximum size of the 'secondaryQueue', when either the top() or pop() is called on an empty 'mainQueue'.
// The push() and empty() methods have O(1) time complexity.
//
// Space Complexity : O(m + n),
// where 'n' is the maximum size of the 'secondaryQueue' and 'm' is the maximum size of the 'mainQueue'.

public class ImplementStackUsingQueues {

    // Approach:
    // A stack is last in first out (LIFO), meaning the last element pushed to the stack is the
    // first element to pop from the stack.
    // A queue is first in first out (FIFO), meaning the first element offered to the queue is the
    // first element to poll from the queue.
    // To achieve the behavior of a stack, we can use a queue ('mainQueue') to maintain the top element of the stack,
    // and another queue ('secondaryQueue') to store the other elements in the stack.
    //
    // When push() is called, we shift the top element in the 'mainQueue' (if any) to the 'secondaryQueue',
    // then only we push the new element to the 'mainQueue'.
    // In this case, the 'secondaryQueue' acts as a storage for the elements.
    //
    // Each time pop() or top() is called, we return the top element from the 'mainQueue'.
    // However, if the 'mainQueue' is empty, we shift all the elements except one from 'secondaryQueue' to the 'mainQueue',
    // then swap the two queues, before performing the pop() or top() operation.

    // Set both 'mainQueue' and 'secondaryQueue' to private
    // as only the constructor and the push(), pop(), peek() and empty() methods is accessible by other classes.
    private Queue<Integer> mainQueue;
    private Queue<Integer> secondaryQueue;

    // Constructor to create new queue for the class variables.
    // Note that we can keep the constructor empty, and declare the new queue directly for the class variables.
    public ImplementStackUsingQueues() {
        mainQueue = new LinkedList<>();
        secondaryQueue = new LinkedList<>();
    }

    public void push(int x) {
        // If there is an element in the 'mainQueue', shift the element to the 'secondaryQueue'.
        if (!mainQueue.isEmpty()) secondaryQueue.offer(mainQueue.poll());

        // Offer the new element to the 'mainQueue'.
        mainQueue.offer(x);
    }

    public int pop() {
        // If there is no elements in the 'mainQueue', shift the elements for the 'mainQueue' to have the top element.
        if (mainQueue.isEmpty()) shiftElements();

        // Return the top element from the 'mainQueue'.
        return mainQueue.poll();
    }

    public int top() {
        // If there is no elements in the 'mainQueue', shift the elements for the 'mainQueue' to have the top element.
        if (mainQueue.isEmpty()) shiftElements();

        // Get the value of the top element from the 'mainQueue'.
        return mainQueue.peek();
    }

    public boolean empty() {
        return mainQueue.isEmpty() && secondaryQueue.isEmpty();
    }

    // Since both pop() and top() share the same method if the 'mainQueue' is empty,
    // extract the method to a private method.
    private void shiftElements() {
        // Swap the 'mainQueue' and the 'secondaryQueue'.
        Queue<Integer> temp = mainQueue;
        mainQueue = secondaryQueue;
        secondaryQueue = temp;

        // Shift all the elements except one from the 'mainQueue' to the 'secondaryQueue'.
        while (mainQueue.size() > 1) secondaryQueue.offer(mainQueue.poll());
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(m * n * k),
// where 'm' is the number of rows in 'board', 'n' is the number of columns in 'board', and 'k' is the length of 'word'.
// This is because that we traverse the whole matrix.
// At each position in the 'board', where check a maximum of length 'k' of 'word'.
//
// Space Complexity : O(m * n),
// where 'm' is the number of rows in 'board', and 'n' is the number of columns in 'board'.
// This is due to the boolean table we use to track the visited positions/nodes.
// If we use either bitmasking or changing the 'board' to record the visited nodes,
// then the space complexity will be the recursive call stack, which has a maximum height of 'k', the length of 'word'.

public class WordSearch {

    // Approach:
    // For every position on the 'board',
    // perform depth first search (DFS) and backtracking to check if 'word' is in the 'board',
    // with the help of a boolean matrix to keep track of the visited positions.

    // Main method to traverse through 'board' and initiate DFS.
    public boolean exist(char[][] board, String word) {
        char[] chars = word.toCharArray();
        // As we are using backtracking, we can just use a single boolean matrix to keep track of the visited nodes.
        boolean[][] visited = new boolean[board.length][board[0].length];
        for (int row = 0; row < board.length; row++) {
            for (int column = 0; column < board[0].length; column++) {
                // If the recursive DFS method successfully traverse the 'word' in the 'board',
                // then return true.
                if (dfs(board, chars, row, column, 0, visited)) return true;
            }
        }
        // If we search the whole 'board' but did not find the 'word', then return false.
        return false;
    }

    // Depth First Search (DFS) recursive method.
    private boolean dfs(char[][] board, char[] chars, int row, int column, int position, boolean[][] visited) {
        // If we have successfully found all the letters in 'word', then return true.
        if (position == chars.length) return true;

        // If the 'row' and 'column' is out of bound, or is already visited previously, return false.
        if (row < 0 || row >= board.length || column < 0 || column >= board[0].length || visited[row][column]) return false;
        // If the character is different and does not match, return false.
        if (board[row][column] != chars[position]) return false;

        // Before checking all four directions for the next letter, set the current position as visited,
        // so we do not accidentally revisit the same position twice.
        visited[row][column] = true;

        // Check all four directions.
        boolean isPathExist = dfs(board, chars, row + 1, column, position + 1, visited) ||
                dfs(board, chars, row - 1, column, position + 1, visited) ||
                dfs(board, chars, row, column + 1, position + 1, visited) ||
                dfs(board, chars, row, column - 1, position + 1, visited);
        // For backtracking, we set the visited position back to false.
        visited[row][column] = false;
        // Return if any of the recursive calls successfully return true.
        return isPathExist;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n + 20001),
// where 'n' is the length of 'nums'.
// The counting array creation and the counting array traversal has time complexity O(20001).
// Depending the size of input array 'nums', this could be significant.
// Next, we traverse the array 'nums' to perform counting sort, with linear time complexity.
//
// Space Complexity : O(1),
// as the counting array has a fixed size of 20001, regardless of the size of the input.

public class ArrayPartition_CountingSort_Greedy {

    // Approach:
    // From the problem, we know that the best approach is to pair the numbers with the least difference,
    // and sum the lower number of the pair.
    // This is the greedy approach, as we only consider the lower number of the pair,
    // regardless on the value, as we know this would lead to the maximum sum.
    //
    // With that understanding, we can perform counting sort on the numbers in 'nums'.
    // Then, we sum the number in an alternate manner while traversing the counting array.
    // Note: The counting sort approach works because we know the possible range of the numbers.

    public int arrayPairSum(int[] nums) {
        // As the constraint stated that "-10e4 <= nums[i] <= 10e4",
        // thus the counting array needed to account the range.
        int[] counting = new int[20001];

        // Perform counting sort, recording the frequency of each number in 'nums'.
        // As the range includes the negative numbers, we offset the counting array by 10000.
        for (int number : nums) counting[number + 10000]++;

        // 'count' flag to keep track which number to sum.
        boolean count = true;
        int sum = 0;
        for (int i = 0; i < counting.length; i++) {
            // As counting[i] represents the frequency, we use a while loop to keep checking until 0.
            while (counting[i] > 0) {
                // If the flag 'count' is true, we sum the number.
                // Note: we need to consider the offset of 10000 we performed earlier.
                if (count) sum += (i - 10000);

                counting[i]--;
                // Alternate the flag for each number.
                count = !count;
            }
        }
        return sum;
    }
}

package com.cheehwatang.leetcode;

import java.util.Arrays;

// Time Complexity  : O(n logn),
// where 'n' is the length of 'nums'.
// The Arrays.sort() function implements the Dual-Pivot Quicksort, which has O(n logn) time complexity.
// We traverse the 'nums' array once to sum the even-indexed numbers, which results in O(n) time complexity.
// Thus, the time complexity of the function is O(n logn) due to the sorting function.
//
// Space Complexity : O(1),
// as the auxiliary spaced used is independent of the input size.

public class ArrayPartition_Sorting_Greedy {

    // Approach:
    // From the problem, we know that the best approach is to pair the numbers with the least difference,
    // and sum the lower number of the pair.
    // This is the greedy approach, as we only consider the lower number of the pair,
    // regardless on the value, as we know this would lead to the maximum sum.
    //
    // With that understanding, we can sort the numbers in ascending order.
    // Then, we only sum the even-indexed number, which is the lower number of the pair.

    public int arrayPairSum(int[] nums) {
        // Sort the 'nums' array.
        Arrays.sort(nums);

        int sum = 0;
        // Sum the even-indexed number.
        for (int i = 0; i < nums.length; i += 2) {
            sum += nums[i];
        }
        return sum;
    }
}

