import java.util.HashMap;
import java.util.Map;

// Time Complexity  : O(n),
// where 'n' is the length of 'nums'.
// We traverse the 'nums' array, with the worst-case having to traverse the whole array,
// which has a linear time complexity.
//
// Space Complexity : O(n),
// where 'n' is the length of 'nums'.
// The worst case is when all the integers in 'nums' are unique,
// thus resulting in the HashMap having the same size as the input 'nums'.

public class ContainsDuplicateII_HashMap {

    // Approach:
    // We use a HashMap to keep track of the last seen index of the integer.
    // Since we only concern about the i - j <= k, any prior j indices is not needed.

    public boolean containsNearbyDuplicate(int[] nums, int k) {
        // If k is 0, then i and j cannot be distinct.
        if (k == 0) return false;

        // Set up the HashMap, with key = integer in 'nums' and value = index.
        Map<Integer, Integer> map = new HashMap<>();

        // Traverse the 'nums'.
        for (int i = 0; i < nums.length; i++) {
            int integer = nums[i];
            // If contains key and i - j <= k, return true.
            if (map.containsKey(integer) && i - map.get(integer) <= k) {
                return true;
            }
            // Either put a new <Integer, Index> pair, or update index of existing integer in the HashMap.
            map.put(integer, i);
        }
        // If successfully traverse the whole array, meaning we fail to find any integers fulfilling the conditions.
        return false;
    }
}

package com.cheehwatang.leetcode;

import java.util.HashSet;
import java.util.Set;

// Time Complexity  : O(n),
// where 'n' is the length of 'nums'.
// We traverse the 'nums' array, with the worst-case having to traverse the whole array,
// which has a linear time complexity.
//
// Space Complexity : O(k),
// where 'k' is the input value 'k'.
// At any one time, the HashSet has a maximum size of 'k', and the integers outside the sliding window is removed.

public class ContainsDuplicateII_SlidingWindow {

    // Approach:
    // We use the sliding window technique.
    // Traversing from left to right, we use a HashSet to store the integers that we saw.
    // If the same integer is seen again, we have found the duplicate.
    // Then, we update the window again to be within 'k' index from 'index'.

    public boolean containsNearbyDuplicate(int[] nums, int k) {
        // If k is 0, then i and j cannot be distinct.
        if (k == 0) return false;

        // Set up the HashSet.
        Set<Integer> slidingWindow = new HashSet<>();

        // Start sliding the slidingWindow to the right.
        for (int index = 0; index < nums.length; index++) {
            // Return true when found duplicates in the slidingWindow.
            if (slidingWindow.contains(nums[index]))
                return true;

            // Update the state of the window, but removing the leftmost integer and add the new integer.
            if (index >= k)
                slidingWindow.remove(nums[index - k]);

            slidingWindow.add(nums[index]);
        }
        // If successfully traverse the whole array, meaning we fail to find any integers fulfilling the conditions.
        return false;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of 's'.
// We use two pointers as sliding window to traverse the string 's' once.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the input.

public class LongestSubstringWithoutRepeatingCharacters {

    // Approach:
    // Using sliding window technique with two pointers 'front' and 'back',
    // and an array to store the latest index of the character found.

    public int lengthOfLongestSubstring(String s) {

        // The standard ASCII characters range from 0 to 127.
        int[] characterIndex = new int[128];
        int max = 0;
        for (int front = 0, back = 0; front < s.length(); front++) {
            char character = s.charAt(front);
            // Get the latest 'back' index
            // if there is a character index (non-zero) that was recorded in the 'characterIndex' array.
            back = Math.max(back, characterIndex[character]);

            // Update 'max' for the longer substring without repeating characters.
            max = Math.max(max, front - back + 1);

            // The index is recorded as "front + 1" is because it will be the start of the substring,
            // when the 'back' index above is updated.
            characterIndex[character] = front + 1;
        }
        return max;
    }
}

