import java.util.ArrayList;
import java.util.List;

// Time Complexity  : O(k),
// where 'k' is the total number of edges between the vertices.
// This is because we use depth-first search to traverse every edge until we find 'destination'.
//
// Space Complexity : O(k),
// where 'k' is the total number of edges between the vertices.
// The maximum size of the 'adjacencyList' (and its nested lists) and the 'queue' during depth-first search
// is the number of edges in 'edges'.

public class FindIfPathExistsInGraph_DFS_Recursive {

    // Approach:
    // First map the 'edges' onto an adjacency list, which is the list of every node and its adjacent nodes or vertices.
    // Once done, we can use depth-first search to start searching from the 'source' vertex,
    // and check every connected vertices paths for 'destination'.
    // Here, we use the recursive implementation of the depth-first search.

    // Wrapper method to set up and initialize the recursive method.
    public boolean validPath(int n, int[][] edges, int source, int destination) {

        // Using the 'edges' to build an adjacency list of all vertices.
        // As the vertex numbers are from 0 to 'n', we use an ArrayList here.
        // However, if we are not certain of the vertices, we use HashMap with the vertex as key,
        // and ArrayList or HashSet as value.
        List<List<Integer>> nodeEdges = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            // Note to create new instances of ArrayList for each vertex.
            // Using Arrays.fill() result in all vertices pointing to the same ArrayList.
            nodeEdges.add(new ArrayList<>());
        }
        // Build the adjacency list. Take note to add both directions, as it is an undirected graph.
        for (int[] edge : edges) {
            nodeEdges.get(edge[0]).add(edge[1]);
            nodeEdges.get(edge[1]).add(edge[0]);
        }

        // Call the depth-first search recursive method, with the 'source', 'destination', the adjacency list,
        // and the 'visitedVertices' table.
        return dfs(source, destination, nodeEdges, new boolean[n]);
    }

    // Recursive method for the depth-first search.
    private boolean dfs(int source, int destination, List<List<Integer>> nodeEdges, boolean[] visitedVertices) {
        // If we have found the 'destination', return true.
        if (source == destination) return true;
        // Skip to the next vertex (if any), if this vertex is visited.
        if (visitedVertices[source]) return false;
        visitedVertices[source] = true;
        for (Integer node : nodeEdges.get(source)) {
            // If we have found the 'destination', return true.
            if (dfs(node, destination, nodeEdges, visitedVertices)) return true;
        }
        // If all the connected vertices are checked but path not found to 'destination', return false.
        return false;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(m logn),
// where 'm' is the total number of find() and union() functions called, and 'n' is the number of vertices.
// The naive approach of the union-find, with both the find() and union() having the time complexity of O(logn).
// With Union by Rank and Path Compression, the time complexity is amortized to almost linear complexity.
//
// Space Complexity : O(n),
// where 'n' is the number of vertices.
// We used an array to keep track of the set representative (parent) for each vertex.
// As we used Union by Rank, we have an additional array of size 'n'.

public class FindIfPathExistsInGraph_UnionFind {

    // Approach:
    // Using the Disjoint Set Data Structure (Union-Find Data Structure) to
    // connect all the connected vertices into disjoint sets.
    // If the 'source' and 'destination' are in the same disjoint set, then they have a valid path.

    // Main function to check if valid path exist from 'source' to 'destination'.
    public boolean validPath(int n, int[][] edges, int source, int destination) {
        // The 'parent' array keeps track of the set representative (parent) of each vertex.
        int[] parent = new int[n];
        // The 'rank' array keeps track of the rank of each vertex, starting at rank 0.
        int[] rank = new int[n];
        // Initialize the parent[], by setting all the set representatives (parents) to itself.
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }

        // For all the edges, merge (union) the disjoint set of the two connected vertices.
        for (int[] edge : edges) {
            union(edge[0], edge[1], parent, rank);
        }

        // If the 'source' and 'destination' are in the same disjoint set, then they have a valid path.
        return find(source, parent) == find(destination, parent);
    }

    // Function to find the set representative.
    private int find(int vertex, int[] parent) {
        // We have found the set representative when the vertex points back to itself.
        if (parent[vertex] == vertex) return vertex;
        // As part of the Path Compression, we set the vertices along the path to the set representative.
        return parent[vertex] = find(parent[vertex], parent);
    }

    // Function to merge the two disjoint set.
    private void union(int vertex1, int vertex2, int[] parent, int[] rank) {
        // Get the set representative of the two vertices.
        int find1 = find(vertex1, parent);
        int find2 = find(vertex2, parent);

        // If the two vertices is in the same disjoint set, skip.
        if (find1 == find2) return;

        // Here we use Union by Rank.
        // So, join the parent with the lower rank to the one with higher rank.
        if (rank[find1] > rank[find2]) {
            parent[find2] = find1;
        } else {
            parent[find1] = find2;
            // If both are of the same rank, increase the rank of the set representative by 1.
            if (rank[find1] == rank[find2]) rank[find2]++;
        }
    }
}

