/**
 * Definition for singly-linked list.
 * public class ListNode {
 *     int val;
 *     ListNode next;
 *     ListNode() {}
 *     ListNode(int val) { this.val = val; }
 *     ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */
// Note: Remember to set up a ListNode class as the same folder as the swapPairs() function.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the linked list.
// We traverse the linked list once to swap the node pairs.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent on the length of the linked list.

public class SwapNodesInPairs {

    // Approach:
    // Traverse the linked list, using a 'current' ListNode to keep track of the first node of the pair, and
    // a 'parent' ListNode to keep track of the parent node of the pair.
    // For each pair, perform the swap using a 'temp' ListNode to store the second node of the pair.
    // Then, link the 'parent' ListNode to the first node ('temp') of the swapped pair.
    //
    // Note: We need to handle the edge case, for the first pair when the 'parent' ListNode is null,
    //       and set the new head.

    public ListNode swapPairs(ListNode head) {
        // If there is no pair, return head.
        if (head == null || head.next == null) return head;

        // 'current' pointer to traverse the linked list.
        ListNode current = head;
        // Start with the 'parent' ListNode as null.
        ListNode parent = null;
        // Continue to traverse and swap nodes if there are pairs.
        while(current != null && current.next != null) {
            // Using the 'temp' variable to swap nodes.
            // Note: After swapping, 'temp' becomes the first node of the pair,
            //       and 'current' becomes the second node of the pair.
            ListNode temp = current.next;
            current.next = temp.next;
            temp.next = current;

            // Handle the first pair, when the 'parent' is null, set the 'temp' as the new head of the linked list.
            if (parent == null) {
                head = temp;
            } else {
                // Else, link the 'parent' ListNode with the new first node after swapping.
                parent.next = temp;
            }

            // Shift the pointers accordingly, and continue to traverse and swap the elements.
            parent = current;
            current = current.next;
        }
        return head;
    }
}

package com.cheehwatang.leetcode;

/**
 * Definition for singly-linked list.
 * public class ListNode {
 * int val;
 * ListNode next;
 * ListNode() {}
 * ListNode(int val) { this.val = val; }
 * ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */
// Note: Remember to set up a ListNode class as the same folder as the swapPairs() function.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the linked list.
// With recursion, the recursive call stack has a height that grows linearly
// with the input linked list.
//
// Space Complexity : O(n),
// where 'n' is the number of nodes in the linked list.
// While the auxiliary space used is independent on the length of the linked list,
// the recursive call stack results in O(n).

public class SwapNodesInPairs_Recursion {

    // Approach:
    // Using recursion, swap the ListNodes in the pair and return the new first ListNode of the pair,
    // and link the second node (head.next) to the next pair by calling the swapPairs() function
    // with the first node of the next pair (head.next.next).

    public ListNode swapPairs(ListNode head) {
        // If there is no pair, return head.
        if (head == null || head.next == null) return head;

        // Swap the ListNodes in the pair.
        ListNode newHead = head.next;
        // Link the second node ('head' ListNode) to the next pair,
        // by recursively calling the swapPairs() function with the head of the next pair.
        head.next = swapPairs(head.next.next);
        newHead.next = head;

        // Return the first node of the pair.
        return newHead;
    }
}

package com.cheehwatang.leetcode;

import java.util.Arrays;

// Time Complexity  : O(n logn),
// where 'n' is the number of ice cream bars (size of 'costs').
// As we sort the array, the Arrays.sort() method uses the Dual-Pivot Quicksort,
// which has an average performance of O(n logn).
//
// Space Complexity : O(1),
// as we only use variables that are independent of the size of the input.

public class MaximumIceCreamBars {

    // Approach:
    // Since we can buy the ice cream bars in any order, we would always buy the cheapest ice cream bars first.
    // As such, we would first sort the 'costs' in ascending order.
    // Then we reduce the 'coins' for each ice cream bar until unable to buy another one.
    // This is also known as Greedy Algorithm as we always buy the cheapest ice cream bar first.

    public int maxIceCream(int[] costs, int coins) {
        // By default, Arrays.sort() sorts the array in ascending order.
        Arrays.sort(costs);

        int numberOfIceCream = 0;
        // For each ice cream bar, from the cheapest to the most expensive,
        for (int cost : costs) {
            // If we do not have enough 'coins', stop buying and break from the loop.
            if (coins < cost) break;
            // Else, buy the ice cream bar.
            coins -= cost;
            numberOfIceCream++;
        }

        return numberOfIceCream;
    }
}

package com.cheehwatang.leetcode;

import java.util.Arrays;

// Time Complexity  : O(n logn),
// where 'n' is the length of 'plantTime' or 'growTime'.
// We first traverse both arrays to pair the plant time and grow time, with O(n) time complexity.
// Then, we sort the new array with Arrays.sort function with O(n logn) time complexity.
// Lastly, we traverse the sorted array to get the earliest possible day, with O(n) time complexity.
// Thus, the time complexity is O(n logn).
//
// Space Complexity : O(n),
// where 'n' is the length of 'plantTime' or 'growTime'.
// We use an array of length 'n' to store the pair of plant time and grow time.

public class EarliestPossibleDayOfFullBloom {

    // Approach:
    // For this problem, it is important to note that, not matter how we choose,
    // we need a minimum of total 'plantTime' for all the flower seeds.
    // So then, the crucial factor is the 'growTime'.
    // To simplify, all the 'growTime' in the example includes the extra day to bloom.
    // For Example, given flowerA and flowerB takes the same 4 days to plant, but 1 day and 3 days to bloom respectively.
    // As such, we plant flowerB first, as it requires longer time to bloom.
    // We know the total 'plantTime' is 4 + 4 == 8.
    // To get the minimum time to bloom, planting the longer bloom time first yield the shortest time in total.
    // (8 + 3 == 11 days) > (9 days == 8 + 1).
    // For that, we noticed that it is a greedy algorithm, since our focus is to plant the longest 'growTime' first.
    //
    // Additionally, we need to sort the 'growTime' in descending order,
    // while keeping in check its corresponding 'plantTime'.
    // We can use a 2D array or a Pair class for the sorting. Here using Pair class for better readability.

    public int earliestFullBloom(int[] plantTime, int[] growTime) {
        int n = plantTime.length;
        Pair[] flowerTime = new Pair[n];
        for (int i = 0; i < n; i++) {
            flowerTime[i] = new Pair(plantTime[i], growTime[i]);
        }
        // Sort the 'growTime' in descending order.
        // The 'plantTime' is not important as flowers with same 'growTime' but different 'plantTime' results in same total time.
        Arrays.sort(flowerTime, (a, b) -> b.growTime - a.growTime);

        // 'plantingDay' is the total days used for planting up to now,
        // which together with the current flower's 'plantTime' and 'growTime' result in a total time up to this flower.
        // This then is checked if we have a greater 'totalDays',
        // as it is possible for the previous flower 'totalDays' to be greatest.
        // For Example: flowerA with 'plantTime' 1 and 'growTime' 10, and flowerB with 'plantTime' 1 and 'growTime' 1.
        int plantingDay = 0;
        int totalDays = 0;
        for (Pair current : flowerTime) {
            // Check if we have found a greater 'totalDays', and update the days already used for previous plantings.
            totalDays = Math.max(totalDays, plantingDay + current.plantTime + current.growTime);
            plantingDay += current.plantTime;
        }
        // As we start at Day 0 (-1 Day from totalDays), and we need to include an extra day to bloom (+1 Day for totalDays),
        // they cancel out each other (totalDays + 1 - 1 == totalDays).
        return totalDays;
    }

    // Class Pair for sorting and readability.
    class Pair {
        public int plantTime;
        public int growTime;

        Pair(int plantTime, int growTime) {
            this.plantTime = plantTime;
            this.growTime = growTime;
        }
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n^2),
// where 'n' is the input 'n'.
// We iterate from 2 to 'n'.
// Approximating the length of the strings are length 'n',
// traversal of the string for each iteration would result in O(n^2) time complexity.
//
// Space Complexity : O(n),
// where 'n' is the input 'n'.
// The length of the string created is approximately 'n' for each iteration.

public class CountAndSay_Iterative {

    // Approach:
    // Use either String itself, or StringBuilder.
    // For longer string, StringBuilder is faster and uses less memory.
    // Iteratively from 1 to n, check each digit in the countAndSay(n - 1) string using a 'count' variable.
    // Once finish counting, append the 'count' and the digit to the result.

    public String countAndSay(int n) {
        // Base case.
        if (n == 1) return "1";

        String result = "1";
        for (int i = 2; i <= n; i++) {
            // 'say' is the result for countAndSay(i), whereas 'result' is the result for countAndSay(i - 1).
            StringBuilder say = new StringBuilder();
            // Since we start from index 0 in the string, there is no previous digit, so assign -1 to start.
            int prevDigit = -1;
            int count = 0;

            for (char character : result.toCharArray()) {
                int digit = character - '0';
                // If we are at the start of the string, or current digit is the same as previous digit, increase the count.
                if (prevDigit == -1 || digit == prevDigit) count++;

                // Once we found a digit that is different, we can append the 'count' and the 'prevDigit' to 'say'.
                // Restart the 'count' at 1.
                else {
                    say.append(count);
                    say.append(prevDigit);
                    count = 1;
                }
                prevDigit = digit;
            }
            // Since the loop ended with 1 unrecorded sequence, we append them to 'say'.
            say.append(count);
            say.append(prevDigit);
            // Update the 'result' to 'say' and continue the iteration.
            result = say.toString();
        }
        return result;
    }
}

