import java.util.ArrayList;
import java.util.List;

// Time Complexity  : O(j * k),
// where 'j' is the length of 'queries' array, and 'k' is the number of powers of 2 in input 'n'.
// We iterate through 'queries' to get the products,
// with the worst-case being that the product of each query is from the whole range of the possible powers generated from 'n'.
//
// Space Complexity : O(j + k),
// where 'j' is the length of 'queries' array, and 'k' is the number of powers of 2 in input 'n'.
// An array of length 'j' is used to store the result, and a list of length 'k' is use to store the powers.

public class RangeProductQueriesOfPowers {

    // Approach:
    // With the integer 'n', we first need to get all the possible powers of 2.
    // One way is to use an integer variable, 'power', to keep track of the powers of 2 while performing division.
    // For each division of 2, if there is a remainder of 1, we know there is a power of 2 number.
    // Example:
    // n = 5
    // 'power' = 0, 5 % 2 = 1, so the bit at 2^0 == 1, (for next, 5 / 2 = 2)
    // 'power' = 1, 2 % 2 = 0, so the bit at 2^1 == 0, (for next, 2 / 2 = 1)
    // 'power' = 2, 1 % 2 = 1, so the bit at 2^2 == 1,
    // so it will be a 101 binary digit for n = 5.
    //
    // Once we got the list of powers of 2, then we can iterate through the 'queries' for each powers of 2,
    // multiply then input into the 'answers' array.

    public int[] productQueries(int n, int[][] queries) {
        // Since the multiplication may exceed 2^31 (Integer.MAX_VALUE), keep the calculations in long type,
        // only cast to int when inputting into the 'answers' array.
        long modulo = (long) (1e9 + 7);
        List<Integer> powers = new ArrayList<>();
        int power = 0;
        while (n > 0) {
            // Using bit manipulation, n & 1 is to check for odd or even, same as n % 2.
            // If digit at 2^0 == 1, 1 & 1 == 1 meaning it is odd.
            // If digit at 2^0 == 0, 0 & 1 == 0 meaning it is even.
            if ((n & 1) == 1) powers.add((int) Math.pow(2, power));

            // >> is shift right. Each right shift is division by 2, likewise each left shift is multiplication of 2.
            n = n >> 1;
            power++;
        }
        int[] answers = new int[queries.length];
        for (int i = 0; i < queries.length; i++) {
            // Keeping the 'product' in long type even when we are using modulo for each multiplication,
            // is so that the 'product' does not overflow during the multiplication.
            long product = 1;
            for (int j = queries[i][0]; j <= queries[i][1]; j++) {
                product = (product * powers.get(j)) % modulo;
            }
            answers[i] = (int) product;
        }
        return answers;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n + m),
// where 'n' is the length of 'arr1', and 'm' is the length of 'arr2'.
// We traverse 'arr1' and 'arr2' once, results in O(n + m) time complexity.
// Additionally, we traverse all the elements in 'arr1' from the 'counting' array
// as we rebuild the 'arr1' array.
// We can also simplify to time complexity to O(n), as 'arr2' is a subset of 'arr1'.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent on the size of the input 'arr1' and 'arr2'.
// Additionally, we replace the result with 'arr1' instead of creating a new 'result' array.

public class RelativeSortArray_CountingSort_Sorting {

    // Approach:
    // Using counting sort to first record the frequency of each element in 'arr1' into a 'counting' array.
    // Then, we traverse 'arr2' to check the relative position,
    // and input the elements into the result array in ascending index order.
    // After traversing 'arr2', we traverse the 'counting' array to input the remaining elements
    // into the result array in ascending number order.
    //
    // Note: The counting array approach is possible due to the stated constraint of "0 <= arr1[i] <= 1000".

    public int[] relativeSortArray(int[] arr1, int[] arr2) {
        // With the constraint of "0 <= arr1[i] <= 1000", we set up the counting array of size 1001,
        // accounting for the zero-indexing.
        int[] counting = new int[1001];

        // Perform counting sort, with the index representing the number,
        // and counting[i] representing the frequency.
        for (int number : arr1) counting[number]++;

        // Index 'i' is to keep track of the position in the result array.
        // Here, we use 'arr1' as the result array to reduce space complexity when using a new 'result' array.
        // Optional to use a new 'result' array for better readability and clarity.
        int i = 0;
        for (int number : arr2) {
            // For each number in 'arr2', we add the number with counting[i] frequency into the result array.
            while (counting[number] > 0) {
                // Shifting index 'i' each time a number is added to the result.
                arr1[i++] = number;
                counting[number]--;
            }
        }

        // Traverse the 'counting' array to get the remaining numbers that are not in 'arr2'.
        for (int number = 0; number < counting.length; number++) {
            // For each number in 'counting', we add the number 'i' into the result array
            // if the frequency is more than zero.
            while (counting[number] > 0) {
                // Shifting index 'i' each time a number is added to the result.
                arr1[i++] = number;
                counting[number]--;
            }
        }
        // We use 'arr1' as the result array.
        return arr1;
    }
}

package com.cheehwatang.leetcode;

import java.util.TreeMap;

// Time Complexity  : O(n),
// where 'n' is the length of 'arr1', as 'arr2' is a subset of 'arr1'.
// TreeMap.get() function has a time complexity of O(log n).
// With the worst-case being all the numbers in 'arr1' is unique,
// the counting of numbers in 'arr1' and the relative sorting of 'arr1'
// results in the total time complexity of O(n logn), as we perform TreeMap.get() function for each element.
//
// Space Complexity : O(n),
// where 'n' is the length of 'arr1'.
// With the worst-case being all the numbers in 'arr1' is unique,
// the size of the TreeMap grows linearly with the size of the input 'arr1'.

public class RelativeSortArray_HashTable {

    // Approach:
    // TreeMap is a hash table while retaining the ordering of the key element in ascending order by default.
    // Thus, we can count the frequency of the numbers in 'arr1' and retrieve with the TreeMap.get() method.
    // Crucially, we can get the numbers as keys of the TreeMap is ascending order.
    //
    // First, we record the frequency of each element in 'arr1' into the TreeMap.
    // Then, we traverse 'arr2' to check the relative position,
    // and input the elements into the result array in ascending index order.
    // Remove the number from the TreeMap once the frequency is 0.
    // Lastly, we traverse the TreeMap to input the remaining numbers
    // into the result array in ascending number order.

    public int[] relativeSortArray(int[] arr1, int[] arr2) {
        // The key is the number, and value is the frequency.
        TreeMap<Integer, Integer> map = new TreeMap<>();

        // Count the frequency of the numbers in 'arr1'.
        for (int number : arr1) {
            map.put(number, map.getOrDefault(number, 0) + 1);
        }

        // Index 'i' is to keep track of the position in the result array.
        // Here, we use 'arr1' as the result array to reduce space complexity when using a new 'result' array.
        // Optional to use a new 'result' array for better readability and clarity.
        int i = 0;
        for (int number : arr2) {
            // For each number in 'arr2', we get the frequency,
            int frequency = map.getOrDefault(number, 0);
            // and record the number into the result array.
            while (frequency > 0) {
                arr1[i++] = number;
                frequency--;
            }
            // Remove the number from the TreeMap once checked.
            map.remove(number);
        }

        // Traverse the TreeMap keys to get the remaining numbers that are not in 'arr2'.
        // Note: TreeMap.keySet() returns the keys in ascending order.
        for (int number : map.keySet()) {
            // For each number in 'arr2', we get the frequency,
            int frequency = map.get(number);
            // and record the number into the result array.
            while (frequency > 0) {
                arr1[i++] = number;
                frequency--;
            }
        }
        // We use 'arr1' as the result array.
        return arr1;
    }
}

package com.cheehwatang.leetcode;

import java.util.Collections;
import java.util.HashMap;
import java.util.Map;

// Time Complexity  : O(n),
// where 'n' is the size of 'nums'. In fact, it is '3n' as we traversed 'nums' twice and 'map' once,
// assuming worst space complexity for the HashMap equals to 'n'. So, it is simplified as O(n).
//
// Space Complexity : O(n),
// where 'n' is the size of 'nums'.
// The worst case is when all the integers in 'nums' have different remainder to 'space',
// For Example: nums = [1,2,3,4,5], space = 5.
// Even with 'space' == 1e9 + 7, the HashMap only scales to the size of 'nums'.

public class DestroySequentialTargets_HashTable {

    // Approach:
    // Using HashMap to store the remainders of the integers in 'nums' to 'space.
    // If two elements are at index 'x' and 'x + space' respectively, then they are sequential targets,
    // with both targets having the same remainder.
    // Thus, all the sequential targets have the same remainder to 'space'.
    // As such, we need to find the remainder with the most integers and get the minimum integer of that remainder.
    // For Example, nums = [1,2,3,4,5], space = 3,
    // the remainders of 3 are:
    // - 0 (with integer 3),
    // - 1 (with integers 1 and 4), and
    // - 2 (with integers 2 and 5).
    // The remainders with the most integers are remainder 1 and 2,
    // thus getting the minimum integer among 1, 2, 4 and 5 resulting in the minimum integer of 1.

    public int destroyTargets(int[] nums, int space) {
        Map<Integer, Integer> map = new HashMap<>();
        // First count the frequencies of the remainders in the HashMap.
        for (int integer : nums)
            map.put(integer % space, map.getOrDefault(integer % space, 0) + 1);

        // Then get the maximum number of integers for all the remainders.
        int maxTargets = Collections.max(map.values());

        // Finally, get the minimum integer of the remainder(s) with the maximum number of integers.
        int minInteger = Integer.MAX_VALUE;
        for (int integer : nums)
            if (map.get(integer % space) == maxTargets)
                minInteger = Math.min(minInteger, integer);

        return minInteger;
    }
}

