import java.util.Stack;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// We traverse every node in the binary tree
// to find all the root-to-leaf paths and compare to find the smallest string.
//
// Space Complexity : O(m),
// where 'm' is the depth of the tree.
// The maximum size of the 'nodeStack' and the 'pathStack' is the depth of the tree.

public class SmallestStringStartingFromLeaf_DFS_Iterative {

    // Approach:
    // Using depth-first search to find every root-to-leaf paths and
    // compare to find the smallest string lexicographically.
    // Here, the depth-first search is implemented iteratively using stack
    // to keep track of the nodes ('nodeStack') and path ('pathStack').
    // We only compare the strings when we have arrived at the leaf node.

    public String smallestFromLeaf(TreeNode root) {

        // Remember to initialize the 'smallestString' by setting to null.
        // This prevents compile-time error.
        // With that, we also need to check for null later before comparing to find the smallest string.
        // Note: An alternative is the use a string greater than "z" as the value for 'smallestString',
        //       strings such as "|" or "~".
        String smallestString = null;

        // Iterative depth-first search uses stack.
        // Here, we need two stacks to keep track of the nodes ('nodeStack') and paths ('pathStack').
        Stack<TreeNode> nodeStack = new Stack<>();
        Stack<String> pathStack = new Stack<>();
        nodeStack.push(root);
        pathStack.push("");

        // Continue to traverse the binary tree until all nodes are visited.
        while (!nodeStack.isEmpty()) {

            // Get the 'currentNode' and 'currentPath'.
            TreeNode currentNode = nodeStack.pop();
            String currentPath = (char)(currentNode.val + 'a') + pathStack.pop();

            // If we reached at leaf node,
            if (currentNode.left == null && currentNode.right == null) {
                // and 'currentPath' is smaller lexicographically, set 'currentPath' as the new 'smallestString'.
                if (smallestString == null || currentPath.compareTo(smallestString) < 0) {
                    smallestString = currentPath;
                    continue;
                }
            }

            // If we have the left or right child node, add them to the 'nodeStack' along with the 'currentPath'.
            if (currentNode.left != null) {
                nodeStack.push(currentNode.left);
                pathStack.push(currentPath);
            }
            if (currentNode.right != null) {
                nodeStack.push(currentNode.right);
                pathStack.push(currentPath);
            }
        }
        // Once we traverse the whole binary tree, return the smallest string.
        return smallestString;
    }
}

package com.cheehwatang.leetcode;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// We traverse every node in the binary tree
// to find all the root-to-leaf paths and compare to find the smallest string.
//
// Space Complexity : O(m),
// where 'm' is the depth of the tree.
// The maximum size of the recursive call stack is the depth of the tree.

public class SmallestStringStartingFromLeaf_DFS_Recursive {

    // Approach:
    // Using depth-first search to find every root-to-leaf paths and
    // compare to find the smallest string lexicographically.
    // Here, the depth-first search is implemented recursively.
    // We only compare the strings when we have arrived at the leaf node.

    // Main method to initialize and find the smallest string.
    public String smallestFromLeaf(TreeNode root) {
        return smallestFromLeaf(root, "");
    }

    // Recursive method to traverse the binary tree, and compare and return the smallest string.
    private String smallestFromLeaf(TreeNode root, String pathString) {
        // As we design the recursion to visit the left and right child regardless if it is null,
        // we perform the check here if the root is null.
        if (root == null) return "";

        // Insert the letter at the first position of the 'pathString'.
        pathString = (char)(root.val + 'a') + pathString;

        // Traverse the left and the right child nodes, and get the string.
        String leftPath = smallestFromLeaf(root.left, pathString);
        String rightPath = smallestFromLeaf(root.right, pathString);

        // If both left and right child nodes returned non-empty strings,
        // we return the string that is smaller lexicographically.
        if (leftPath.length() > 0 && rightPath.length() > 0)
            return (leftPath.compareTo(rightPath) < 0) ? leftPath : rightPath;
        // If only either left or right is a non-empty string, return that string.
        else if (leftPath.length() > 0)
            return leftPath;
        else if (rightPath.length() > 0)
            return rightPath;
        // If both left and right child nodes are null, we have arrived at the leaf node and return the 'pathString'.
        else
            return pathString;
    }
}

package com.cheehwatang.leetcode;

import java.util.LinkedList;
import java.util.List;
import java.util.Stack;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder as your postorder traversal algorithms.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree, as we are traversing every single node.
//
// Space Complexity : O(n),
// where 'n' is the number of nodes in the tree,
// as we are recording the data of every node into the List.
// The stack only takes up the maximum space of tree height, which is smaller than 'n'.

public class BinaryTreePostorderTraversal_Iterative {

    // Approach:
    // For postorder traversal, we visit the node in the following order:
    // 1. Left node.
    // 2. Right node.
    // 3. Visit the root node, and add the value to the list.
    // Using a LinkedList and adding the 'root' node value at the front of the LinkedList,
    // the first added value is the last visited node in the result.
    //
    // Note: Other than slight variation in the algorithm,
    //       both preorder and postorder traversal also use Stack when implemented iteratively.

    public List<Integer> postorderTraversal(TreeNode root) {

        // As we are adding the value at the front of the list,
        // the use of LinkedList is more efficient than ArrayList,
        // as the addition of node at first position in LinkedList is O(1) time complexity,
        // while addition of node at first position in ArrayList is O(n) time complexity
        // due to the shifting of values in the backing array.
        List<Integer> integerList = new LinkedList<>();

        // If the 'root' is null, we return an empty list.
        if (root == null) return integerList;

        Stack<TreeNode> stack = new Stack<>();
        stack.push(root);

        while (!stack.isEmpty()) {
            root = stack.pop();
            // Since we are adding the value of the 'root' after visiting the 'left' and 'right' nodes,
            // we can insert the 'root' values in the first position, with the first added being the last visited.
            integerList.add(0, root.val);

            // If either 'left' or 'right' nodes are not null, visit that node.
            if (root.left != null) stack.push(root.left);
            if (root.right != null) stack.push(root.right);
        }

        // Once the tree is fully traversed, return the result.
        return integerList;
    }
}

package com.cheehwatang.leetcode;

import java.util.LinkedList;
import java.util.List;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder as your postorder traversal algorithms.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree, as we are traversing every single node.
//
// Space Complexity : O(n),
// where 'n' is the number of nodes in the tree,
// as we are recording the value of every node into the List.
// The recursive call stack only takes up the maximum space of tree height, which is smaller than 'n'.

public class BinaryTreePostorderTraversal_Recursive {

    // Approach:
    // Using recursive function to traverse the tree, visiting the nodes in the order of:
    // 1. Left node (with another recursive call).
    // 2. Right node (with another recursive call).
    // 3. Visit the root node, and add the value to the list.

    // Wrapper method to set up and initialize the recursive function.
    public List<Integer> postorderTraversal(TreeNode root) {
        List<Integer> integerList = new LinkedList<>();
        integerList = postorderTraversal(root, integerList);
        return integerList;
    }

    // Recursive method.
    private List<Integer> postorderTraversal(TreeNode root, List<Integer> integerList) {
        // The base case, for when the root is null.
        if (root == null) return integerList;

        // For postorder traversal, we first visit the left node.
        postorderTraversal(root.left, integerList);
        // Then, we visit the right node.
        postorderTraversal(root.right, integerList);
        // Lastly, we visit the root and add the value of the root to the list.
        integerList.add(root.val);

        // Once done, we return the list.
        return integerList;
    }
}

