// Time Complexity  : O(n),
// where 'n' is the number of pen possible to buy.
// After finding out the number of pen possible to buy, we iterate through the pen numbers to find the count for pencils.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the size of the input.

public class NumberOfWaysToBuyPensAndPencils {

    // Approach:
    // First determine how many pen it is possible to buy.
    // Then for each number of pen, check how many pencil can be bought with the remaining amount of money.

    public long waysToBuyPensPencils(int total, int cost1, int cost2) {
        long count = 0;

        // Determine the number of pen possible.
        int pen = total / cost1;

        // For each number of pen bought, determine how much pencil can be bought with the money left.
        for (int i = 0; i <= pen; i++) {
            int remaining = total - (cost1 * i);
            int pencil = remaining / cost2;
            // The + 1 is to account for the case with 0 pencils.
            count += pencil + 1;
        }
        return count;
    }
}

package com.cheehwatang.leetcode;

import java.util.HashMap;
import java.util.Map;
import java.util.Objects;

// Time Complexity  : O(n),
// where 'n' is the number of words in 's' or the length of 'pattern'.
// We check whether the words in 's' matches the 'pattern'.
//
// Space Complexity : O(n),
// where 'n' is the number of words in 's' or the length of 'pattern'.
// We use HashMap with a maximum size of the number of words in 's'.

public class WordPattern {

    // Approach:
    // Using HashMap to record the index of the word in 's' and letter in 'pattern'.
    // If the previous index of the word and letter is different, then the word and letter does not match.
    // For example, pattern = "aaba", s = "alice alice bob bob",
    // 1. Index = 0, the previous index for both word 'alice' and letter 'a' are null, so is the same.
    // 2. Index = 1, the previous index for both word 'alice' and letter 'a' are 0, so is the same.
    // 3. Index = 2, the previous index for both word 'bob' and letter 'b' are null, so is the same.
    // 4. Index = 3, the previous index for word 'bob' is 2, for letter 'a' is 1.
    //    As the two indices are different, string 's' does not match the 'pattern'.

    public boolean wordPattern(String pattern, String s) {
        // Use split() method to get the array of words.
        String[] words = s.split(" ");

        // As we want to get a full match, the pattern is not repeated, so it is a 1-to-1 match.
        // If the number of words and letters are different, then 's' does not follow the 'pattern'.
        if (words.length != pattern.length()) return false;

        // Using two HashMap, one to record the index of the words in 's',
        // and another to record the index of the letters in 'pattern'.
        // Alternatively, we can use Map<Object, Integer> to record both the String and Character object.
        Map<String, Integer> wordIndex = new HashMap<>();
        Map<Character, Integer> letterIndex = new HashMap<>();
        // Traverse both the 'words' array and the 'pattern'.
        for (int i = 0; i < words.length; i++) {
            // If the word and letter indices are different, then return false,
            // as the 's' does not follow the 'pattern'.
            if (!Objects.equals(letterIndex.put(pattern.charAt(i), i), wordIndex.put(words[i], i)))
                return false;
        }
        // If we successfully checked all the words and letters, then the 's' follows hte 'pattern'.
        return true;
    }
}

package com.cheehwatang.leetcode;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

// Time Complexity  : O(n^2),
// where 'n' is the size of the input 'nums'.
// The Arrays.sort() method implements the Dual-Pivot Quicksort, which has O(n logn) time complexity.
// Additionally, we traverse 'nums' in a nested for-loop, which results in O(n^2) time complexity.
// Lastly, we traverse the 'previous' array once to record the result into a List,
// which has linear time complexity.
// Thus, the time complexity of the 'largestDivisibleSubset()' is O(n^2).
//
// Space Complexity : O(n),
// where 'n' is the size of the input 'nums'.
// We use two arrays of size 'n', 'length' and 'previous' to record the length and links of the divisible subset.

public class LargestDivisibleSubset {

    // Approach:
    // If we sort 'nums' in ascending order,
    // we can see that all the possible divisible integers are to the right of that number.
    // Additionally, if nums[i] is divisible by nums[j], then all the divisor for nums[j] is also the divisor for nums[i].
    // For Example, nums = [1,2,4,8,16].
    // The divisor for 2 is 1, the divisor of 4 is 2 and 1, the divisor of 8 is 4,2 and 1.
    // If 8 is the divisor for 16, then naturally 1, 2 and 4 is the divisor for 16 as well.
    // As such, we look for the longest subsequence with elements that is divisible by its preceding integer in the subsequence.
    // This looks like the longest increasing subsequence where we look for subsequence with numbers increasing.
    // For that, we first sort the array, then use Dynamic Programming to keep track of the index and length of the subsequence.
    //
    // Note: We will refer the subset as a subsequence for better visualization.

    public List<Integer> largestDivisibleSubset(int[] nums) {
        int n = nums.length;
        // Sort in ascending order.
        Arrays.sort(nums);

        // 'length' records the length of the longest subsequence possible for nums[i].
        int[] length = new int[n];
        // 'previous' records the index of the preceding integer, so that we can get the list of the subsequence.
        int[] previous = new int[n];

        // For keeping track of the maximum length, so we take note of the index of the head of the subsequence.
        int maxLength = 0;
        int index = -1;
        for (int i = 0; i < n; i++) {
            // Initialize the arrays. Length is 1 because that is the shortest possible length, with 1 element.
            // Set 'previous' as -1 for when that number is the start of the subsequence (do not have any divisor).
            length[i] = 1;
            previous[i] = -1;
            for (int j = i - 1; j >= 0; j--) {
                // If we found a divisor, as the length is greater, then record in the arrays.
                if (nums[i] % nums[j] == 0 && length[j] >= length[i]) {
                    length[i] = length[j] + 1;
                    previous[i] = j;
                }
            }
            // If we successfully found a longer subsequence, then keep track of the index of the head.
            if (length[i] > maxLength) {
                maxLength = length[i];
                index = i;
            }
        }
        List<Integer> result = new ArrayList<>();
        // Here is where we use the index (head) of the subsequence and traverse each element in the subsequence.
        // Imagine a singly linked list.
        while (index >= 0) {
            result.add(nums[index]);
            index = previous[index];
        }
        return result;
    }
}

