/**
 * Definition for singly-linked list.
 * public class ListNode {
 *     int val;
 *     ListNode next;
 *     ListNode() {}
 *     ListNode(int val) { this.val = val; }
 *     ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the Linked List.
// We traverse the whole Linked List once.
// In actual case, it would be O(n/2) as we are moving the 'fast' pointers two nodes at a time, but simplify as O(n).
//
// Space Complexity : O(1),
// as we are only using fixed variable that do not grow with the length of the Linked List.

public class DeleteTheMiddleNodeOfALinkedList {

    // Approach:
    // Using Two Pointers to traverse the Singly Linked List to find the middle node:
    // - 'fast' pointer move two nodes at a time,
    // - 'slow' pointer move one node at a time.

    public ListNode deleteMiddle(ListNode head) {
        // If the Linked List has only one node, the node is deleted, thus return null.
        if (head.next == null) return null;

        ListNode fast = head;
        ListNode slow = head;
        // An additional 'parent' pointer to keep track of the parent node of 'slow'.
        // Since this is a Singly Linked List, there is no way to return to the previous node.
        // We need the previous node to delete a node from the Singly Linked List.
        ListNode parent = slow;
        while (fast != null && fast.next != null) {
            fast = fast.next.next;
            parent = slow;
            slow = slow.next;
        }
        // Remove the middle node from the Singly Linked List.
        parent.next = slow.next;

        return head;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(sqrt(n)),
// where 'n' is the area, with the worst case is that the area is a prime number, thus only a width of 1 is possible.
//
// Space Complexity : O(1),
// as only fixed variable is used.

public class ConstructTheRectangle {

    // Approach:
    // As we know the greatest width possible is the square-root of 'area'.
    // However, as the result only accepts int, not double,
    // we can use the remainder operator % to find the greatest 'width' that fully divides 'area'.
    // The first possible 'width' is the width with the least difference to 'length'.

    public int[] constructRectangle(int area) {
        // Reminder: Result == [L, W]

        // Starts 'width' as the square-root of 'area' as we need to satisfy 'width' <= 'length'.
        int width = (int) Math.sqrt(area);

        // Continue to reduce 'width' (at the same time extends 'length'),
        // until we found a 'width' that fully divides 'area'.
        while (area % width != 0) width--;

        return new int[]{area / width, width};
    }
}

