// Time Complexity  : O(n),
// where 'n' is the length of the input string 's'.
// We iterate through the string 's' once to check each roman numeral and adjust the sum accordingly.
//
// Space Complexity : O(1),
// as the auxiliary space used for the variables is independent on the size of the input string 's'.

public class RomanToInteger_WithoutHashMap {

    // Approach:
    // Generally, the Roman characters increases in value from right to left. However...
    // Notice the pattern in the Roman numeral, where IV = 5 - 1, IX = 10 - 1, XL = 50 - 10 etc.
    // Whenever the left (eg I) is less than the right (eg X), we will deduct left (in this case 1).
    // Thus, we need to keep track of the previous value to compare.
    //
    // Here, we use switch case to check for the roman numeral and integer pair.
    // As compared to using HashMap, this approach is more time-consuming,
    // as we need to iterate through the switch cases, but saves on the memory from the HashMap.

    public int romanToInt(String s) {
        int sum = 0;
        int previous = 0;
        int current = 0;
        // Starting from the smallest roman numeral (from the right).
        for (int i = s.length()-1; i >= 0; i--) {
            char letter = s.charAt(i);
            switch (letter) {
                case 'I':
                    current = 1;
                    break;
                case 'V':
                    current = 5;
                    break;
                case 'X':
                    current = 10;
                    break;
                case 'L':
                    current = 50;
                    break;
                case 'C':
                    current = 100;
                    break;
                case 'D':
                    current = 500;
                    break;
                case 'M':
                    current = 1000;
                    break;
            }
            // Add to the sum if the current numeral is equal or greater than the previous one,
            // or subtract from the sum if the current numeral is smaller, as explained in the Approach.
            sum = (current >= previous ? sum + current : sum - current);
            previous = current;
        }
        return sum;
    }
}

package com.cheehwatang.leetcode;

import java.util.ArrayList;
import java.util.List;

// Time Complexity  : O(n * n!),
// where 'n' is the length of 'nums'.
// For each number in 'nums', we traverse each position for the permutations to add the number,
// with each permutation being O(n!).
//
// Space Complexity : O(n!),
// where 'n' is the length of 'nums'.
// The result has 'n!' of permutations, thus the space complexity is O(n!).
// Additionally, the recursive call stack has a maximum length of 'n'.

public class Permutations_Backtracking_Recursion {

    // Approach:
    // To get the permutations for 'n' number, we need to use every number in every possible positions.
    // Using a backtrack method, we can test each number in 'nums' for each position,
    // and only add to the position if the number is not already in the current permutation.
    // This is possible because of the constraint that each element in 'nums' is unique.
    //
    // For example, nums = [A,B,C], currentList = [].
    // First position:
    // First element, A, is not in 'currentList', so we put A into 'currentList', resulting in currentList = [A].
    // Move on to second position.
    //
    // Second position:
    // First element, A, is in 'currentList', then we skip.
    // Second element, B, is not in 'currentList', so we put B into 'currentList', resulting in currentList = [A,B].
    // Move on to third position.
    //
    // Third position:
    // First element, A, is in 'currentList', then we skip.
    // Second element, B, is in 'currentList', then we skip.
    // Third element, C, is not in 'currentList', so we put C into 'currentList', resulting in currentList = [A,B,C].
    // With the 'currentList' having the same length as 'nums', we add [A,B,C] into the result.
    // Backtrack to the second position, currentList = [A,B].
    //
    // Second position:
    // Continue with the third element, C.
    // Third element, C, is not in 'currentList', so we put C into 'currentList', resulting in currentList = [A,C].
    // Move on to third position.
    //
    // Third position:
    // First element, A, is in 'currentList', then we skip.
    // Second element, B, is not in 'currentList', so we put B into 'currentList', resulting in currentList = [A,C,B].
    // With the 'currentList' having the same length as 'nums', we add [A,C,B] into the result.
    // Backtrack to the second position, currentList = [A,C].
    // Third element, C, is in 'currentList', then we skip.
    // Backtrack to the first position, currentList = [A].
    //
    // Then continue to change the first position to B or C, and continue the process.
    //
    // Here, we are using recursion to build up each permutation until length 'n', then add to the result list.
    // Note that we are using only one list to record the permutation.
    // As such, we need to create a new list copy before adding to the result list.

    // Main method to get the list of permutations.
    public List<List<Integer>> permute(int[] nums) {
        // Create a new empty list as the result.
        List<List<Integer>> result = new ArrayList<>();
        // Initialize the recursive method.
        // Note that we are using a boolean array to keep track if the element is used in the current permutation.
        // This approach allows duplicate values in 'nums'.
        // Alternatively, we could check using List.contains() method,
        // with the condition that each element in 'nums' is unique.
        backtrack(nums, result, new ArrayList<>(), new boolean[nums.length]);

        // Once all the recursive methods are completed, return the result.
        return result;
    }

    // Recursive method to build each permutation and backtracking.
    private void backtrack(int[] nums, List<List<Integer>> result, List<Integer> currentList, boolean[] used) {
        // If the 'currentList' has the same length as 'nums', it means that the permutation is formed,
        // thus we add to 'result'.
        if (currentList.size() == nums.length) {
            result.add(new ArrayList<>(currentList));
            return;
        }

        // For each element in 'nums',
        for (int i = 0; i < nums.length; i++) {
            // we skip the element if it is already used in 'currentList'.
            if (used[i]) continue;
            // Otherwise, add the element into 'currentList',
            currentList.add(nums[i]);
            // and mark as used,
            used[i] = true;
            // before calling moving to the next position to check all the elements for that position.
            backtrack(nums, result, currentList, used);
            // Once finish traversing the recursion, backtrack by setting the current element to false in 'used[i]',
            used[i] = false;
            // and remove the element from 'currentList'.
            currentList.remove(currentList.size() - 1);
        }
    }
}

package com.cheehwatang.leetcode;

import java.util.LinkedList;
import java.util.List;

// Time Complexity  : O(n * n!),
// where 'n' is the length of 'nums'.
// For each number in 'nums', we traverse each position for the permutations to add the number,
// with each permutation being O(n!).
//
// Space Complexity : O(n!),
// where 'n' is the length of 'nums'.
// The result has 'n!' of permutations, thus the space complexity is O(n!).

public class Permutations_Iteration {

    // Approach:
    // To get the permutations for 'n' number, we can add each number into the resulting List of permutations
    // in every possible position.
    //
    // For example, nums = [A,B,C],
    // we start the list with a single permutation of the first element, A, with result = [[A]].
    // For the second number, B, we put in every possible position (index 0 to i - 1),
    // resulting in result = [[B,A],[A,B]].
    // For the third number, C, we repeat the process for each permutation in the result,
    // with result = [[C,B,A],[B,C,A],[B,A,C],[C,A,B],[A,C,B],[A,B,C]],
    // with the first 3 for [B,A], and the last 3 for [A,B].
    //
    // In this solution, we create a new result list for each number in 'nums',
    // for easier understanding of the solution.
    // Additionally, we used LinkedList instead of ArrayList, because we are adding elements at specific position,
    // for better efficiency.

    public List<List<Integer>> permute(int[] nums) {
        // Create an empty result list.
        List<List<Integer>> result = new LinkedList<>();
        // Add the first element in 'nums' to a new list and add to the 'result'.
        result.add(List.of(nums[0]));

        // For each number in 'nums',
        for (int i = 1; i < nums.length; i++) {
            // we create a new result list,
            List<List<Integer>> newResult = new LinkedList<>();
            // and add the number in each position,
            for (int position = 0; position <= i; position++) {
                // for each of the permutations in 'result'.
                for (List<Integer> permutation : result) {
                    // Be sure to create a new copy of the List with the permutation,
                    // to prevent using the same permutation for each position.
                    List<Integer> current = new LinkedList<>(permutation);
                    // Add the number in the position,
                    current.add(position, nums[i]);
                    // and add to the new result.
                    newResult.add(current);
                }
            }
            // Once the new permutations are formed, update 'result' with the 'newResult'.
            result = newResult;
        }
        // Once all the permutations are formed, return the result.
        return result;
    }
}

package com.cheehwatang.leetcode;

import java.util.LinkedList;
import java.util.List;

// Time Complexity  : O(n * n!),
// where 'n' is the length of 'nums'.
// For each number in 'nums', we traverse each position for the permutations to add the number,
// with each permutation being O(n!).
//
// Space Complexity : O(n!),
// where 'n' is the length of 'nums'.
// The result has 'n!' of permutations, thus the space complexity is O(n!).
// Additionally, the recursive call stack has a maximum length of 'n'.

public class Permutations_Recursion {

    // Approach:
    // To get the permutations for 'n' number, we can add each number into the resulting List of permutations
    // in every possible position.
    //
    // For example, nums = [A,B,C],
    // we start the list with a single permutation of the first element, A, with result = [[A]].
    // For the second number, B, we put in every possible position (index 0 to i - 1),
    // resulting in result = [[B,A],[A,B]].
    // For the third number, C, we repeat the process for each permutation in the result,
    // with result = [[C,B,A],[B,C,A],[B,A,C],[C,A,B],[A,C,B],[A,B,C]],
    // with the first 3 for [B,A], and the last 3 for [A,B].
    //
    // Here, we are using recursion to build up each permutation until length 'n', then add to the result list.
    // Additionally, we used LinkedList instead of ArrayList, because we are adding elements at specific position,
    // for better efficiency.

    // Main method to get the list of permutations.
    public List<List<Integer>> permute(int[] nums) {
        // Create a new empty list as the result.
        List<List<Integer>> result = new LinkedList<>();
        // Initialize the recursive method, starting at index 0.
        permute(nums, result, new LinkedList<>(), 0);

        // Once all the recursive methods are completed, return the result.
        return result;
    }

    // Recursive method to build each permutation.
    private void permute(int[] nums, List<List<Integer>> result, List<Integer> currentList, int index) {
        // If the 'currentList' has the same length as 'nums', it means that the permutation is formed,
        // thus we add to 'result'.
        if (currentList.size() == nums.length) {
            result.add(currentList);
            return;
        }

        // For each of the possible positions,
        for (int i = 0; i <= currentList.size(); i++) {
            // make a copy of the 'currentList',
            List<Integer> current = new LinkedList<>(currentList);
            // and add the number to the position.
            current.add(i, nums[index]);
            // Once added, continue to add to the permutation with the recursive method,
            // by increasing the index by 1.
            permute(nums, result, current, index + 1);
        }
    }
}

package com.cheehwatang.leetcode;

import java.util.ArrayList;
import java.util.List;

// Time Complexity  : O(k ^ (n ^ m)),
// where 'm' is the length of 'queries', 'n' is the length of 'dictionary', and
// 'k' is the length of each element in 'queries' and 'dictionary'.
// Brute force approach to loop through 'queries' to compare to every letter in every element in 'dictionary'.
//
// Space Complexity : O(m),
// where 'm' is the length of 'queries'.
// The worst case to have all elements in 'queries' satisfying the requirement to add to the result list.

public class WordsWithinTwoEditsOfDictionary {

    // Approach:
    // As the constraints for 'queries', 'dictionary' and queries.length <= 100, we use the brute force approach
    // to compare the elements in 'queries' with every element in 'dictionary'
    // to check if there are more than two letters that is different.

    public List<String> twoEditWords(String[] queries, String[] dictionary) {
        List<String> result = new ArrayList<>();

        for (String query : queries) {
            for (String dict : dictionary) {
                // 'count' to keep track on the number of letters that is different, at each index position in the string.
                int count = 0;
                for (int k = 0; k < query.length(); k++) {
                    // Increase the count when the character that the same position is different.
                    if (query.charAt(k) != dict.charAt(k)) {
                        count++;
                        // To improve the performance slightly, stop checking once found count > 2.
                        if (count > 2) break;
                    }
                }
                // Once found word in 'dictionary' with less than 2 letter difference, add the query to the result,
                // and stop checking to rest of the 'dictionary', to improve performance slightly.
                if (count <= 2) {
                    result.add(query);
                    break;
                }
            }
        }
        return result;
    }
}

package com.cheehwatang.leetcode;

import java.util.LinkedList;
import java.util.Queue;

// Time Complexity  : O(m * n),
// where 'm' is the number of rows, and 'n' is the number of columns.
// With the worst case being that we check every position in the 'maze'.
//
// Space Complexity : O(m + n),
// where 'm' is the number of rows, and 'n' is the number of columns.
// The queue grows linearly with the rows and columns of the matrix,
// as we are constantly removing nodes from the queue at each step,
// with the max queue size being the distance from the center to the edge of the 'maze'.
//
// If we use a 2D boolean array for the visited nodes, then the space complexity is O(m * n).

public class NearestExitFromEntranceInMaze {
    // Approach:
    // A classic breadth first search problem, we use slowly expanding from the starting node.
    // We can imagine every position in the 'maze' as a node with the 'maze' being a directional graph,
    // since we cannot visit the same node twice to find the shortest path to the exit.
    // As such, we take one step at a time to all directions to a new valid position.
    // Note to check for invalid moves, either that direction is out of bound or towards a wall.
    // If that direction leads to a border space, it means it is the exit.
    // With breadth first search, we use Queue store the nodes for the next step.
    //
    // To mark the visited node, we can either use an additional 2D boolean array to record,
    // or mark the visited node as a wall '+' in 'maze', latter which is implemented here.

    public int nearestExit(char[][] maze, int[] entrance) {
        int rows = maze.length;
        int columns = maze[0].length;

        // For breadth first search, offer the first node ('entrance').
        // Note that we immediately mark the node as visited when putting into the queue as to
        // prevent other nodes from visiting it. Otherwise, we will be trapped in an infinite loop.
        Queue<int[]> queue = new LinkedList<>();
        queue.offer(entrance);
        maze[entrance[0]][entrance[1]] = '+';

        // As simple 2D array to keep track of the directions to take.
        // We can use 4 separate operation, but it is more efficient to use a for-loop to go through the four directions.
        int[][] directions = new int[][] {{0,1},{0,-1},{1,0},{-1,0}};

        int steps = 0;
        int x, y;
        while (!queue.isEmpty()) {
            // We take a step before checking the directions for the nodes that we are at (in the queue).
            steps++;

            // Make sure to use a variable to keep track of the queue.size(),
            // because the queue size continuously changes as we check for the other nodes,
            // which can lead to infinite loops or undue termination of the for-loop.
            int n = queue.size();

            // Check every node at the current step.
            for (int i = 0; i < n; i++) {
                int[] current = queue.poll();
                // For each node, check every direction.
                for (int[] direction : directions) {
                    x = current[0] + direction[0];
                    y = current[1] + direction[1];

                    // Check if this direction out of bound.
                    if (x < 0 || x >= rows || y < 0 || y >= columns) continue;
                    // Check if this direction is the wall.
                    if (maze[x][y] == '+') continue;

                    // If this direction is empty, not visited and is at the boundary, we have arrived at the exit.
                    if (x == 0 || x == rows - 1 || y == 0 || y == columns - 1) return steps;

                    // Otherwise, we change this direction as visited and put into the queue to check at the next step.
                    maze[x][y] = '+';
                    queue.offer(new int[]{x, y});
                }
            }

        }
        // If all the possible nodes and directions checked but no exits found, return -1.
        return -1;
    }
}

package com.cheehwatang.leetcode;

import java.util.Arrays;

// Time Complexity  : O(n^2),
// where 'n' is the number of bags (size of 'capacity' or 'rocks').
// The Arrays.sort() method uses the Dual-Pivot Quicksort, which results in complexity of O(n logn) in most cases,
// but worst case is quadratic O(n^2).
//
// Space Complexity : O(1),
// as we only modify the array in-place.

public class MaximumBagsWithFullCapacityOfRocks {

    // Approach:
    // As we want to get the most bags to fill to full capacity,
    // we always fill the bags needing the least number of rocks to full capacity (Greedy Approach).
    // First, get the number of rock left to fill until full capacity, by getting difference of capacity[i] and rocks[i].
    // Then, we sort in ascending order.
    // Lastly, we add the rocks into the bags in ascending order, until unable to fill anymore,
    // either all bags are full, or no more additional rocks available.

    public int maximumBags(int[] capacity, int[] rocks, int additionalRocks) {
        int n = rocks.length; // Same as capacity.length.

        // Here, we use 'capacity' to record the number of rocks left to full capacity.
        // Alternatively, we can use 'rocks' instead.
        // Idea here is to modify the existing array in-place to save memory (reduce space complexity).
        for (int i = 0; i < n; i++) capacity[i] -= rocks[i];

        // Sort in ascending order, so we can fill the bag the least empty first.
        Arrays.sort(capacity);

        int count = 0;
        // Add the rocks from the 'additionalRocks' into the bags.
        for (int rocksUntilFull : capacity) {
            // If we do not have sufficient rocks left, exit the for-loop.
            // Note that we can also return 'count' here,
            // but we still need to return statement at the end of the method to prevent compile-time error.
            if (additionalRocks < rocksUntilFull) break;

            // Reduce the 'additionalRocks' for each bag filled.
            // Note that if the bag is already full, no additional rocks is used.
            additionalRocks -= rocksUntilFull;

            // When successfully fill, increase the count by one.
            count++;
        }
        return count;
    }
}

