            // If the distance is less than the minimum distance found so far,
            // set the result to the current node and the minimum distance to the current distance.
            int distance = Math.max(distanceArray1[i], distanceArray2[i]);
            if (distance < minDistance) {
                result = i;
                minDistance = distance;
            }
        }
        // Return the index of the closest meeting node.
        // If there are no meeting node found, -1 is returned instead.
        return result;
    }

    // Method to get the array for the distance of each node from the input node.
    // If the node is not connected to the input node, -1 is used.
    private int[] getDistanceArray(int[] edges, int node) {
        // Create a distance array with the values set to -1, indicating that the node is not visited.
        int[] distanceArray = new int[edges.length];
        Arrays.fill(distanceArray, -1);

        // Traverse the graph from the input node, and record the distance from the node.
        // If the node already has a distance recorded (not -1),
        // it means that the node is visited and there is a cycle in the graph.
        // Thus, stop the traversal when a cycle is found or when we have reached the last node in the path.
        int distance = 0;
        while (node != -1 && distanceArray[node] == -1) {
            distanceArray[node] = distance++;
            node = edges[node];
        }
        // Return the distance array.
        return distanceArray;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n^3),
// where 'n' is 9, the length and width of the 'board'.
// For each position in the board, we perform 3 checks, row, column and box, which iterates 9 positions each.
// Thus, to be more exact, it is O(3 * 9 * 9 * 9).
//
// Space Complexity : O(1),
// as only fixed auxiliary variable is used to check.

public class ValidSudoku {

    // Approach:
    // Using the intuitive way of checking, which is to check the row, the column and the box to see if any same number.
    // With that, we can split it into 3 separate methods to check the row, the column and the box respectively.
    // This approach is adapted from the solution to solving the whole sudoku.
    // However, we need to take note to skip the current row and column when checking,
    // which is not necessary when solving the sudoku.

    // Main Method to check the valid sudoku.
    public boolean isValidSudoku(char[][] board) {
        // Checking every number in the 'board'.
        for (int row = 0; row < 9; row++) {
            for (int column = 0; column < 9; column++) {
                // If the position is a number (!= '.'), and it is a not a valid placement, then return false.
                if (board[row][column] != '.' && !isValidPlacement(board, board[row][column], row, column))
                    return false;
            }
        }
        // If all checks succeed, then the 'board' is a valid sudoku.
        return true;
    }

    // Method to check if identical number found in the row.
    private boolean isNumberInRow(char[][] board, char number, int row, int column) {
        for (int i = 0; i < 9; i++) {
            // "column != i" to skip the current number.
            // Otherwise, check if any identical number in the row and return true if found.
            if (column != i && board[row][i] == number) return true;
        }
        // If we did not find any identical number in the row, then return false.
        return false;
    }

    private boolean isNumberInColumn(char[][] board, char number, int row, int column) {
        for (int i = 0; i < 9; i++) {
            // "row != i" to skip the current number.
            // Otherwise, check if any identical number in the column and return true if found.
            if (row != i && board[i][column] == number) return true;
        }
        // If we did not find any identical number in the column, then return false.
        return false;
    }

    private boolean isNumberInBox(char[][] board, char number, int row, int column) {
        // Here, we get the top left corner position of the box the 'number' is in,
        // because we are going to scan from top left to bottom right of the box.
        int boxRow = row - row % 3;
        int boxColumn = column - column % 3;

        // Checking just the 3 row and 3 column position in the box.
        for (int i = boxRow; i < boxRow + 3; i++) {
            for (int j = boxColumn; j < boxColumn + 3; j++) {
                // "row != i && column != j" to skip the current number.
                // Otherwise, check if any identical number in the box and return true if found.
                if (row != i && column != j && board[i][j] == number) return true;
            }
        }
        // If we did not find any identical number in the box, then return false.
        return false;
    }

    // Additional wrapper method for all three checks to make the code more readable.
    private boolean isValidPlacement(char[][] board, char number, int row, int column) {
        // If the number is not found in the row, column and the box, then it is a valid placement and return true.
        return !isNumberInRow(board, number, row, column) &&
                !isNumberInColumn(board, number, row, column) &&
                !isNumberInBox(board, number, row, column);
    }
}

package com.cheehwatang.leetcode;

import java.util.HashSet;
import java.util.Set;

// Time Complexity  : O(n^2),
// where 'n' is 9, the length and width of the 'board'.
// This is because we iterate through every number in 'board'.
// Do note that the string concatenation take use some additional time,
// but they are constant time and do not scale linearly with 'n'.
//
// Space Complexity : O(n^2),
// where 'n' is 9, the length and width of the 'board'.
// This is due to the HashSet used, which stores the information of the number in the row, column and box.
// Every row with every 9 numbers, likewise for every column and every box,
// thus, to be more precise, it is O (n^2 + n^2 + n^2).

public class ValidSudoku_HashTable {

    // Approach:
    // Using a HashSet to record the number that was already found in the row, column and box.
    // If there are any same number in the row, column or box is already in the HashSet,
    // then we have found the identical number, which resulted in an invalid sudoku board.
    // There are multiple approaches for the HashSet, either use separate HashSet for the rows, columns and boxes,
    // or using String to include all the information into a single HashSet.
    // The latter approach is implemented here.

    public boolean isValidSudoku(char[][] board) {
        Set<String> set = new HashSet<>();
        for (int row = 0; row < 9; row++) {
            for (int column = 0; column < 9; column++) {
                char number = board[row][column];
                // If the position is a number (!= '.'),
                // then we can try adding the number and its information into the HashSet.
                if (number != '.') {
                    // The HashSet.add() function returns a boolean result, true if added successfully and false otherwise.
                    // As such, we can just use this boolean return from add() to check if we successfully added.
                    // If any of the 3 (row, column and box) is not added successfully,
                    // then 'board' is not a valid sudoku board.
                    // 1. Store the number in the row.
                    // 2. Store the number in the column.
                    // 3. Store the number in the box. (Make sure to separate row and column information with a delimiter).
                    if (!set.add(number + " in row " + row) ||
                            !set.add(number + " in column " + column) ||
                            !set.add(number + " in block " + (row / 3) + "," + (column / 3)))
                        return false;
                }
            }
        }
        // If all checks succeed, then the 'board' is a valid sudoku.
        return true;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of 'prices'.
// We traverse 'prices' once to determine the maximum profit.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the input.

public class BestTimeToBuyAndSellStock {

    // Approach:
    // Let's imagine that we can travel back in time to buy the stock with the least price.
    // Then, we can travel to the future to find the day to sell with the maximum profit.
    //
    // With this, we need to keep track of the minimum price up to any day.
    // Then for each day, we compare the current price with the minimum price to get the maximum profit.
    // For example, prices = [6,1,4,2,5]:
    // Day 1: price = 6, minPrice = 6, maxProfit = 0, when we buy and sell at 6.
    // Day 2: price = 1, minPrice = 1, maxProfit = 0, when we buy and sell at 1.
    // Day 3: price = 4, minPrice = 1, maxProfit = 3, when we buy at 1, and sell at 4.
    // Day 4: price = 2, minPrice = 1, maxProfit = 3, when we buy at 1, and sell at 4. (Note we are not selling at 2)
    // Day 5: price = 5, minPrice = 1, maxProfit = 4, when we buy at 1, and sell at 5.
    //
    // With that, we use a 'minPrice' variable to keep track of the minimum price,
    // and a 'maxProfit' variable to keep track of the maximum profit.
    // While traversing 'prices', we update the 'minPrice' and update the 'maxProfit' for each day.

    public int maxProfit(int[] prices) {
        int minPrice = Integer.MAX_VALUE, maxProfit = 0;
        // For each day,
        for (int price : prices) {
            // we update the minimum price,
            minPrice = Math.min(minPrice, price);
            // and update the maximum profit.
            maxProfit = Math.max(maxProfit, price - minPrice);
        }
        return maxProfit;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of 'prices'.
// We traverse 'prices' once to determine the maximum profit.
//
// Space Complexity : O(n),
// where 'n' is the length of 'prices'.
// We use a 'profits' array of length 'n' to record the maximum profits on each day.

public class BestTimeToBuyAndSellStock_DynamicProgramming {

    // Approach:
    // Let's imagine that we can travel back in time to buy the stock with the least price.
    // Then, we can travel to the future to find the day to sell with the maximum profit.
    //
    // With this, we need to keep track of the minimum price up to any day.
    // Then for each day, we compare the current price with the minimum price to get the maximum profit.
    // For example, prices = [6,1,4,2,5]:
    // Day 1: price = 6, minPrice = 6, maxProfit = 0, when we buy and sell at 6.
    // Day 2: price = 1, minPrice = 1, maxProfit = 0, when we buy and sell at 1.
    // Day 3: price = 4, minPrice = 1, maxProfit = 3, when we buy at 1, and sell at 4.
    // Day 4: price = 2, minPrice = 1, maxProfit = 3, when we buy at 1, and sell at 4. (Note we are not selling at 2)
    // Day 5: price = 5, minPrice = 1, maxProfit = 4, when we buy at 1, and sell at 5.
    //
    // We can use the bottom-up approach of dynamic programming,
    // where we use a 'profits' array to record the maximum profit for the day,
    // and use the 'prices' array to record the minimum price up to that day.

    public int maxProfit(int[] prices) {
        int n = prices.length;

        int[] profits = new int[n];
        // Traverse both the 'prices' and 'profits' array.
        // As the buying and selling on the first day while yield 0 profit, we can skip day 1.
        for (int i = 1; i < n; i++) {
            // For each day, we compare and update the maximum profit,
            // by comparing the max profit on the previous day, and the maximum profit on the current day.
            // We can get the maximum profit of the current day by determining the difference between
            // the minimum price in the past (prices[i - 1]) and the current price (prices[i]).
            profits[i] = Math.max(profits[i - 1], prices[i] - prices[i - 1]);
            // For each day, we update the minimum price up to the current day.
            prices[i] = Math.min(prices[i], prices[i - 1]);
        }
        // The last day in 'profits' is the maximum profit.
        return profits[n - 1];
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(1),
// as no iteration is performed, only simple arithmetic calculations.
//
// Space Complexity : O(1),
// as only fixed variables are created.

public class RectangleOverlap {

    // Approach:
    // For the overlap, we find the coordinates which is explained below.
    // Using x-coordinates as example:
    // Rectangle A:         |           |          * Indicates the max for x1 and min for x2.
    //                     ax1*         ax2
    // Rectangle B:     |          |
    //                 bx1        bx2*
    // The overlap on the left is Math.max(ax1, bx1), while the right is Math.min(ax2, bx2).
    // The same applies for the y-coordinates.
    // If there are no overlap, then (Math.min(ax2, bx2) <= Math.max(ax1, bx1)) == (bx2 <= ax1).
    // Rectangle A:                     |           |       * Indicates the max for x1 and min for x2.
    //                                 ax1*         ax2
    // Rectangle B:     |          |
    //                 bx1        bx2*

    public boolean isRectangleOverlap(int[] rec1, int[] rec2) {
        // Reminder: rec[0] == x1, rec[1] == y1, rec[2] == x2, rec[3] == y2.

        // If there are any overlap, the top right corner coordinates of the overlap
        // will be the minimum of the top right of both A and B.
        int top = Math.min(rec1[3], rec2[3]);
        int right = Math.min(rec1[2], rec2[2]);

        // Likewise for the bottom left corner is the maximum of the bottom left of both A and B.
        int bottom = Math.max(rec1[1], rec2[1]);
        int left = Math.max(rec1[0], rec2[0]);

        // There are overlap only if top > bottom and right > left.
        return top > bottom && right > left;
    }
}

package com.cheehwatang.leetcode;

import java.util.LinkedList;
import java.util.Queue;

// Time Complexity  : O(m * n),
// where 'm' is the number of rows, and 'n' is the number of columns of the 'board'.
// We perform breadth-first search (BFS) of the non-surrounded region, for a maximum of the whole 'board',
// and we check every position in the matrix for 'O'.
//
// Space Complexity : O(m + n),
// where 'm' is the number of rows, and 'n' is the number of columns.
// This is due to the Queue used in the breadth first search when we found 'i'.
// As we are adding and removing positions (nodes) at each level, the Queue can only grow to a maximum of 'm' + 'n' size.

public class SurroundedRegions_BFS {

    // Approach:
    // Visit every border positions to check for land 'O', since it is the non-surrounded region.
    // Once found the first land 'O' of the non-surrounded region,
    // perform breadth-first search (BFS) to mark the whole region.
    // With all the non-surrounded regions marked, we traverse through the whole 'board'
    // to capture the remaining land 'O' on the 'board', and convert the marked positions back to 'O'.
    // Note that we are marking the non-surrounded regions in-place, so we need to convert it back.
    // It is optional to use another matrix for marking, which we only capture the land 'O' not marked.

    public void solve(char[][] board) {
        int m = board.length;
        int n = board[0].length;

        // Check the border positions, and perform the BFS to mark any non-surrounded regions.
        Queue<int[]> queue = new LinkedList<>();
        for (int row = 0; row < m; row++) {
            for (int column = 0; column < n; column++) {
                // Check the border,
                if (row == 0 || row == m - 1 || column == 0 || column == n - 1) {
                    // if we found the non-surrounded land, add to the queue for BFS.
                    // Note to mark it by changing the 'O' to '-'.
                    if (board[row][column] == 'O') {
                        board[row][column] = '-';
                        queue.offer(new int[]{row, column});
                    }
                }
            }
        }

        // This 'directions' array is to simplify the checks on all four directions.
        // Alternatively, we can individually code the directions when performing BFS.
        int[][] directions = new int[][]{{1,0},{-1,0},{0,1},{0,-1}};

        // With the border non-surrounded lands marked,
        // we perform BFS to mark the lands connected to the non-surrounded land at the border.
        while (!queue.isEmpty()) {
            for (int i = 0, size = queue.size(); i < size; i++) {
                int[] current = queue.poll();
                // For every direction,
                for (int j = 0; j < directions.length; j++) {
                    int x = current[0] + directions[j][0];
                    int y = current[1] + directions[j][1];
                    // check if the position is out of bound of the matrix,
                    if (x < 0 || x >= board.length || y < 0 || y >= board[0].length) continue;
                    // or is either the water 'X' or visited land '-'.
                    if (board[x][y] == 'X' || board[x][y] == '-') continue;

                    // If not, mark the position and add the position to the queue.
                    board[x][y] = '-';
                    queue.offer(new int[]{x, y});
                }
            }
        }

        // With all the non-surrounded regions marked, we can capture the remaining land 'O' to 'X',
        // and convert the marked land '-' back to 'O'.
        for (int row = 0; row < m; row++) {
            for (int column = 0; column < n; column++) {
                if (board[row][column] == 'O') board[row][column] = 'X';
                else if (board[row][column] == '-') board[row][column] = 'O';
            }
        }
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(m * n),
// where 'm' is the number of rows, and 'n' is the number of columns of the 'board'.
// We perform depth-first search (DFS) of the non-surrounded region, for a maximum of the whole 'board',
// and we check every position in the matrix for 'O'.
//
// Space Complexity : O(m * n),
// where 'm' is the number of rows, and 'n' is the number of columns of the 'board'.
// Even though we modify the 'board' in-place,
// the recursive depth first search (DFS) function has a maximum call stack of every position in the 'board'.

public class SurroundedRegions_DFS {

    // Approach:
    // Visit every border positions to check for land 'O', since it is the non-surrounded region.
    // Once found the first land 'O' of the non-surrounded region,
    // perform depth-first search (DFS) to mark the whole region.
    // With all the non-surrounded regions marked, we traverse through the whole 'board'
    // to capture the remaining land 'O' on the 'board', and convert the marked positions back to 'O'.
    // Note that we are marking the non-surrounded regions in-place, so we need to convert it back.
    // It is optional to use another matrix for marking, which we only capture the land 'O' not marked.

    // Main method to capture the surrounded regions.
    public void solve(char[][] board) {
        int m = board.length;
        int n = board[0].length;

        // Check the border positions, and perform the DFS to mark any non-surrounded regions.
        // First is to check the left and right border.
        for (int row = 0; row < m; row++) {
            markNonSurroundedRegion(board, row, 0);
            markNonSurroundedRegion(board, row, n - 1);
        }
        // Second is to check the top and bottom border.
        for (int column = 0; column < n; column++) {
            markNonSurroundedRegion(board, 0, column);
            markNonSurroundedRegion(board, m - 1, column);
        }

        // With all the non-surrounded regions marked, we can capture the remaining land 'O' to 'X',
        // and convert the marked land '-' back to 'O'.
        for (int row = 0; row < m; row++) {
            for (int column = 0; column < n; column++) {
                if (board[row][column] == 'O') board[row][column] = 'X';
                else if (board[row][column] == '-') board[row][column] = 'O';
            }
        }
    }

    // Recursive DFS method to mark the non-surrounded regions.
    private void markNonSurroundedRegion(char[][] board, int row, int column) {
        // If the position is out of bound, return.
        if (row < 0 || row >= board.length || column < 0 || column >= board[0].length) return;
        // If the position is not land or already marked, return.
        if (board[row][column] == 'X' || board[row][column] == '-') return;

        // With the above check passed, this position is a land 'O' in a non-surrounded region, so mark it as '-'.
        board[row][column] = '-';

        // Continue the recursive DFS for all four directions.
        markNonSurroundedRegion(board, row + 1, column);
        markNonSurroundedRegion(board, row - 1, column);
        markNonSurroundedRegion(board, row, column + 1);
        markNonSurroundedRegion(board, row, column - 1);
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(m * n),
// where 'm' is the number of rows, and 'n' is the number of columns of the 'board'.
// We traverse the 'board' in multiple occasions,
// 1. Set the set representative (parent) for every position in the 'board' to itself.
// 2. Traverse the 'board' to find lands, and union the land adjacent to another land.
// 3. Traverse the 'board' again to capture the 'O' to 'X' if the land is surrounded.
//
// Space Complexity : O(m * n),
// where 'm' is the number of rows, and 'n' is the number of columns of the 'board'.
// We used an array to keep track of the set representative (parent) for each position in the 'board'.

public class SurroundedRegions_UnionFind {

    // Approach:
    // Using Union-Find data structure, we first make all the positions on the 'board' as separate disjoint sets.
    // Then we visit every border positions to check for land 'O', since it is the non-surrounded region.
    // Once found, we assign the parent of the position to a 'dummyID'.
    // In this case, we use the size of the 'board' (m * n), since the 'board' matrix is 0-indexed.
    // Then, we traverse the 'board' to union all the connected land 'O' to its disjoint set,
    // while giving priority to the 'dummyID' as the parent.
    // Once all the lands are union to its respective disjoint sets,
    // we traverse the 'board' to capture the land 'O' that is surround, the land without 'dummyID' as the parent.

    public void solve(char[][] board) {
        int rows = board.length;
        int columns = board[0].length;

        // 'parent' array to record the set representatives for each position.
        // Note that we are hashing the position with 'row' and 'column' into 'nodeID' "row * column + column".
        int[] parent = new int[rows * columns + 1];

        // Set up the disjoint set data structure by referencing all the nodes (positions) to itself.
        for (int i = 0; i <= rows * columns; i++) {
            parent[i] = i;
        }

        int dummyID = rows * columns;
        for (int row = 0; row < rows; row++) {
            for (int column = 0; column < columns; column++) {
                // Check the border positions,
                if (row == 0 || row == rows - 1 || column == 0 || column == columns - 1) {
                    // and mark any non-surrounded regions with the parent as 'dummyID'.
                    if (board[row][column] == 'O') {
                        parent[row * columns + column] = dummyID;
                    }
                }
            }
        }

        // This 'directions' array is to simplify the checks on all four directions.
        int[][] directions = new int[][]{{1,0},{-1,0},{0,1},{0,-1}};

        // Traverse the 'board' to union all the connected land 'O' to its disjoint set,
        // while giving priority to the 'dummyID' as the parent.
        for (int row = 0; row < rows; row++) {
            for (int column = 0; column < columns; column++) {
                // Skip if the position is water.
                if (board[row][column] == 'X') continue;
                int nodeID1 = row * columns + column;
                // If the position is land, check the four directions.
                for (int j = 0; j < directions.length; j++) {
                    int x = row + directions[j][0];
                    int y = column + directions[j][1];
                    // Skip if the direction position is out of bound.
                    if (x < 0 || x >= board.length || y < 0 || y >= board[0].length) continue;
                    // Skip if the direction position is water.
                    if (board[x][y] == 'X') continue;

                    // If the direction position is land, union the two lands.
                    int nodeID2 = x * columns + y;
                    union(nodeID1, nodeID2, parent, dummyID);
                }
            }
        }

        // Once all the lands are in their respective disjoint sets,
        for (int row = 0; row < rows; row++) {
            for (int column = 0; column < columns; column++) {
                if (board[row][column] == 'X') continue;
                int nodeID = row * columns + column;
                // Capture the land that is surrounded, the land without 'dummyID' as the parent.
                if (find(nodeID, parent) != dummyID) board[row][column] = 'X';
            }
        }
    }

    // The find() method, with path compression implemented to reduce time complexity.
    private int find(int nodeID, int[] parent) {
        // Once the node has itself as the parent,
        // then we have found the set representative (parent) of this disjoint set.
        if (parent[nodeID] == nodeID) {
            return nodeID;
        }

        // If not, then we continue to find.
        // Once the parent is found, the node is referenced to the parent,
        // compressing the path from the node to the set representative (parent).
        return parent[nodeID] = find(parent[nodeID], parent);
    }

    // The union() method.
    // Note that union by rank is not implemented,
    // as we need to prioritize the land connected to 'dummyID' to be the parent.
    private void union(int nodeID1, int nodeID2, int[] parent, int dummyID) {
        // Find the parent for both nodes.
        int find1 = find(nodeID1, parent);
        int find2 = find(nodeID2, parent);

        // If the parents are the same, then both nodes are already in the same disjoint set.
        if (find1 == find2) return;

        // If 'find1' is part of the non-surrounded region (with 'dummyID'), make 'find1' the parent of 'find2'.
        if (find1 == dummyID) {
            parent[find2] = find1;
        }
        // If 'find2' is part of the non-surrounded region (with 'dummyID'), make 'find2' the parent of 'find1'.
        // Note that if either nodes are with 'dummyID', then we just defaults to 'find2' as parent, or vice versa.
        else {
            parent[find1] = find2;
        }
    }
}

package com.cheehwatang.leetcode;

import java.util.HashMap;
import java.util.Map;

// Time Complexity  : O(n),
// where 'n' is the length of 'nums'.
// We traverse the 'nums' array to add the integer to the HashMap.
//
// Space Complexity : O(n),
// where 'n' is the length of 'nums'.
// In the worst-case when no duplicate is found, the HashMap has a size of 'n'.

public class ContainsDuplicate_HashMap {

    // Approach:
    // Using HashMap, store the integers in 'nums'. Return true if the same integer is already in the HashMap.

    public boolean containsDuplicate(int[] nums) {
        // Set up the HashMap.
        Map<Integer, Integer> hashMap = new HashMap<>();

        // For each integer in 'nums',
        for (int integer : nums) {
            // if HashMap contains the key, duplicate integer is found and return true.
            if (hashMap.containsKey(integer)) return true;
            // Add the integer into the HashMap.
            hashMap.put(integer, 1);
        }
        // If all integers added successfully, that means all integers are distinct.
        return false;
    }
}

