/**
 * Definition for singly-linked list.
 * public class ListNode {
 *     int val;
 *     ListNode next;
 *     ListNode() {}
 *     ListNode(int val) { this.val = val; }
 *     ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the Linked List.
// We traverse the whole Linked List once.
//
// Space Complexity : O(1),
// as we are only using fixed variable that do not grow with the length of the Linked List.

public class RemoveNthNodeFromEndOfList_OnePass {

    // Approach:
    // Using Two Pointers, with the gap in between the 'fast' and 'slow' pointer of 'n' number of nodes,
    // we traverse the 'fast' pointer until the end of the Linked List and remove the node at the 'slow' pointer.

    public ListNode removeNthFromEnd(ListNode head, int n) {
        // To prevent the edge of case removing the first node without a parent, we introduce a parent for the 'head'.
        ListNode start = new ListNode(0);
        start.next = head;

        // With a 'slow' and a 'fast' pointer,
        // we first traverse the 'fast' pointer until the gap of 'n' from the 'slow' pointer.
        ListNode slow = start, fast = start;
        for (int i = 1; i <= n; i++) fast = fast.next;

        // Once we have the gap, we traverse both pointers until 'fast' pointer reaches the end of the list.
        while (fast.next != null) {
            slow = slow.next;
            fast = fast.next;
        }
        // Remove the node.
        // Note that we started at the 0-th node, the 'slow' pointer is at the parent of the node the be removed.
        slow.next = slow.next.next;

        // Return the head of the Linked List.
        // If the first node is removed, the start.next points to the second node,
        // else, it still points to the 'head'.
        return start.next;
    }
}

package com.cheehwatang.leetcode;

/**
 * Definition for singly-linked list.
 * public class ListNode {
 *     int val;
 *     ListNode next;
 *     ListNode() {}
 *     ListNode(int val) { this.val = val; }
 *     ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the Linked List.
// We traverse the whole Linked List twice, once to count the number of nodes, once to remove the Nth node.
//
// Space Complexity : O(1),
// as we are only using fixed variable that do not grow with the length of the Linked List.

public class RemoveNthNodeFromEndOfList_TwoPasses {

    // Approach:
    // Traverse the Singly Linked List twice, first to count the number of nodes,
    // second to traverse the pointer until the Nth node and remove the node.

    public ListNode removeNthFromEnd(ListNode head, int n) {

        // Count the number of nodes.
        int size = 0;
        ListNode pointer = head;
        while (pointer != null) {
            size++;
            pointer = pointer.next;
        }

        // 'size' - 'n' is the position of the node to remove, counting from the 'head' with 0-indexed.
        // For example, if the 'size' is 5, and 'n' is 5, we remove the node at position 0, which is the first node.
        int nodeToRemove = size - n;

        // The first node is an edge case as it has no parent node.
        // Thus, we check if we need to remove the first node.
        if (nodeToRemove == 0) return head.next;

        // Using a 'current' pointer for the Nth node from end of list,
        // and a 'parent' pointer for node removal as this is a Singly Linked List.
        ListNode current = head;
        ListNode parent = current;
        // Traverse both pointers until we reach the node to remove.
        while (nodeToRemove > 0) {
            parent = current;
            current = current.next;
            nodeToRemove--;
        }
        // Remove the node from the Singly Linked List.
        parent.next = current.next;

        return head;
    }
}

package com.cheehwatang.leetcode;

/**
 * Definition for singly-linked list.
 * public class ListNode {
 * int val;
 * ListNode next;
 * ListNode() {}
 * ListNode(int val) { this.val = val; }
 * ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */
// Note: Remember to set up a ListNode class as the same folder as the reverseBetween() function.

// Time Complexity  : O(n),
// where 'n' is the length of the linked list.
// We traverse the linked list once to flip the linked list nodes in the section.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the input size.

public class ReverseLinkedListII {

    // Approach:
    // Use 3 main pointers to reverse the list between 'left' and 'right':
    // 1. 'previous' to mark the node before the section to reverse,
    // 2. 'current' to mark the current head of reversing section,
    // 3. 'next' to mark the next node to reverse.
    //
    // For example: head = [1,2,3,4,5], left = 2, right = 4,
    // We first traverse until the start of the reversing section.
    // Then, 'previous' = 1, 'current' = 2, and 'next' = 3.
    // Each iteration,
    // - head = [1,3,2,4,5], 'previous' = 1, 'current' = 2, and 'next' = 4.
    // - head = [1,4,3,2,5], 'previous' = 1, 'current' = 2, and 'next' = 5.
    //
    // Additionally, we use a 'placeholder' node to mark the head.
    // The reason why 'head' is not used, is because the section to reverse includes the 'head' node,
    // and 'previous' will refer to 'placeholder'.
    // The new head would be the next node to the 'placeholder'.

    public ListNode reverseBetween(ListNode head, int left, int right) {
        // If the list is empty or with only one node, return the head.
        if (head == null || head.next == null) return head;

        // Set up the placeholder node.
        ListNode placeholder = new ListNode(0);
        placeholder.next = head;

        // Traverse the section before 'left'.
        ListNode previous = placeholder;
        for (int i = 0; i < left - 1; i++) {
            previous = previous.next;
        }

        // Set up the 'current' and 'next' pointer.
        ListNode current = previous.next;
        ListNode next = current.next;

        // For each iteration,
        for (int i = 0; i < right - left; i++) {
            // moves the 'next' node to the node after 'previous',
            // by first setting the 'current' next to the node after 'next',
            current.next = next.next;
            // point the 'next' next to the tail of the reversing section,
            next.next = previous.next;
            // set the tail to 'next',
            previous.next = next;
            // and reset 'next' to the node after the head, 'current', of the section.
            next = current.next;
        }
        // Return the head of the list.
        return placeholder.next;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of integer array 'data'.
// We traverse the 'data' array to check if the numbers fit the UTF8 pattern.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent on the size of the input.

public class UTF8Validation {

    // UTF-8 Binary Sequence:
    // 1 byte = 0xxxxxxx
    // 2 bytes = 110xxxxx 10xxxxxx
    // 3 bytes = 1110xxxx 10xxxxxx 10xxxxxx
    // 4 bytes = 11110xxx 10xxxxxx 10xxxxxx 10xxxxxx

    // Approach:
    // With the 8-bits binary number, we can check if the number in 'data' matches any of the pattern as shown below:
    // - 0xxxxxxx : <= 127
    // - 10xxxxxx : >= 128 && <= 191
    // - 110xxxxx : >= 192 && <= 223
    // - 1110xxxx : >= 224 && <= 239
    // - 11110xxx : >= 240 && <= 247
    //
    // We also use a count to keep track the number 10xxxxxx required, for 2, 3 and 4 bytes pattern.

    public boolean validUtf8(int[] data) {
        // 'count' keep track of the 10xxxxxx required.
        int count = 0;
        for (int number : data) {
            // Number greater than 247 does not fit any of the above pattern.
            if (number > 247) return false;

            // If count is 0, and the number is fits 110xxxxx, 1110xxxx or 11110xxx, then we will update the count
            // to check the subsequent number if it follows 10xxxxxx.
            if (count == 0) {
                // If number matches 11110xxx, check for the subsequent three numbers to follow 10xxxxxx.
                if (number >= 240) count = 3;
                // If number matches 1110xxxx, check for the subsequent two numbers to follow 10xxxxxx.
                else if (number >= 224) count = 2;
                // If number matches 110xxxxx, check for the subsequent number to follow 10xxxxxx.
                else if (number >= 192) count = 1;
                // If number matches 10xxxxxx while the count is 0, then it is invalid.
                else if (number >= 128) return false;
                // Note that we did not perform any checks for 0xxxxxxx (<= 127),
                // as no action is needed (count remains 0 and move to the next number).
            }
            // If the count is more than 0,
            else {
                // check if the number matches 10xxxxxx.
                if (number >= 128 && number <= 191) count--;
                // If not, then the sequence is invalid.
                else return false;
            }
        }
        // If the count reaches zero at the end, meaning no leftover 10xxxxxx unchecked.
        return count == 0;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of integer array 'data'.
// We traverse the 'data' array to check if the numbers fit the UTF8 pattern.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent on the size of the input.

public class UTF8Validation_BitManipulation {

    // UTF-8 Binary Sequence:
    // 1 byte = 0xxxxxxx
    // 2 bytes = 110xxxxx 10xxxxxx
    // 3 bytes = 1110xxxx 10xxxxxx 10xxxxxx
    // 4 bytes = 11110xxx 10xxxxxx 10xxxxxx 10xxxxxx

    // Approach:
    // Using bit manipulation to shift the bits to the right, to get the binary digits of importance:
    // - shift 7 bits : 0xxxxxxx
    // - shift 6 bits : 10xxxxxx
    // - shift 5 bits : 110xxxxx
    // - shift 4 bits : 1110xxxx
    // - shift 3 bits : 11110xxx
    // number >> 7 to shift seven position to the right, getting only the first binary digit.
    // The bit manipulation works for both integers and binary numbers.
    // Example: 01001010 (int 74) >> 7 = 0, 11010111 (215) >> 5 == 110 (int 6).
    //
    // Note that we are using prefix '0b' before the binary number to represent it as binary number.
    // For example, 0b10 is binary 10 which is number 2.

    public boolean validUtf8(int[] data) {
        int count = 0;
        for (int number : data) {
            // If count is 0, and the number is fits 110xxxxx, 1110xxxx or 11110xxx, then we will update the count
            // to check the subsequent number if it follows 10xxxxxx.
            if (count == 0) {
                // For 4 bytes, shift 3 position to check 11110xxx.
                if (number >> 3 == 0b11110) count = 3;
                // For 3 bytes, shift 4 position to check 1110xxxx.
                else if (number >> 4 == 0b1110) count = 2;
                // For 2 bytes, shift 5 position to check 110xxxxx.
                else if (number >> 5 == 0b110) count = 1;
                // For 1 byte, shift 7 position to check 0xxxxxxx.
                else if (number >> 7 == 0b0) count = 0;
                // If the number does not fit any of the pattern, then it is invalid.
                else return false;
            }
            // If the count is more than 0,
            else {
                // shift 6 position to check 10xxxxxx.
                if (number >> 6 == 0b10) count--;
                // If not, then the sequence is invalid.
                else return false;
            }
        }
        // If the count reaches zero at the end, meaning no leftover 10xxxxxx unchecked.
        return count == 0;
    }
}

