// Time Complexity  : O(n),
// as we are only iterating from 1 to 'n' once.
//
// Space Complexity : O(n),
// as the array grows linearly with 'n'.

public class UglyNumberII_DynamicProgramming {

    // Approach:
    // Ugly number is found with the multiplication of an ugly number (including 1) with 2, 3 or 5.
    // So, we use a table to keep track of the ugly number that was found,
    // and using pointers for 2, 3 and 5 to keep track on the ugly number that it had to multiply with.
    // As we are building the table of ugly numbers, we only add a new element when it is the smallest
    // among the products of ugly numbers with 2, 3 and 5.
    // For Example, table = [1], pointers for 2, 3 and 5 all at position 0.
    // the next ugly number will be the smallest among (2 * 1), (3 * 1) and (5 * 1), which is 2.
    // Thus table = [1,2], with pointer for 2 is at position 1 now.
    // Next is smallest among (2 * 2), (3 * 1) and (5 * 1), which is 3.
    // So on until we each table[n - 1] position, which is the n-th ugly number, since table is 0-indexed.
    // Do take note to account for when more than one in 2, 3 and 5 produces the same ugly number,
    // for example with ugly number, 6, with 2 * 3 and 3 * 2.

    public int nthUglyNumber(int n) {
        int[] table = new int[n];
        // We know the first ugly number is 1.
        table[0] = 1;
        // All the pointers start at position 0.
        int factor2 = 0, factor3 = 0, factor5 = 0;

        for (int index = 1; index < n; index++){
            table[index] = Math.min(Math.min(2 * table[factor2], 3 * table[factor3]), 5 * table[factor5]);
            // Three separate if statements, rather than if-else to account for the situation where,
            // more than one factor produces the same ugly number (example with 6 above).
            if (table[index] == 2 * factor2) factor2++;
            if (table[index] == 3 * factor3) factor3++;
            if (table[index] == 5 * factor5) factor5++;
        }
        return table[n - 1];
    }
}

package com.cheehwatang.leetcode;

import java.util.PriorityQueue;

// Time Complexity  : O(n logn),
// as the poll() function in the priority queue has a logarithmic O(logn) complexity,
// and we are performing poll() at least 'n' number of times.
// There is also a O(logn) time complexity when we use the add() function in the priority queue,
// resulting in an additional O(3 * n * logn) time complexity.
//
// Space Complexity : O(n),
// as the priority queue grows linearly with 'n'.

public class UglyNumberII_PriorityQueue {

    // Approach:
    // Ugly number is found with the multiplication of an ugly number (including 1) with 2, 3 or 5.
    // So, we use priority queue to get the smallest of the ugly numbers found so far,
    // and multiple them with 2, 3 or 5, to get new ugly numbers.
    // As priority queue is a minimum heap data structure,
    // the smallest ugly number in the priority queue is the i-th ugly number.
    // For Example, with priority queue having 1.
    // Next, we add 2 * 1, 3 * 1, and 5 * 1 into the priority queue, removing the number 1.
    // With 2, 3 and 5 in the priority queue, the smallest number is 2.
    // Thus, we add 2 * 2 == 4, 3 * 2 == 6, and 5 * 2 == 10, into the priority queue.
    // We continue until the n-th iteration.
    // Do note that there can be multiple identical ugly numbers,
    // so make sure to remove identical numbers (if any) from the priority queue.

    public int nthUglyNumber(int n) {
        // Note that we are using Long primitive type, because this method will result in overflow if we use Integer.
        // For example if the smallest number in the priority queue is (2 ^ 31) - 1,
        // then it means that other numbers in the priority queue is greater than Integer.MAX_VALUE.
        PriorityQueue<Long> pq = new PriorityQueue<>();
        pq.add(1L);
        for (int i = 1; i < n; i++) {
            long value = pq.remove();
            // Check and remove identical ugly numbers.
            while (pq.size() > 0 && pq.peek() == value) pq.poll();
            pq.add(value * 2);
            pq.add(value * 3);
            pq.add(value * 5);
        }
        // The next smallest ugly number is the n-th ugly number.
        return pq.remove().intValue();
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of 'nums'.
// We traverse 'nums' once to find the single number.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the input.

public class SingleNumber {

    // Approach:
    // As the constraints are linear time complexity and constant space complexity,
    // it can only be achieved with bit manipulation.
    // Firstly, we need to understand the bitwise XOR operator '^'.
    // The XOR of any two numbers gives the difference of bit,
    // for example: 1010 ^ 1111 = 0101.
    // If we perform XOR of two identical number, then the result would be 0.
    // For example, 1111 ^ 1111 = 0.
    //
    // Within the 'nums' array, we are guaranteed to have a single distinct number without duplicates.
    // As such, all the other duplicates negates each other when performing XOR operation.
    // Thus, we can determine the single number by performing XOR for all the numbers in 'nums.
    // For example, 1111 ^ 1010 ^ 1111 = 1010, with 1111 negating each other in the XOR operation.

    public int singleNumber(int[] nums) {
        // For each number, perform the XOR operation and return the result.
        int result = 0;
        for (int number : nums) result ^= number;
        return result;
    }
}

