// Time Complexity  : O(n + m),
// where 'n' is the length of 'changed', and 'm' is the maximum number in 'changed'.
// We traverse the 'changed' array twice,
// first is to find the maximum number, and second is to count the numbers in 'changed'.
// Additionally, we traverse the counting array once with size of 'm'.
// Thus, the total time complexity is O(n + m).
//
// Space Complexity : O(n + m),
// where 'n' is the length of 'changed', and 'm' is the maximum number in 'changed'.
// We use a counting array of size 'm' to count the frequency of the numbers in 'changed'.
// Additionally, the result array has size half of 'changed', thus has space complexity of O(n).
// Thus, the total space complexity is O(n + m).

public class FindOriginalArrayFromDoubledArray_Counting {

    // Approach:
    // We use a counting array to count the frequency of the numbers in 'changed' array.
    // Instead of using the constraint size of 10^5, we can first determine the maximum number in 'changed',
    // then create a counting array of size "max + 1".
    //
    // As we traverse the counting array, we skip the numbers that has 0 frequency.
    // For each number with frequency greater than 0, we check if the double exists.
    // Return an empty array if empty.
    // Else, record the number in the result array, and reduce the frequency of both number by 1.

    public int[] findOriginalArray(int[] changed) {
        int n = changed.length;

        // For all test cases, if "changed.length" is 0, or odd number, then it must not be a doubled array.
        // Since all values in the doubled array must be in pairs. (e.g. 1 -> 2, 5 -> 10, etc.)
        if (n == 0 || n % 2 == 1) return new int[0];

        // This method involves using an array of size 'maxNumber' in the 'changed' array,
        // by counting the frequency of each number.
        // Thus, first get the 'maxNumber' by checking all the numbers in 'changed'.
        int maxNumber = Integer.MIN_VALUE;
        for (int number : changed) maxNumber = Math.max(number, maxNumber);

        // Once found 'maxNumber', create a 'countArray' to record the frequency of each number.
        // Note: Counting the frequency of each number inadvertently sorted the 'changed' array.
        int[] countArray = new int[maxNumber + 1];
        for (int number : changed) countArray[number]++;

        // Set up the array of the original array, and index to track the position in the array.
        int[] original = new int[n/2];
        int index = 0;

        // Traverse the countArray to perform number matching with number * 2.
        for (int j = 0; j <= maxNumber; j++) {
            // If the frequency of the number is already "used up" when matching with smaller number, we will skip.
            if (countArray[j] <= 0) continue;

            // If "j * 2" is greater than the 'maxNumber', then there is no match.
            // If the frequency of number j * 2 is 0, we know that number j is not matched.
            // Note that we would need to check if "j * 2" is greater than 'maxNumber' first to prevent IndexOutOfBoundsException.
            if (j * 2 > maxNumber || countArray[j*2] == 0) return new int[0];

            // Input the number to the original array.
            original[index++] = j;
            // Reduce the count for both, number and number * 2
            countArray[j*2]--;
            countArray[j]--;
            // The j-- is used to account for number 'j' frequency of > 1,
            // thus repeating the for-loop for the same number, until 'countArray[j]' reaches 0.
            j--;
        }
        return original;
    }
}

package src.com.cheehwatang.leetcode;

import java.util.Arrays;
import java.util.HashMap;
import java.util.Map;

// Time Complexity  : O(n logn),
// where 'n' is the length of 'changed'.
// We traverse the 'changed' array twice,
// first is to count the numbers in 'changed' using a HashMap, and
// second is to traverse the sorted 'changed' array determine the original array, if any.
// Additionally, we sort 'changed' array using the Arrays.sort() function, which implements the Dual-Pivot Quicksort
// with O(n logn) time complexity.
// Thus, the final time complexity is O(n logn).
//
// Space Complexity : O(n),
// where 'n' is the length of 'changed'.
// We use a HashMap with the maximum size of 'n' to count the frequency of the numbers in 'changed'.
// Additionally, the result array has size half of 'changed', thus has space complexity of O(n).
// Thus, the total space complexity is O(n).

public class FindOriginalArrayFromDoubledArray_HashMap_Sorting {

    // Approach:
    // We use a HashMap to count the frequency of the numbers in 'changed' array.
    // Then, we sort 'changed' array.
    // This allows use to traverse the sorted 'changed' array in ascending order, and check the smaller numbers first.
    // As we traverse the sorted array, we skip the numbers that has 0 frequency.
    // For each number with frequency greater than 0, we check if the double exists.
    // Return an empty array if empty.
    // Else, record the number in the result array, and reduce the frequency of both number by 1.

    public int[] findOriginalArray(int[] changed) {
        int n = changed.length;

        // If changed.length is 0 or odd, then it must not be a doubled array.
        // Since all values in the doubled array must be in pairs. (e.g. 1 -> 2, 5 -> 10, etc.)
        if (n == 0 || n % 2 == 1) return new int[0];

        // Count the frequency of each number and record into the HashMap.
        Map<Integer, Integer> count = new HashMap<>();
        for (int number : changed) {
            count.put(number, count.getOrDefault(number, 0) + 1);
        }

        // Set up the array of the original array, and index to track the position in the array.
        int[] original = new int[n / 2];
        int index = 0;

        // For the method below to work, we must sort the 'changed' array.
        // The reason being that we are checking if the frequency of number > frequency of number * 2.
        // If number of higher value at front, it will unintentionally return new int[0],
        // even if later will have a number matching.
        // e.g. if array [14,7], will first check if 28 exist. Answer is no, so return an empty array,
        //      but in actual case it has a match later with 7.
        Arrays.sort(changed);
        for (int number : changed) {
            // If the frequency of the number is already "used up" when matching with smaller number, we will skip.
            if (count.get(number) <= 0) continue;

            // If frequency of number > frequency of (number * 2), return an empty array.
            if (count.get(number) > count.getOrDefault(number * 2, 0)) {
                return new int[0];
            }

            // If reach here, meaning frequency of (number * 2) is sufficient to match the frequency of number.
            // Input the number to the original array.
            original[index++] = number;
            // Reduce the count for both, number and number * 2
            count.put(number, count.get(number) - 1);
            count.put(number * 2, count.get(number * 2) - 1);
        }
        return original;
    }
}

package src.com.cheehwatang.leetcode;

import java.util.Arrays;
import java.util.LinkedList;
import java.util.Queue;

// Time Complexity  : O(n logn),
// where 'n' is the length of 'changed'.
// We sort 'changed' array using the Arrays.sort() function,
// which implements the Dual-Pivot Quicksort with O(n logn) time complexity.
// Then, we traverse 'changed' array once to determine the original array.
// Thus, the final time complexity is O(n logn).
//
// Space Complexity : O(n),
// where 'n' is the length of 'changed'.
// We use a Queue with the maximum size of 'n' to record the numbers that are not matched.
// Additionally, the result array has size half of 'changed', thus has space complexity of O(n).
// Thus, the total space complexity is O(n).

public class FindOriginalArrayFromDoubledArray_Queue_Sorting {

    // Approach:
    // We first sort 'changed' array, so that we can traverse the sorted array in ascending order.
    // As we traverse the sorted array, we use a Queue to record the numbers that are not matched.
    // For each number, we check if the number is double the first element in the Queue.
    // If the numbers matched, we add the smaller number to the result array.
    // If not matched, we offer the number to the Queue.
    //
    // After traverse the sorted array, we check if the Queue is empty.
    // If the Queue is empty, then there are numbers that is not matched, and we return an empty array.
    // Return the result array otherwise.

    public int[] findOriginalArray(int[] changed) {
        int n = changed.length;

        // For all test cases, if changed.length is 0, or odd number, then it must not be a doubled array.
        // Since all values in the doubled array must be in pairs. (e.g. 1 -> 2, 5 -> 10, etc.)
        if (n == 0 || n % 2 == 1) return new int[0];

        // We will use sorting, to get ascending sequence, and a queue to keep track of values without a pair yet.
        Arrays.sort(changed);
        Queue<Integer> queue = new LinkedList<>();

        // Set up the array of the original array, and index to track the position in the array.
        int[] original = new int[n/2];
        int index = 0;

        for (int number : changed) {
            // Check for pair matching, if not found, add to the queue to check later.
            if (queue.isEmpty() || queue.peek() * 2 != number)
                queue.offer(number);
            // If found, then we take the smaller value (which is the one in the queue), and put into 'original'.
            else
                original[index++] = queue.poll();
        }

        // If the queue is empty, meaning all numbers in 'changed' successfully matched.
        if (queue.isEmpty()) return original;
        // Else, there are numbers that is not matched.
        else return new int[0];
    }
}

