// Time Complexity  : O(n),
// where 'n' is the length of string 'colors'.
// We traverse the string 'colors' once to find the adjacent balloons with the same color.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the size of input string 'colors' or int array 'neededTime'.

public class MinimumTimeToMakeRopeColorful_DynamicProgramming {

    // Approach:
    // Check for any similar color with the previous balloon.
    // If it is the same color, then we always remove the balloon requiring the least time (Greedy Approach).
    // Here, the balloon with the most time needed is kept, and we are using 'neededTime' array to record,
    // instead of a separate variable.

    public int minCost(String colors, int[] neededTime) {
        int minTime = 0;

        // Traverse the string 'colors' to check for any consecutive balloons of identical color.
        for (int index = 1; index < colors.length(); index++) {
            // If found, then we record the least time needed to remove either balloon,
            // and update the current balloon with the most time needed.
            if (colors.charAt(index) == colors.charAt(index - 1)) {
                minTime += Math.min(neededTime[index], neededTime[index - 1]);
                neededTime[index] = Math.max(neededTime[index], neededTime[index - 1]);
            }
        }
        return minTime;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n),
// where 'n' is the length of string 'colors'.
// We traverse the string 'colors' once to find the adjacent balloons with the same color.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the size of input string 'colors' or int array 'neededTime'.

public class MinimumTimeToMakeRopeColorful_Greedy {

    // Approach:
    // Check for any similar color with the previous balloon.
    // If it is the same color, then we always remove the balloon requiring the least time (Greedy Approach).
    // Using a variable to keep track of the most time needed between the two consecutive balloons of the same color.

    public int minCost(String colors, int[] neededTime) {
        int minTime = 0;
        int previousTime = neededTime[0];

        // Traverse the 'colors' String to check for any consecutive balloons of identical color.
        for (int index = 1; index < colors.length(); index++) {

            // If found, then we record the least time needed to remove either balloon,
            // and record the most time needed into the 'previousTime' variable.
            if (colors.charAt(index) == colors.charAt(index - 1)) {
                minTime += Math.min(previousTime, neededTime[index]);
                previousTime = Math.max(previousTime, neededTime[index]);
            }
            // If not found, then keep updating the variable with the current time needed.
            else previousTime = neededTime[index];
        }
        return minTime;
    }
}

package com.cheehwatang.leetcode;

import java.util.LinkedList;
import java.util.Queue;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// The number of nodes to visit to find the minimum depth grows linearly with the number of nodes in the tree.
//
// Space Complexity : O(m),
// where 'm' is the breadth of the tree.
// The maximum size of the 'queue' is the breadth of the tree.

public class MinimumDepthOfBinaryTree_BFS {

    // Approach:
    // Using breadth-first search to find the minimum depth of the tree.
    // Traverse the tree level by level, while keeping track of the level.
    // When we found the first leaf node, the level of the node is the minimum depth of the tree.

    public int minDepth(TreeNode root) {
        // If the tree is empty, there is zero depth.
        if (root == null) return 0;

        // Start the 'level' at 0, as we have yet to traverse the first level.
        int level = 0;

        // Breadth-first search is implemented using 'queue'.
        Queue<TreeNode> queue = new LinkedList<>();
        queue.offer(root);

        // If there are nodes in the 'queue' and no leaf node is found yet,
        // continue to traverse the tree level by level until the leaf node is found.
        while (!queue.isEmpty()) {
            // Each new level, we increase 'level' by 1.
            level++;

            // Remember to use a variable 'size' to keep track of the size of the queue,
            // as we want to traverse the tree one level at a time.
            for (int i = 0, size = queue.size(); i < size; i++) {
                TreeNode current = queue.poll();

                // When we reach the first leaf node, return the level.
                if (current.left == null && current.right == null)
                    return level;

                // If there are left or right child nodes, add them to the 'queue' for the next level.
                if (current.left != null) queue.offer(current.left);
                if (current.right != null) queue.offer(current.right);
            }
        }
        // This return statement is to prevent compile-time error.
        // It is guaranteed to find the first leaf node before all the nodes are visited.
        return level;
    }
}

package com.cheehwatang.leetcode;

import java.util.Stack;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// We traverse every node in the binary tree to find the minimum depth of the tree.
//
// Space Complexity : O(m),
// where 'm' is the depth of the tree.
// The maximum size of the 'nodeStack' and 'levelStack' is the depth of the tree.

public class MinimumDepthOfBinaryTree_DFS_Iterative {

    // Approach:
    // Using depth-first search to find and determine the depth of every root-to-leaf paths.
    // Then, compare and find the minimum depth whenever we arrived at a leaf node.
    // Here, the depth-first search is implemented iteratively.

    public int minDepth(TreeNode root) {
        // If the tree is empty, there is zero depth.
        if (root == null) return 0;

        // Both the depth and level of a tree describe the same thing.
        // Here, we use 'minLevel' as a variable name to make it differ from the 'minDepth()' method.
        int minLevel = Integer.MAX_VALUE;

        // For iterative depth-first search,
        // we use 'nodeStack' for the nodes and 'levelStack' to for the level of the node.
        Stack<TreeNode> nodeStack = new Stack<>();
        Stack<Integer> levelStack = new Stack<>();

        // Each time pushing a node into the 'nodeStack', push the level of the node to the 'levelStack'.
        nodeStack.push(root);
        levelStack.push(1);

        while (!nodeStack.isEmpty()) {
            // Get the current node and level of the node.
            TreeNode currentNode = nodeStack.pop();
            int currentLevel = levelStack.pop();

            // Once we reach a leaf node, compare and update the 'maxLevel'.
            if (currentNode.left == null && currentNode.right == null) {
                minLevel = Math.min(minLevel, currentLevel);
                continue;
            }

            // If there are left or right child nodes,
            // add them to the 'nodeStack' as well as their level ('currentLevel' + 1) to 'levelStack'.
            if (currentNode.left != null) {
                nodeStack.push(currentNode.left);
                levelStack.push(currentLevel + 1);
            }
            if (currentNode.right != null) {
                nodeStack.push(currentNode.right);
                levelStack.push(currentLevel + 1);
            }
        }
        // Once all the nodes are visited, return the minimum depth of the tree.
        return minLevel;
    }
}

package com.cheehwatang.leetcode;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// We traverse every node in the binary tree to find the minimum depth of the tree.
//
// Space Complexity : O(m),
// where 'm' is the depth of the tree.
// The maximum size of the 'nodeStack' and 'levelStack' is the depth of the tree.

public class MinimumDepthOfBinaryTree_DFS_Recursive {

    // Approach:
    // Using depth-first search to find the depth of every node.
    // Then, compare and find the minimum depth.
    // Here, the depth-first search is implemented recursively.

    // Main method to check for empty tree and to initialize the recursive method.
    public int minDepth(TreeNode root) {
        // If the tree is empty, there is zero depth.
        if (root == null) return 0;

        // Call the recursive method to perform depth-first search of the tree, with the level of the root is 1.
        return minDepth(root, 1);
    }

    // Recursive method to traverse the tree to find the minimum depth of the tree.
    private int minDepth(TreeNode root, int level) {
        // When we reach a leaf node, return the level of the leaf node.
        if (root.left == null && root.right == null) return level;

        // Traverse the left and right branch to find the minimum depth of each branch.
        // If either branch is null, use Integer.MAX_VALUE, as we will use Math.min() to find the minimum depth.
        int leftMinLevel = root.left == null ? Integer.MAX_VALUE : minDepth(root.left, level + 1);
        int rightMinLevel = root.right == null ? Integer.MAX_VALUE : minDepth(root.right, level + 1);

        // Return the minimum depth of the two branches.
        return Math.min(leftMinLevel, rightMinLevel);
    }
}

