import java.util.HashSet;
import java.util.PriorityQueue;
import java.util.Set;

// Time Complexity  : O(n logn),
// where 'n' is the length of 'nums'.
// For each number in 'nums', we offer to the priority queue with O(logn) time complexity,
// thus resulting in O(n logn) time complexity.
//
// Space Complexity : O(n),
// where 'n' is the length of 'nums'.
// We use a Priority Queue and HashSet to store the numbers in 'nums',
// with the maximum size the same as the size of 'nums'.

public class ThirdMaximumNumber_PriorityQueue_HashSet {

    // Approach:
    // We use Priority Queue, with comparator set to a max heap, allows us to offer the number to the max heap,
    // then we return the first element if the heap size is less than 3, or return the third element.
    // In order to address the possibilities of duplicated numbers,
    // we use HashSet the keep track of the distinct numbers in 'nums'.
    // We skip the number if the number is already found in the HashSet.

    public int thirdMax(int[] nums) {
        // Set up the Priority Queue as a max heap.
        PriorityQueue<Integer> pq = new PriorityQueue<>((a, b) -> Integer.compare(b, a));
        Set<Integer> set = new HashSet<>();

        // For each number,
        for (int number : nums) {
            // Offer to the priority queue if it is not in the HashSet.
            if (set.add(number))
                pq.offer(number);
        }

        // If there are less than 3 distinct numbers, return the first number in the max heap.
        if (set.size() < 3)
            return pq.peek();

        // Return the third maximum number otherwise.
        pq.poll();
        pq.poll();
        return pq.peek();
    }
}

package com.cheehwatang.leetcode;

import java.util.Arrays;

// Time Complexity  : O(n logn),
// where 'n' is the length of 'nums'.
// We use Arrays.sort() to sort the 'nums' array,
// which implements the Dual-Pivot Quicksort with O(n logn) time complexity.
// Then, we traverse the sorted 'nums' array to find the third maximum number.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent on the input.

public class ThirdMaximumNumber_Sorting {

    // Approach:
    // We first sort 'nums'.
    // This allows use to traverse the array in descending order,
    // checking for the second and third maximum number.
    // Here, we are sure that the third distinct number found in the sorted array is the thid maximum number.

    public int thirdMax(int[] nums) {
        int n = nums.length;

        // As Arrays.sort() method's comparator do not allow comparison with int primitive type,
        // we sort in ascending order, but traverse from the last index.
        Arrays.sort(nums);

        // We know for sure the last element in the sorted 'nums' is the first maximum number.
        Integer first = nums[n - 1];
        // We use Integer type instead of int primitive type, so that we can use null as placeholder,
        // for better readability.
        // Options to use long type or Integer.MIN_VALUE.
        Integer second = null;

        // Traverse the sorted 'nums' in descending order (from right to left).
        for (int i = n - 2; i >= 0; i--) {
            // If the number is less than the first and second maximum, return the number.
            if (nums[i] < first) {
                // If the second number is null, replace with the number.
                if (second == null)
                    second = nums[i];
                else if (nums[i] < second) {
                    return nums[i];
                }
            }
        }
        // If we successfully traverse the array, it means the third maximum number is not found.
        return first;
    }
}

