package com.cheehwatang.leetcode;

// Time Complexity  : O(1),
// as we would check for each binary (0 to 31) for any inputs of 'dividend' and 'divisor'.
//
// Space Complexity : O(1),
// as the auxiliary space used by the variables is constant and independent of the input.

public class DivideTwoIntegers {

    // Approach:
    // Using bit manipulation, focusing on the shift operators '>>' and '<<'.
    // The shift operators has the property of multiplying the number by 2 for each shift.
    // Example:
    // 1 << 2 == 1 * 2^2 == 4, 5 << 3 == 5 * 2^3 == 40.
    // Together with "dividend == (quotient * divisor) + remainder", if the 'divisor' shift 'x' is less than the 'dividend',
    // dividend == (divisor << x) + (something * divisor) + remainder
    // Continue the process until 'something' == 0, or dividend < divisor, in both cases the 'dividend' is the 'remainder'.

    public int divide(int dividend, int divisor) {
        // This is the handle the corner case where the result is greater than 2^31 - 1.
        if (dividend == Integer.MIN_VALUE && divisor == -1) return (1 << 31) - 1;

        // Case both 'dividend' and 'divisor' to long type to handle the cases where the number == -2^31,
        // from which the absolute value is greater than 2^31 - 1, resulting in integer overflow.
        long longDividend = Math.abs((long) dividend);
        long longDivisor = Math.abs((long) divisor);

        // As the 'quotient' is made up of 'divisor' * 2^i, much like the binary with 1s and 0s,
        // we check each possible 'i' for the 'divisor', from the largest 'i'.
        long result = 0;
        for (int i = 31; i >= 0; i--) {
            if (longDividend >> i >= longDivisor) {
                // Adjust the 'result' and 'dividend' accordingly.
                result += 1L << i;
                longDividend -= longDivisor << i;
            }
        }
        // The record the sign (positive or negative) of the result to return.
        // If only either 'dividend' or 'divisor' is negative, then the 'result' should return in negative.
        boolean positive = (dividend > 0 && divisor > 0) || (dividend < 0 && divisor < 0);

        return positive ? (int) result : (int) -result;
    }
}

package com.cheehwatang.leetcode;

import java.util.ArrayList;
import java.util.List;
import java.util.Stack;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// We traverse every node in the binary tree to find all the paths with path sum equal to the 'targetSum'.
//
// Space Complexity : O(n),
// where 'n' is the number of nodes in the tree.
// The size of the result grows linearly with the number of nodes.

public class PathSumII_DFS_Iterative_Backtracking {

    // Approach:
    // Using depth-first search to check every root-to-leaf paths to see if the path sum is equal to the 'targetSum'.
    // Here, the depth-first search is implemented iteratively, and backtracking approach is used.
    // For backtracking, we travel from root-to-leaf and check.
    // Once checked, we backtrack the path by a node, and check the next branch if any.
    // Continue to backtrack and check the next branch, if any, until all the paths are checked.

    public List<List<Integer>> pathSum(TreeNode root, int targetSum) {
        // If the tree is empty, return an empty result.
        if (root == null) return new ArrayList<>();

        List<List<Integer>> result = new ArrayList<>();

        // For iterative depth-first search, we use 'stack' for the TreeNodes.
        // As we also need to keep track of the path that we are on,
        // we use another stack to keep track of the value of the nodes in the 'path'.
        // Additionally, we also use a variable to keep track of the 'pathSum'.
        // For backtracking of the path,
        // any data structure that allows LIFO (Last-In First-Out) implementation can be used.
        // We are only removing the latest node value that is added.
        // Here, we use Stack for simplicity.
        Stack<TreeNode> stack = new Stack<>();
        Stack<Integer> path = new Stack<>();
        int pathSum = 0;

        // For iterative backtracking, we need to keep track of the previous node visited,
        // so that we do not get into an infinite loop.
        TreeNode current = root;
        TreeNode previous = null;

        while (current != null || !stack.isEmpty()) {
            // Keep traversing the left node until we reach null, while adding the nodes into the 'stack'.
            // In the process, keep track of the 'path' and the 'pathSum'.
            while (current != null) {
                stack.push(current);
                path.push(current.val);
                pathSum += current.val;
                current = current.left;
            }
            current = stack.peek();
            // If there is right child node and not previously visited,
            // go to the right child node, and continue to traverse down the left nodes until null.
            if (current.right != null && current.right != previous) {
                current = current.right;
                continue;
            }
            // If we arrive at a leaf node and the 'pathSum' is equal to the 'targetSum', add the 'path' to the result.
            // Note: Remember to create a new ArrayList for each path added,
            //       rather than adding the variable reference ('path') to result.
            if (current.left == null && current.right == null && pathSum == targetSum)
                result.add(new ArrayList<>(path));

            // Once the root-to-leaf path is checked, backtrack to the previous node (next node in the 'stack'),
            // while removing it from the 'path', and subtracting from the 'pathSum'.
            stack.pop();
            path.pop();
            pathSum -= current.val;

            // Set 'previous' as 'current' so we do not revisit and get into an infinite loop.
            // Remember to set 'current' to null, so we can visit the next node in the 'stack',
            // rather than traversing the left branch again.
            previous = current;
            current = null;
        }
        // Once all the root-to-leaf paths are visited, return the result.
        return result;
    }
}

package com.cheehwatang.leetcode;

import java.util.ArrayList;
import java.util.List;
import java.util.Stack;

/**
 * Definition for a binary tree node.
 * public class TreeNode {
 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree.
// We traverse every node in the binary tree to find all the paths with path sum equal to the 'targetSum'.
//
// Space Complexity : O(n),
// where 'n' is the number of nodes in the tree.
// The size of the result grows linearly with the number of nodes.

public class PathSumII_DFS_Recursive_Backtracking {

    // Approach:
    // Using depth-first search to check every root-to-leaf paths to see if the path sum is equal to the 'targetSum'.
    // Here, the depth-first search is implemented recursively, and backtracking approach is used.
    // For backtracking, we travel from root-to-leaf and check.
    // Once checked, we backtrack the path by a node, and check the next branch if any.
    // Continue to backtrack and check the next branch, if any, until all the paths are checked.

    // Main method to get the paths that have path sum equal to 'targetSum'.
    public List<List<Integer>> pathSum(TreeNode root, int targetSum) {
        List<List<Integer>> result = new ArrayList<>();
        // We use 'path' to keep track of the value of the nodes in the path.
        // For backtracking of the path,
        // any data structure that allows LIFO (Last-In First-Out) implementation can be used.
        // We are only removing the latest node value that is added.
        // Here, we use Stack for simplicity.
        Stack<Integer> path = new Stack<>();
        pathSum(root, targetSum, path, result);
        return result;
    }

    // Recursive method to perform depth-first search and backtracking.
    private void pathSum(TreeNode root, int targetSum, Stack<Integer> path, List<List<Integer>> result) {
        // If the 'root' is null, escape the function.
        if (root == null) return;
        // Rather than using a 'pathSum' variable to keep track,
        // we can simply keep subtracting the node values in the path from 'targetSum'.
        // If the 'targetSum' is zero, then the path sum is equal to 'targetSum'.
        targetSum -= root.val;
        // Add the node value to the 'path'.
        path.push(root.val);

        // If we arrive at a leaf node and the 'pathSum' is equal to the 'targetSum', add the 'path' to the result.
        // Note: Remember to create a new ArrayList for each path added,
        //       rather than adding the variable reference ('path') to result.
        if (root.left == null && root.right == null && targetSum == 0)
            result.add(new ArrayList<>(path));

        // Traverse the left and right child nodes.
        pathSum(root.left, targetSum, path, result);
        pathSum(root.right, targetSum, path, result);

        // Remember to remove the current node from the 'path' for backtracking.
        path.pop();
    }
}

