package com.cheehwatang.leetcode;

import java.util.Stack;

// Time Complexity  : O(n),
// where 'n' is the maximum size of the 'pushStack', when either the peek() or pop() is called on an empty 'popStack'.
// push() and empty() have O(1) time complexity.
//
// Space Complexity : O(m + n),
// where 'n' is the maximum size of the 'pushStack' and 'm' is the maximum size of the 'popStack'.

public class ImplementQueueUsingStacks {

    // Approach:
    // A queue is first in first out (FIFO), meaning the first element offered to the queue is the
    // first element to poll from the queue.
    // A stack is last in first out (LIFO), meaning the last element pushed to the stack is the
    // first element to pop from the stack.
    // To achieve the behavior of a queue, we can use a stack ('pushStack') for the input of the elements,
    // and another stack ('popStack') for the output of the elements.
    // When shifting the elements from the 'pushStack' to the 'popStack', the whole 'pushStack' is inverted
    // so the first element pushed to the 'pushStack' is the top element at the 'popStack'.
    // However, we would shift the elements only if the 'popStack' is empty.
    // Shifting the elements while the 'popStack' is not empty would result in incorrect ordering of the elements.

    // Set both 'pushStack' and 'popStack' to private
    // as only the constructor and the push(), pop(), peek() and empty() methods is accessible by other classes.
    // 'pushStack' is responsible for integer input to the queue.
    // 'popStack' is responsible for integer output from the queue, either for peek() or pop().
    private Stack<Integer> pushStack;
    private Stack<Integer> popStack;

    // Constructor to create new stack for the class variables.
    // Note that we can keep the constructor empty, and declare the new stack directly for the class variables.
    public ImplementQueueUsingStacks() {
        pushStack = new Stack<>();
        popStack = new Stack<>();
    }

    public void push(int x) {
        // When push() is called, push the integer to the 'pushStack'.
        pushStack.push(x);
    }

    public int pop() {
        // If the 'popStack' is empty, shift all the elements in the 'pushStack' over to the 'popStack'.
        if (popStack.empty()) shiftStack();

        // Remove the top element from the 'popStack'.
        return popStack.pop();
    }

    public int peek() {
        // If the 'popStack' is empty, shift all the elements in the 'pushStack' over to the 'popStack'.
        if (popStack.empty()) shiftStack();

        // Get the value of the top element from the 'popStack'.
        return popStack.peek();
    }

    public boolean empty() {
        // Only return true if both 'pushStack' and 'popStack' is empty.
        return pushStack.empty() && popStack.empty();
    }

    // Since both pop() and peek() share the same method if the 'popStack' is empty,
    // extract the method to a private method.
    private void shiftStack() {
        // Shift the whole 'pushStack' to the 'popStack'.
        while (!pushStack.empty()) popStack.push(pushStack.pop());
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(m logn),
// where 'm' is the total number of find() and union() functions called, and 'n' is the number of lowercase letters, 26.
// The naive approach of the union-find, with both the find() and union() having the time complexity of O(logn).
// With Union by Rank and Path Compression, the time complexity is amortized to almost linear complexity.
//
// Space Complexity : O(k + 26),
// where 'k' is the length of 'baseStr'.
// We used an array to keep track of the set representative (parent) for each lowercase letter, which is 26.
// Additionally, we used a new result string with the same length as 'baseStr'.

public class LexicographicallySmallestEquivalentString {

    // Approach:
    // Using the Disjoint Set Data Structure (Union-Find Data Structure) to
    // group the characters that are equivalent in 's1' and 's2',
    // which the character of the smaller value lexicographically being the set representative (parent).
    // At the same time, this follows the rules of equivalence relation,
    // which is Reflexivity, Symmetry and Transitivity.
    // Once the relationships between 's1' and 's2' are mapped,
    // make a new string from 'baseStr' using the new relationships.

    // Main function to get the smallest equivalent string.
    public String smallestEquivalentString(String s1, String s2, String baseStr) {
        // The 'parent' array keeps track of the set representative (parent) of each characters.
        int[] parent = new int[26];

        // Initialize the parent[], by setting all the set representatives (parents) to itself.
        for (int i = 0; i < parent.length; i++)
            parent[i] = i;

        // Merge (union) all the equivalent characters in 's1' and 's2',
        for (int i = 0; i < s1.length(); i++) {
            union(parent, s1.charAt(i) - 'a', s2.charAt(i) - 'a');
        }

        // Make a new string from the 'baseStr' using the new relationship,
        // with the new character being the parent of the character in 'baseStr'.
        StringBuilder result = new StringBuilder();
        for (char character : baseStr.toCharArray()) {
            // As the returned result of the find() function is an integer indicating the index from char 'a',
            // we add the integer to 'a', and cast to char.
            result.append((char) ('a' + find(parent, character - 'a')));
        }

        // Return the converted string.
        return result.toString();
    }

    // Function to find the set representative.
    private int find(int[] parent, int character) {
        // We have found the set representative when the character points back to itself.
        if (parent[character] == character) return character;

        // As part of the Path Compression, we set all the related characters to the set representative.
        return parent[character] = find(parent, parent[character]);
    }

    // Function to merge the two disjoint set.
    private void union(int[] parent, int char1, int char2) {
        // Get the set representative of the two characters.
        int find1 = find(parent, char1);
        int find2 = find(parent, char2);

        // If the parent of 'char1' is smaller lexicographically, then the parent of 'char1' becomes the parent.
        // If the parent of 'char2' is smaller lexicographically, then the parent of 'char2' becomes the parent.
        if (find1 < find2) parent[find2] = find1;
        else if (find1 > find2) parent[find1] = find2;
    }
}

package com.cheehwatang.leetcode;

import java.util.HashMap;
import java.util.Map;

// Time Complexity  : O(n),
// where 'n' is the length of 'nums'.
// We traverse 'nums' array once to find the match.
//
// Space Complexity : O(n),
// where 'n' is the length of 'nums'.
// The HashMap has a maximum size of 'n', where all numbers are unique and no match is found.

public class MaxNumberOfKSumPairs_HashTable {

    // Approach:
    // Using a HashMap to keep track of frequency of the numbers in 'nums'.
    // Reduce the count or remove the entry (value == 1) if we found the match.
    // If not, then we record the number into the HashMap.

    public int maxOperations(int[] nums, int k) {
        int count = 0;
        Map<Integer, Integer> map = new HashMap<>();

        // For each number in 'nums',
        for (int number : nums) {
            // 'difference' is the second number that pairs with 'number' to sum to 'k'.
            int difference = k - number;

            // Skip the number if it is greater than k.
            if (difference <= 0) continue;

            // If there is the 'difference' in the HashMap, meaning the number came up previously.
            // Increase the count, and reduce the frequency or remove the entry.
            if (map.containsKey(difference)) {
                count++;
                if (map.get(difference) == 1)
                    map.remove(difference);
                else
                    map.put(difference, map.get(difference) - 1);
            }
            // If no match found, increase the frequency or add the entry into the HashMap.
            else
                map.put(number, map.getOrDefault(number, 0) + 1);
        }
        return count;
    }
}

package com.cheehwatang.leetcode;

import java.util.Arrays;

// Time Complexity  : O(n logn),
// where 'n' is the length of 'nums'.
// We use Arrays.sort() to sort the array, which implements Dual-Pivot Quicksort which has O(n logn) time complexity.
// Additionally, we use two pointers to traverse 'nums' once, with O(n) time complexity.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent of the input size.

public class MaxNumberOfKSumPairs_Sorting_TwoPointers {

    // Approach:
    // Using sorting and two pointers. The sorting in ascending order allows us to use two pointers, 'left' and 'right'
    // to traverse the sorted array from both ends.
    // If the sum of nums[left] and nums[right] is greater than 'k',
    // then we move 'right' (to reduce the sum of the two numbers).
    // If the sum is less than 'k', then we move 'left' (to increase the sum of the two numbers).
    // If found a match, then we move both pointers.

    public int maxOperations(int[] nums, int k) {

        Arrays.sort(nums);
        int count = 0;

        // Traverse the sorted array by moving the 'left' and 'right' pointers towards each other.
        int left = 0;
        int right = nums.length - 1;
        while (left < right) {
            // If nums[right] is larger than k, we know it is impossible to get a sum lesser or equal to k.
            // Move 'right' if sum is greater than k.
            if (nums[right] >= k || nums[left] + nums[right] > k) {
                right--;
            }
            // If match, increase the count and move both pointers.
            else if (nums[left] + nums[right] == k) {
                count++;
                left++;
                right--;
            }
            // Move 'left' if sum is lesser than k.
            else {
                left++;
            }
        }
        return count;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n^3),
// where 'n' is the number of rows in 'img1' and 'img2'.
// We traverse both 'img1' and 'img2' once to convert the rows into binaries represented by an integer,
// which results in time complexity of O(n^2).
// Next, we shift the images in both axes, for iterating through each of the 4 directions.
// Since we use the bitwise shift operators '<<' and '>>', the time complexity lowers to O(n^3).
// This results in the final time complexity of O(n^3).
//
// Space Complexity : O(n),
// where 'n' is the number of rows in 'img1' and 'img2'.
// We use 2 arrays of length 'n' to store the rows (after conversion to binaries and stored as bits) of both images.

public class ImageOverlap_BitManipulation {

    // Approach:
    // This is basically a brute force technique by translating 'img1' in all the possible combinations.
    // which will result in a O(n^4) time complexity, 'n' to translate horizontally, nest 'n' to translate vertically,
    // nest 'n' to traverse every row, nest 'n' to traverse every column.
    // For improvement, we can use Bit Manipulation to lower the time complexity to O(n^3).
    // Given the constraint of 1 <= n <= 30, O(n^3) is possible as a solution without getting the TimeLimitExceeded notice.
    // Using a primitive type int that can store maximum 2 ^ 31 - 1,
    // we can store the rows as binary using the left shift '<<' operator and bitwise OR '|' operation.
    //
    // When comparing for overlap, we can simply use bitwise AND '&' operation, for each row.
    // Bit Manipulation allows us to reduce time complexity by reducing the need to traverse the row to check for overlap.
    // Note:
    // As we need to left shift by 'n' when checking for overlap, resulting in a number of 2^60,
    // we need to use type long which stores up to 2^63 - 1.

    public int largestOverlap(int[][] img1, int[][] img2) {
        int n = img1.length;
        long[] image1 = new long[n];
        long[] image2 = new long[n];
        // Convert the rows into binary.
        for (int i = 0; i < n; i++) {
            int binary1 = 0; int binary2 = 0;
            for (int bit : img1[i]) binary1 = (binary1 << 1) | bit;
            for (int bit : img2[i]) binary2 = (binary2 << 1) | bit;
            image1[i] = binary1;
            image2[i] = binary2;
        }

        int max = 0;
        // 'i' is used to shift left or right.
        for (int i = 0; i < n; i++) {
            // 'j' is used to shift up or down.
            for (int j = 0; j < n; j++) {
                int countDownRight = 0;
                int countDownLeft = 0;
                int countUpRight = 0;
                int countUpLeft = 0;
                for (int k = 0; k < n - j; k++) {
                    // Shift down, by comparing image1[k] with image2[k + j]
                    countDownRight += Long.bitCount(image1[k] >> i & image2[k + j]);
                    countDownLeft += Long.bitCount(image1[k] << i & image2[k + j]);
                    // Shift up, by comparing image1[k + j] with image2[k]
                    countUpRight += Long.bitCount(image1[k + j] & image2[k] << i);
                    countUpLeft += Long.bitCount(image1[k + j] & image2[k] >> i);
                }
                // Check for the maximum for all 4 directions of translation.
                max = Math.max(max, Math.max(Math.max(countDownRight, countDownLeft), Math.max(countUpRight, countUpLeft)));
            }
        }
        return max;
    }
}

package com.cheehwatang.leetcode;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

// Time Complexity  : O(n^2),
// where 'n' is the number of rows in 'img1' and 'img2'.
// As the matrix for both images is square, the number of rows and columns is the same.
// We first traverse both images once to convert the 1s to hash and store in the list.
// Next, we traverse the lists in a nested loop to get the coordinate differences,
// with the worst-case being O(n^2), where both images are only consist of 1s.
// This results in the final time complexity of O(n).
//
// Space Complexity : O(n^2),
// where 'n' is the number of rows in 'img1' and 'img2'.
// Both list has a space complexity of O(n^2), if both images only consist of 1s.
// Additionally, this results in the HashMap having a maximum of n^2 size.

public class ImageOverlap_HashTable {

    // Approach:
    // Every 1 in 'img1' has a certain relationship with the 1s in 'img2',
    // in terms of the differences in the 'row' and 'column.
    //
    // If two points in 'img1' overlaps with two points in 'img2',
    // then this two pairs has the same 'row' and 'column' differences.
    // As such, we can use a Hash Table to keep track on the frequency of the 'row' and 'column' differences,
    // and return the 'row' and 'column' difference with the highest frequency.

    public int largestOverlap(int[][] img1, int[][] img2) {
        int n = img1.length;
        List<Integer> coordinates1 = new ArrayList<>();
        List<Integer> coordinates2 = new ArrayList<>();
        // Using n * n to traverse row by row, with the row = i / n, and column = i % n.
        for (int i = 0; i < n * n; i++) {
            // With the constraint of 1 <= n <= 30,
            // we can use XX00 to store the 'row', and 00XX to store the 'column'.
            int hash = (i / n * 100) + (i % n);
            // Only store the 'hash' if it contains a 1.
            if (img1[i / n][i % n] == 1) coordinates1.add(hash);
            if (img2[i / n][i % n] == 1) coordinates2.add(hash);
        }

        Map<Integer, Integer> map = new HashMap<>();
        int max = 0;
        // Compare all the coordinates from 'img1' containing 1 with the coordinates from 'img2' containing 1.
        // Use the HashMap to store the differences, and find the maximum number of overlap.
        for (int i : coordinates1) {
            for (int j : coordinates2) {
                map.put(i - j, map.getOrDefault(i - j, 0) + 1);
                max = Math.max(max, map.get(i - j));
            }
        }
        return max;
    }
}

package com.cheehwatang.leetcode;

import java.util.LinkedList;
import java.util.Queue;

// Time Complexity  : O(m * n),
// where 'm' is the number of rows, and 'n' is the number of columns of the 'grid'.
// We check every position in the 'grid' for land '1',
// and worst case if the whole 'grid' is an island, we perform a full breadth first search which is O(m * n),
// resulting in the worst case of O(2 * m * n).
//
// Space Complexity : O(m + n),
// where 'm' is the number of rows, and 'n' is the number of columns of the 'grid'.
// This is due to the Queue used in the breadth first search when we found 'i'.
// As we are adding and removing positions (nodes) at each level, the Queue can only grow to a maximum of 'm' + 'n' size.

public class NumberOfIslands_BFS {

    // Approach:
    // Search the whole 'grid' for land '1'.
    // Whenever we found a land '1', we use breadth-first search to "sink" the land, changing the '1' to '0'.
    // Then we use a variable to keep track of the number of islands we encounter.
    // Remember, each breadth-first search started only accounts for one island.

    public static int numIslands(char[][] grid) {
        int rows = grid.length;
        int columns = grid[0].length;

        // Creating an array for the directions (up, down, left, right) for simpler execution later.
        int[][] directions = new int[][] {{1,0}, {-1,0}, {0,1}, {0,-1}};

        // Variable to keep track of island count.
        int islands = 0;

        // Search through every position in the 'grid' for land '1'.
        for (int row = 0; row < rows; row++) {
            for (int column = 0; column < columns; column++) {
                // If not land, continue.
                if (grid[row][column] == '0') continue;

                // Increase the island count accordingly,
                // before starting the breadth first search to "sink" the island.
                islands++;

                // Breadth first search implementation.
                Queue<int[]> queue = new LinkedList<>();
                // Note to always set the '1' to '0' first before adding the position to the queue,
                // to prevent accidental repeated search of the same position.
                grid[row][column] = '0';
                queue.offer(new int[] {row, column});
                while (!queue.isEmpty()) {
                    // Remember to set a variable for the queue size for each level,
                    // as we are constantly changing the queue size,
                    // which may lead to infinite loop or accidentally ending of loop if the variable is not set.
                    for (int i = 0, n = queue.size(); i < n; i++) {
                        int[] current = queue.poll();
                        // Iterate through all four directions (up, down, left, right).
                        for (int[] direction : directions) {
                            int x = current[0] + direction[0];
                            int y = current[1] + direction[1];
                            // Skip the direction if it leads to out of bound.
                            if (x < 0 || x >= rows || y < 0 || y >= columns) continue;
                            // "sink" the land and continue the BFS.
                            if (grid[x][y] == '1') {
                                grid[x][y] = '0';
                                queue.offer(new int[]{x, y});
                            }
                        }
                    }
                }
            }
        }
        // When we finish checking every position in 'grid', return the number of islands.
        return islands;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(m * n),
// where 'm' is the number of rows, and 'n' is the number of columns of the 'grid'.
// We check every position in the 'grid' for land '1',
// and perform depth-first search (DFS) for a maximum of the whole 'grid'.
//
// Space Complexity : O(m * n),
// where 'm' is the number of rows, and 'n' is the number of columns of the 'grid'.
// Even though we modify the 'grid' in-place,
// the recursive depth first search (DFS) function has a maximum call stack of every position in the 'grid'.

public class NumberOfIslands_DFS {

    // Approach:
    // Search the whole 'grid' for land '1'.
    // Whenever we found a land '1', we use depth-first search to "sink" the land, changing the '1' to '0'.
    // Then we use a variable to keep track of the number of islands we encounter.
    // Remember, each depth-first search started only accounts for one island.

    // Main method to find the land and call the recursive DFS method.
    public int numIslands(char[][] grid) {
        int rows = grid.length;
        int columns = grid[0].length;

        // Variable to keep track of island count.
        int islands = 0;

        // Search through every position in the 'grid' for land '1'.
        for (int row = 0; row < rows; row++) {
            for (int column = 0; column < columns; column++) {
                if (grid[row][column] == '1') {
                    // When found, it is an island, and we sink the land '1' connected.
                    islands++;
                    sinkIsland(grid, row, column);
                }
            }
        }
        return islands;
    }

    // Recursive DFS method to change the land '1' to water '0'.
    private void sinkIsland(char[][] grid, int row, int column) {
        // If the position is out of bound, or if the position is water '0', return.
        if (row < 0 || row >= grid.length || column < 0 || column >= grid[row].length || grid[row][column] == '0') return;
        // Change the land '1' to water '0'.
        grid[row][column] = '0';
        // Search all four directions (up, down, left, right).
        sinkIsland(grid, row + 1, column);
        sinkIsland(grid, row - 1, column);
        sinkIsland(grid, row, column + 1);
        sinkIsland(grid, row, column - 1);
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(m * n),
// where 'm' is the number of rows, and 'n' is the number of columns of the 'grid'.
// We traverse the 'grid' in two occasions,
// 1. Set the set representative (parent) for land '1' in the 'grid' to itself.
// 2. Traverse the 'grid' to find lands, and union the land adjacent to another land.
//
// Space Complexity : O(m * n),
// where 'm' is the number of rows, and 'n' is the number of columns of the 'grid'.
// We used an array to keep track of the set representative (parent) for each position in the 'grid'.

public class NumberOfIslands_UnionFind {

    // Approach:
    // Using Union-Find data structure, we first make all the land '1' on the 'grid' as separate disjoint sets,
    // or separate islands.
    // Imagine we start with many islands of only one land '1'.
    // As we traverse 'grid' and check if two lands '1' are adjacent to one another,
    // we merge (union) the two lands '1' as a single island, reducing the number of islands by one.
    // Once we have traversed the whole 'grid',
    // we have merged all the lands '1' to their respective islands (disjoint sets).
    // Here, we implemented path compression and union by rank to lower time complexity.

    public int numIslands(char[][] grid) {
        int rows = grid.length;
        int columns = grid[0].length;

        // 'parent' array to record the set representatives for each position.
        // Note that we are hashing the position with 'row' and 'column' into 'landID' "row * column + column".
        int[] parent = new int[rows * columns];

        // The 'rank' array is used as part of the union by rank implementation,
        // with the ranks when merging (union),
        // and the node with higher rank to be the parent of the node with lower rank.
        int[] rank = new int[rows * columns];

        int islands = 0;
        // Set up the disjoint set data structure by referencing all the nodes (positions) to itself.
        // Additionally, count the number of land '1' as the number of 'islands' at the start.
        for (int row = 0; row < rows; row++) {
            for (int column = 0; column < columns; column++) {
                // If the position is water, move to the next position.
                if (grid[row][column] == '0') continue;
                // Hash the position as 'landID'.
                int landID = row * columns + column;
                islands++;
                parent[landID] = landID;
            }
        }

        // Creating an array for the directions (up, down, left, right) for simpler execution later.
        int[][] directions = new int[][] {{1,0}, {-1,0}, {0,1}, {0,-1}};
        for (int row = 0; row < rows; row++) {
            for (int column = 0; column < columns; column++) {
                // If the position is water, move to the next position.
                if (grid[row][column] == '0') continue;
                int landID1 = row * columns + column;
                // Check all the positions adjacent for land '1'.
                for (int[] direction : directions) {
                    int x = row + direction[0];
                    int y = column + direction[1];
                    // If the position is out of bound or is water '0', continue to the next position.
                    if (x < 0 || x >= rows || y < 0 || y >= columns || grid[x][y] == '0') continue;
                    // If found a land '1', union the two position and decrease the 'islands' by 1.
                    int landID2 = x * columns + y;
                    if (union(landID1, landID2, parent, rank)) islands--;
                }
            }
        }
        // Once all the land '1' is in their respective disjoint set, we have the number of 'islands'.
        return islands;
    }

    // Method to find the set representative (parent) of the node, with path compression implemented.
    private int find(int landID, int[] parent) {
        // Continue to find the parent until the node references itself,
        // that the self-referencing node is the set representative.
        if (parent[landID] == landID) return landID;
        // Compress that path by referencing all the children node along the path directly to the parent node.
        return parent[landID] = find(parent[landID], parent);
    }

    // Method to merge (union) two nodes, with union by rank implemented.
    private boolean union(int landID1, int landID2, int[] parent, int[] rank) {
        int find1 = find(landID1, parent);
        int find2 = find(landID2, parent);
        // If the two nodes are already in the same disjoint set (island),
        // return false, indicating that the union is not successful.
        if (find1 == find2) return false;

        // If node 2 'find2' has a higher rank, make node 2 'find2' the parent of node 1 'find1'.
        if (rank[find2] > rank[find1]) {
            parent[find1] = find2;
        }
        // If node 1 'find1' has a higher rank, make node 1 'find1' the parent of node 2 'find2'.
        else {
            parent[find2] = find1;
            // If both node has the same rank, increase the rank of the parent (node 1 'find1') by 1.
            if (rank[find1] == rank[find2]) rank[find1]++;
        }
        return true;
    }
}

package com.cheehwatang.leetcode;

import java.util.HashMap;
import java.util.Map;

// Time Complexity  : O(n * m),
// where 'n' is the length of 'nums', and 'm' is the length of 'target'.
// For each number string in 'nums', we check if the number string is prefix or suffix of 'target',
// using String.startWith() and String.endWith() functions, which has O(m) time complexity.
//
// Space Complexity : O(n),
// where 'n' is the length of 'nums'.
// We use a HashMap with a maximum size of 'n', if all strings in 'nums' are unique.

public class NumberOfPairsOfStringsWithConcatenationEqualToTarget_HashTable {

    // Approach:
    // Using HashMap to record the frequency of the elements in 'nums',
    // while checking for its prefix or suffix that can form 'target'.
    // The String class offers two helpful methods, startWith(String) and endsWith(String),
    // which returns boolean whether the string starts with or ends with the input string.
    //
    // Note: This problem can be solved with Brute Force nested for-loops to check the concatenation of every element.

    public int numOfPairs(String[] nums, String target) {
        Map<String, Integer> map = new HashMap<>();
        int count = 0;
        for (String number : nums) {
            // If 'number' is the prefix of 'target', add the count of the corresponding suffix.
            if (target.startsWith(number)) {
                String suffix = target.substring(number.length());
                count += map.getOrDefault(suffix, 0);
            }
            // If 'number' is the suffix of 'target', add the count of the corresponding prefix.
            if (target.endsWith(number)) {
                String prefix = target.substring(0, target.length() - number.length());
                count += map.getOrDefault(prefix, 0);
            }
            // Note that we used two if-statements here, because 'number' can be both prefix and suffix of 'target'.

            // For each, record the frequency of 'number' in the map.
            map.put(number, map.getOrDefault(number, 0) + 1);
        }
        return count;
    }
}

package com.cheehwatang.leetcode;

import java.util.Arrays;

// Time Complexity  : O(n * k),
// where 'n' and 'k' are the variables used by the method.
// For every face, we check every dice, to find all the possible combinations that sums to 'target',
// thus we can treat it like nested for-loop.
//
// Space Complexity : O(n * target),
// where 'n' and 'target' are the variables used by the method.
// We use a matrix of 'n' rows with 'target' columns for memoization.
// The recursive call stack has a maximum height of 'n'.

public class NumberOfDiceRollsWithTargetSum_Memoization {

    // Approach:
    // A dynamic programming problem where there are overlapping subproblem,
    // for which each roll has possible 1 to k number face-up.
    // Here, the recursive and memoization method is used.
    // By reducing the target by the face-up number each roll (hence n - 1),
    // the successful sequence of rolls is achieved when n = 0 and target = 0,
    // which forms the base case where target == 0 && n == 0.
    // If target <= 0 || n == 0, meaning the sequence is unsuccessful.

    // Wrapper method to initiate the memo and call the recursive method.
    // As the number 0 in the memo is a meaningful result, set all the elements of the memo to -1.
    public int numRollsToTarget(int n, int k, int target) {
        // As the array is 0-indexed, we need + 1 length to accommodate 'n' and 'target' respectively.
        int[][] memo = new int[n + 1][target + 1];
        for (int[] row : memo) Arrays.fill(row, -1);
        return numRollsToTarget(n, k, target, memo);
    }

    // Recursive method.
    private int numRollsToTarget(int n, int k, int target, int[][] memo) {
        // Base case for successful sequence.
        if (target == 0 && n == 0) return 1;
        // Base case for unsuccessful sequence.
        if (target <= 0 || n == 0) return 0;
        // If memo already contains the result, return the result.
        if (memo[n][target] != -1) return memo[n][target];
        int modulus = (int) (1e9 + 7);
        int count = 0;
        // For each face, reduce the 'n' by 1 and 'target' by the face-up number.
        for (int face = 1; face <= k; face++) {
            count = (count + numRollsToTarget(n - 1, k, target - face, memo)) % modulus;
        }
        // Store the result into the memo and return the result.
        return memo[n][target] = count;
    }
}

package com.cheehwatang.leetcode;

// Time Complexity  : O(n * k * target),
// where 'n', 'k' and 'target' are the variables used by the method.
// For each dice, 'n', we check each values of 'target' to add the number of faces 'k' that can sum to 'target',
// in a 3 layer nested for-loops.
//
// Space Complexity : O(n * target),
// where 'n' and 'target' are the variables used by the method.
// We use a matrix of 'n' rows with 'target' columns for tabulation.

public class NumberOfDiceRollsWithTargetSum_Tabulation {

    // Approach:
    // A dynamic programming problem where there are overlapping subproblem,
    // for which each roll has possible 1 to k number face-up.
    // Here, the iterative and tabulation method is used.
    // By reducing the target by the face-up number each roll (hence n - 1),
    // the successful sequence of rolls is achieved when n = 0 and target = 0, which forms the base case for the table.

    public int numRollsToTarget(int n, int k, int target) {
        // As the array is 0-indexed, we need + 1 length to accommodate 'n' and 'target' respectively.
        int[][] table = new int[n + 1][target + 1];
        // The seed/base case for successful sequence in the table.
        table[0][0] = 1;
        // Iterate through the table to get the result for all possibilities.
        int modulus = (int) (1e9 + 7);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < target; j++) {
                // Skip if the position in the array is 0, meaning nothing to add to the j + 1 to k positions.
                if (table[i][j] == 0) continue;
                for (int face = 1; face <= k; face++) {
                    if (face + j <= target) {
                        table[i + 1][j + face] = (table[i + 1][j + face] + table[i][j]) % modulus;
                    }
                }
            }
        }
        return table[n][target];
    }
}

package com.cheehwatang.leetcode;

import java.util.ArrayList;
import java.util.List;

/**
 * Definition for singly-linked list.
 * public class ListNode {
 * int val;
 * ListNode next;
 * ListNode() {}
 * ListNode(int val) { this.val = val; }
 * ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */
// Note: Remember to set up a ListNode class as the same folder as the pairSum() function.

// Time Complexity  : O(n),
// where 'n' is the length of the linked list.
// We traverse the linked list once to record the values into an ArrayList,
// and traverse the ArrayList using two pointers to get the max sum of the twin.
//
// Space Complexity : O(n),
// where 'n' is the length of the linked list.
// The ArrayList used to record the values of the linked list nodes are of size 'n'.

public class MaximumTwinSumOfALinkedList_TwoPointers {

    // Approach:
    // Traverse the linked list once to record the values into an ArrayList.
    // Then, we use two pointers 'start' and 'end' to traverse the ArrayList from both directions,
    // and get the sum of the twin nodes value, and determine the max sum.

    public int pairSum(ListNode head) {
        List<Integer> list = new ArrayList<>();

        // Use 'current' pointer to traverse the linked list once to record the values.
        ListNode current = head;
        while (current != null) {
            list.add(current.val);
            current = current.next;
        }

        int start = 0;
        int end = list.size() - 1;
        int max = 0;
        // Traverse the ArrayList from both directions.
        while (start < end) {
            // Compare and get the max sum.
            max = Math.max(max, list.get(start) + list.get(end));
            start++;
            end--;
        }
        return max;
    }
}

package com.cheehwatang.leetcode;

import java.util.Stack;

/**
 * Definition for singly-linked list.
 * public class ListNode {
 * int val;
 * ListNode next;
 * ListNode() {}
 * ListNode(int val) { this.val = val; }
 * ListNode(int val, ListNode next) { this.val = val; this.next = next; }
 * }
 */
// Note: Remember to set up a ListNode class as the same folder as the pairSum() function.

// Time Complexity  : O(n),
// where 'n' is the length of the linked list.
// We traverse the linked list to get the max sum of the twin.
//
// Space Complexity : O(n),
// where 'n' is the length of the linked list.
// The Stack used to record the values of the linked list nodes has a maximum size of 'n / 2'.

public class MaximumTwinSumOfALinkedList_TwoPointers_Stack {

    // Approach:
    // Using a 'slow' and 'fast' pointer, we traverse the linked list with 'slow' moving one node at a time,
    // and 'fast' moving two nodes at a time, we can determine the midpoint of the linked list.
    // For the first half, while the 'fast' pointer not reach the end of the linked list,
    // we record the values of the 'slow' pointer in a Stack.
    // Once the 'fast' pointer reaches the end, we continue to traverse with the 'slow' pointer,
    // but now we are popping the value from the stack and sum with the 'slow' pointer value.
    // Continue to determine the maximum twin nodes value sum.

    public int pairSum(ListNode head) {
        int max = 0;
        Stack<Integer> stack = new Stack<>();
        // Both the 'slow' and 'fast' pointers start at the first node.
        ListNode slow = head;
        ListNode fast = head;
        // Traverse the linked list with the 'slow' and 'fast' pointer.
        while (slow != null) {
            // If 'fast' is not at the end of the linked list,
            if (fast != null) {
                // add the 'slow' pointer value to the stack.
                stack.push(slow.val);
                // As we know that 'n' is even, we can skip checking if fast.next is null.
                // The constraint ensures that fast.next.next does not throw NullPointerException.
                fast = fast.next.next;
            }
            // If 'fast' reaches the end of the linked list,
            else {
                // Pop the value from the stack and sum with the value at the 'slow' pointer.
                max = Math.max(max, stack.pop() + slow.val);
            }
            // Move the 'slow' pointer forward.
            slow = slow.next;
        }
        return max;
    }
}

package com.cheehwatang.leetcode;

import java.util.HashMap;
import java.util.Map;

// Time Complexity  : O(n),
// where 'n' is the size of the integer array 'fruits'.
// We traverse the array once with two pointers acting as the sliding window.
//
// Space Complexity : O(1),
// as the use of the auxiliary space is independent on the size of the input, 'fruits'.
// The HashMap used has a maximum size of 2 no matter how big the size of the 'fruits' array.

public class FruitIntoBaskets {

    // Approach:
    // Using two pointers marking the sliding window and
    // a HashMap to count the number of unique fruits in the sliding window,
    // we expand the front of the sliding window in each iteration,
    // with contracting the back of the sliding window if there are more than two unique key value in the HashMap.
    // In each iteration, we update the max with the maximum size of the sliding window.

    public int totalFruit(int[] fruits) {
        // The key of the HashMap is the unique fruit integer,
        // and the value is the number of that unique fruit in the sliding window.
        Map<Integer, Integer> map = new HashMap<>();

        // 'max' keeps track of the maximum size of the sliding window.
        // The 'back' and 'front' are the two pointers marking the sliding window.
        int max = 0, back = 0;
        for (int front = 0; front < fruits.length; front++) {
            // Count the fruits[front] into the HashMap.
            map.put(fruits[front], map.getOrDefault(fruits[front], 0) + 1);

            // If the HashMap has more than two unique fruits, then we contract the sliding window
            while (map.size() > 2) {
                // by moving the 'back' pointer forward, each time reducing the count of the fruit in the HashMap
                map.put(fruits[back], map.get(fruits[back]) - 1);
                // until two unique fruits are in the HashMap.
                if (map.get(fruits[back]) == 0) map.remove(fruits[back]);
                back++;
            }
            // Check and find the maximum size of the sliding window.
            max = Math.max(max, front - back + 1);
        }
        return max;
    }
}

package com.cheehwatang.leetcode;

import java.util.Arrays;

// Time Complexity  : O(n logn),
// where 'n' is the length of 'tokens'.
// We use Arrays.sort() to sort 'tokens', which implements the Dual-Pivot Quicksort with O(n logn) time complexity.
// Additionally, we traverse the 'tokens' array once to perform the greedy approach to get the maximum score.
//
// Space Complexity : O(1),
// as the auxiliary space used is independent on the size of the input.

public class BagOfTokens {

    public int bagOfTokensScore(int[] tokens, int power) {

        // With the rules, this problem is suitable with greedy approach, by:
        // 1. losing the least power to gain the most score (play face up), and
        // 2. losing the least score to gain the most power (play face down).
        // Since the tokens are in random order, we need to sort the tokens in ascending order
        // to perform the greedy algorithm.

        // First sort the bag of tokens in ascending order.
        Arrays.sort(tokens);

        // Set the head and tail pointers.
        int head = 0;
        int tail = tokens.length - 1;

        int score = 0;
        while (head <= tail) {
            // Will keep adding score by losing tokens[head] powers, until power is less than
            // the smallest available token. (Greedy, to maximize the score)
            if (power >= tokens[head]) {
                power -= tokens[head++];
                score++;
            }
            // Gain power of tokens[tail] while score > 0. (Greedy, to maximize power gained when lose 1 score)
            else if (score > 0 && tokens[head] < tokens[tail]) {
                power += tokens[tail--];
                score--;
            }
            // End while loop when all remaining tokens is same value,
            else {
                break;
            }
            // or when head > tail.
        }
        return score;
    }
}
